window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q16"]=window.__LIBQ["tien-nghich"]["q16"]||{};window.__LIBQ["tien-nghich"]["q16"]["characters"]={"updatedAt":"2026-07-15","count":76,"chars":[{"id":"vuong-lam","name":"Vương Lâm","tabs":{"kinhLich":[{"chuong":"@c1633","importance":"normal","mucCt":"ky","tieuDe":"Áp chế tứ đại chiến tướng, tàn sát tiên nhân bằng thiên đạo","text":"Cầm Khai Thiên Phủ dung nhập huyết mạch Đạo cổ chém khe không gian phá tan hư ảnh Thanh Long, dùng Đạo cổ bất diệt thể chống đỡ hợp kích tứ đại chiến tướng Không Huyền hậu kỳ. Dùng cánh tay phải (cánh tay Diệp Mịch) phát Tê Thiên lực tàn sát hàng loạt tiên nhân không chút kháng cự. Ra lệnh u Minh thú phóng sương mù thiên đạo nuốt khoảng bảy tám mươi tiên nhân, chỉ còn lại năm người. Thầm thở dài vì thiên đạo chưa hoàn chỉnh, u Minh thú rất khó nuốt được Chiến lão quỷ. Cưỡi u Minh thú hướng về Côn Hư.","anchor":"Tu vi của các ngươi còn chưa hoàn toàn khôi phục, chỉ khoảng Không Huyền hậu kỳ mà thôi"},{"mucCt":"ky","text":"Cưỡi U Minh thú, dùng ngọc giản Nạp Đa đưa hơn ngàn năm trước để tìm tọa độ Ngũ Hành tinh. Dung hợp với thiên đạo qua U Minh thú, nhận ra Ngũ Hành tinh không thuộc động phủ giới mà được tu sĩ bên ngoài dùng thần thông mang từ Tiên Cương đại lục tới. Dùng giọng nói truyền xuyên quầng sáng vào Ngũ Hành tinh khiến mọi sinh linh chấn động, xưng ước hẹn năm xưa với Nạp Đa. Phó tông chủ Duẫn Đông Thân từ chối cho vào, cảnh báo sẽ khởi động Ngũ Hành Quy Nhất trận. Một luồng thần thức bá đạo từ bên trong thách thức: qua được Ngũ Hành trận thì cứ vào. Bất chấp cảnh báo, bước thẳng vào quầng sáng ngũ sắc, chịu liên tiếp công kích từ lực lượng Ngũ Hành.","anchor":"Nạp Đa hôm nay Vương mỗ tới đây vì ước hẹn năm xưa","bridge":true,"khoang":"@c1634"},{"importance":"normal","mucCt":"ky","chuong":"@c1635","tieuDe":"Phá Đại địa thổ trận, thu trận linh","text":"Vương Lâm bước mười bốn bước rưỡi xâm nhập quầng sáng Ngũ Hành, đối mặt trận thứ nhất Đại địa thổ trận. Dùng thân thể Đạo cổ tung chín quyền đánh nát chín mặt người bùn đất. Bị đệ nhị biến hai mặt đất ép chặt không khe hở nhưng thong thả đấm vỡ từ bên trong bước ra. Thu luôn trận linh của Đại địa thổ trận — dúm bùn đất tỏa linh khí dày đặc — khiến bốn trưởng lão và Nạp Đa đều chấn động. Ngẩng đầu nhìn thẳng vào mặt gương quan sát của bốn trưởng lão. Xác định Ngũ Hành tinh là biến số ẩn giấu thứ hai ngoài Thiên Vận Tử, bất lợi cho việc tìm hồn thứ ba, tự tin khi muốn chạy không ai cản nổi.","anchor":"Hắn có thân thể mạnh mẽ của Đạo cổ, làm sao chút thần thông này có thể phá vỡ được"},{"chuong":"@c1636","importance":"normal","mucCt":"ky","tieuDe":"Thu thổ linh, hỏa linh quỳ bái trong Ngũ Hành đại trận","text":"Thu nhúm thổ linh (thổ bổn nguyên) trong Ngũ Hành đại trận, hiện có hai nhúm thổ linh trong không gian trữ vật. Suy tính thu đủ bốn bổn nguyên còn lại ngoài hỏa bổn nguyên để tăng tu vi, tự hỏi Ngũ Hành quy nhất có thể sản sinh bổn nguyên mới không. Bước vào Ngũ Hành hỏa trận hoàn toàn thoải mái nhờ hỏa bổn nguyên. Chín con hỏa Kỳ Lân phủ phục trước hắn, toàn bộ ngọn lửa ngưng tụ thành người khổng lồ hỏa diễm cao mấy ngàn trượng quỳ gối sùng kính. Từ đầu đến cuối không mở miệng, không thi triển thần thông, chỉ đứng đó như bậc quân vương.","anchor":"Hắn chỉ đứng đó, giống như là một bậc quân vương đi trở lại đất nước mình, có thể dùng một ánh mắt mà khiến tất cả con dân phải quỳ lạy."},{"mucCt":"ky","text":"Đứng trên đỉnh đầu người khổng lồ lửa chỉ huy nó cùng chín con Kỳ Lân phá sập Ngũ Hành hỏa trận, cảnh tượng chuyển sang thủy trận. Bị Thủy Tướng dùng bốn bức tường nước vạn trượng và trường thương nước mưa huyễn hóa nhấn chìm trong biển cùng người khổng lồ lửa. Bất ngờ xuất hiện sau lưng Thủy Tướng, vỗ chưởng truyền lực lượng bổn nguyên và khí tức hủy diệt Đạo cổ khiến ngũ tạng hắn tan nát, xương cốt chia lìa, phun máu bị đánh bay, nhưng áo giáp phóng sinh cơ khôi phục thương thế cho Thủy Tướng. Dùng cấm chế bổn nguyên tự hình thành quy tắc nhìn thấu bí mật áo giáp: tu vi Thủy Tướng không tới bước thứ ba, áo giáp cho sức mạnh bước ba nhưng điều khiển ngược lại người mặc. Bị tu sĩ Quy Nhất tông xuyên tạc là kẻ giết toàn tộc họ Đằng vì tham bảo vật, vô ơn với Nạp Đa.","anchor":"tay phải đột nhiên vỗ lên người Thủy Tướng","bridge":true,"khoang":"@c1637"},{"importance":"normal","mucCt":"ky","chuong":"@c1638","tieuDe":"Cảm ngộ thủy bổn nguyên trong Càn Khôn Nhất Tích","text":"Bị Thủy Tướng nhốt trong quả cầu nước khổng lồ do thần thông Càn Khôn Nhất Tích tạo ra, nhưng hoàn toàn có thể thoát hoặc giết đối phương dễ dàng. Quyết định ở lại bên trong cảm ngộ thủy bổn nguyên — cơ hội cực hiếm nâng bổn nguyên từ bảy đạo lên tám đạo. Dùng tơ máu trong đồng tử (cấm chế bổn nguyên hóa thành quy tắc) quan sát ghi nhớ mọi biến hóa của thủy bổn nguyên. Trước đó chỉ liếc mắt đã nhìn ra bí ẩn lớn nhất của áo giáp Thủy Tướng, yêu cầu cởi giáp đổi mạng bị từ chối, tuyên bố không nương tay với kẻ xâm nhập. Huyền La Đại Thiên Tôn quan sát từ ngoài xác nhận Vương Lâm có huyết mạch Đạo cổ, tiên nhân thuật, bảy đạo bổn nguyên, nhận xét là Đạo tiên song tu — chưa từng thấy trên bất cứ ai.","anchor":"Ta nếu muốn rời khỏi nơi này rất dễ dàng, thậm chí trong nháy mắt đánh chết Thủy Tướng cũng dễ như trở bàn tay"},{"importance":"normal","mucCt":"ky","chuong":"@c1639","tieuDe":"Minh ngộ thủy bổn nguyên, thu bổn nguyên thứ ba","text":"Bị thủy cầu Càn Khôn Nhất Tích của Thủy Tướng đè ép nhưng lợi dụng toàn bộ quá trình để minh ngộ thủy bổn nguyên, quan sát ba triệu tám ngàn vạn lần biến hóa. Lấy giọt nước thủy bổn nguyên Thiên Vận Tử từng cho ra làm chìa khóa hoàn tất minh ngộ. Ra lệnh ngưng, toàn bộ thủy cầu tự co rút từ hai trăm trượng xuống năm trượng rồi ngưng tụ thành giọt nước thủy tinh trên lòng bàn tay, tiêu tán vào tay. Ôm quyền khom lưng vái Thủy Tướng nói đại ân như vậy xin nhận một vái. Phất tay áo gây cuồng phong tống toàn bộ thần thức Nạp Đa và tu sĩ Quy Nhất tông ra khỏi trận pháp, chỉ giữ lại Thủy Tướng một mình trong thủy trận.","anchor":"Đại ân như vậy, xin nhận của Vương mỗ một vái!"},{"chuong":"@c1640","importance":"major","mucCt":"ky","tieuDe":"Đạt mầm mống thủy bổn nguyên, đoạt áo giáp Thủy Tướng","text":"Sau khi hấp thu Càn Khôn Nhất Tích, Vương Lâm có được mầm mống thủy bổn nguyên — bổn nguyên thứ tám, thuộc thực bổn nguyên cần dung hợp nhiều lần mới đại thành. Cứu mạng Thủy Tướng bằng cách truyền sinh cơ vào mi tâm, tạo tấm màng ngăn hồn phách khỏi áo giáp, rồi dùng huyết kiếm chém đứt tia máu liên kết tách hoàn chỉnh áo giáp ra. Tuyên bố nguyên tắc ân thì trả, không giết kẻ có ân. Khi kẻ lạ từ dòng xoáy vươn cánh tay khô héo đoạt áo giáp, Vương Lâm bùng nổ toàn lực — bảy bổn nguyên dung hợp thành tu vi Không Linh hậu kỳ cộng Đạo cổ huyết mạch dung nhập thân thể — một bước đạp nát cánh tay kẻ kia, xương gãy vụn, cánh tay nổ tung. Thu áo giáp và trường thương vào tay áo. Bị kẻ lạ nhận ra là tu sĩ cổ quốc, người cổ tộc.","anchor":"Đây là nguyên tắc làm người của Vương mỗ!"},{"chuong":"@c1641","importance":"normal","mucCt":"ky","tieuDe":"Phá mộc trận kim trận, đối chưởng lão tổ","text":"Thu hồi áo giáp, đối chưởng Đệ Cửu lão tổ Quy Nhất tông qua dòng xoáy, chỉ lùi ba bước trong khi lão tổ bị bẻ gãy cánh tay phun máu. Chủ động bước vào Ngũ Hành mộc trận, dùng thuật Tê Thiên xé thiên địa thành hai nửa phá tan lá cây bao vây. Ép mộc linh quy phục bằng tuyên bố thần phục hoặc bị hủy diệt, thu được tinh thể xanh biếc ngưng tụ từ sinh cơ mộc linh. Phá nốt Ngũ Hành kim trận cuối cùng, toàn bộ Ngũ Hành đại trận tan rã. Đang muốn bước vào Ngũ Hành tinh thì sững lại phát hiện tinh cầu chuyển động — Cửu Chuyển Tâm Luân kích hoạt.","anchor":"Trong mắt hắn Ngũ Hành tinh không ngờ lại chuyển động!"},{"chuong":"@c1642","importance":"normal","mucCt":"ky","tieuDe":"Ngộ bản chất Cửu Chuyển Tâm Luân tại đệ cửu chuyển","text":"Bị mắc kẹt trong trận pháp Cửu Chuyển Tâm Luân bên cạnh Ngũ Hành tinh, trải qua chín chuyển. Tâm thần hao tổn cực độ, phun máu tươi, toàn thân nổi gân xanh, xúc động và điên cuồng tràn ngập. Cố phân tích cơ chế nhưng càng suy tư càng không thể tĩnh tâm, chuyển thứ sáu tới chín nhanh chóng trôi qua. Tới đệ cửu chuyển, nhắm mắt ngộ ra bản chất trận pháp: mọi thứ chuyển động đều do tâm mình không tĩnh, tâm động cho nên thần động, thân động, Ngũ Hành tinh xoay chỉ là phản chiếu tâm bất tĩnh. Lập tức tĩnh lặng, tơ máu tiêu tán, điên cuồng tiêu tán, xúc động tiêu tán, tâm như nước giếng cổ không chút gợn sóng, chuyển động bắt đầu chậm lại, bước đầu phá giải trận pháp.","anchor":"Hai mắt Vương Lâm tiêu tán tơ máu, vẻ điên cuồng tiêu tán, xúc động tiêu tán, chỉ còn lại sự bình tĩnh như nước giếng cổ không chút gợn sóng"},{"importance":"normal","mucCt":"ky","chuong":"@c1643","tieuDe":"Sáng tạo thân tình dẫn tâm, nghịch chuyển Cửu Chuyển Tâm Luân","text":"Trong đệ cửu chuyển, nhận ra Chân Giả bổn nguyên vô dụng vì tất cả đều từ tâm, sáng tạo phương pháp mới: thân tĩnh dẫn hồn tĩnh dẫn thần tĩnh dẫn tâm tĩnh, chín nhịp thở phá hoàn toàn Cửu Chuyển Tâm Luân. Không rời trận mà phản kích, dùng nguyên lý tâm động thì tinh động vẽ vòng tròn ngược chiều kim đồng hồ nghịch chuyển Ngũ Hành tinh, đảo ngược trận pháp đánh ngược tu sĩ Quy Nhất tông. Tu sĩ thường hôn mê ở đệ tứ chuyển, Nạp Đa cũng hôn mê ở đệ tứ chuyển, lão già kim bào chống tới đệ thất chuyển mới suy kiệt. Ba lão già trong tháp phải xuất thủ phá trận. Sau khi trận pháp bị phá, một thân bạch y hiện thân trên bầu trời Ngũ Hành tinh.","anchor":"Cả đời hắn tu đạo cứ mỗi lần chịu thiệt là đều trả lại gấp bội"},{"chuong":"@c1644","importance":"normal","mucCt":"ky","tieuDe":"Phá tháp Ngũ Hành, giao chiến Vân Dật Phong","text":"Xuất hiện trên bầu trời Ngũ Hành tinh sau nghịch động Cửu Chuyển Tâm Luân, chủ động khiêu chiến ba tu sĩ Tiên Cương. Triệu hư ảnh Đạo Cổ đội trời đạp đất hộ thể rồi cố ý để nó sụp đổ tạo sóng xung kích quét lui ba người. Giao chiến ngang sức với Vân Dật Phong — bị sáu đóa hoa đen từ Lục Hoa Ấn khắc lên cánh tay phải gây rữa nát, nhờ Đạo Cổ bất diệt thể khôi phục nhanh hơn đối thủ vài nhịp thở. Lợi dụng khoảng hở đánh quyền phá sập tháp từ tầng một tới tầng bốn, chỉ còn ba tầng gốc lơ lửng. Mục đích là bức hết lực lượng ẩn giấu lộ diện, xác định sức mạnh thật sự của chiếc đinh thứ hai sau Thiên Vận Tử để lên kế hoạch tìm hồn thứ ba.","anchor":"Hắn muốn xem nơi này rốt cục tồn tại cường giả tới bậc nào"},{"chuong":"@c1645","importance":"normal","mucCt":"ky","tieuDe":"Đấu roi với lão già tầng ba, kích hoạt bất diệt thể","text":"Xông vào Ngũ Hành đại trận Cửu Chuyển Tâm Luân trong tháp cao Quy Nhất tông, đối đầu lão già tóc bạc tầng ba (Không Huyền trung kỳ bước ba). Dùng Nhân Quả ấn hút bổn nguyên roi nhưng roi hấp thu sinh cơ bổ sung lại. Bị roi quất trúng bảy tấc trước thân, lui mấy bước phải nén máu tươi. Rút Côn Cực tiên dùng làm roi đánh roi đối roi, nhờ huyết mạch Đạo cổ, bảy đạo bổn nguyên trong phân thân và cánh tay Diệp Mịch, khí lực áp đảo giật đứt roi lão già. Khi lão già khoác áo giáp Quy Nhất tông triệu mộc nhân khổng lồ mấy ngàn trượng đánh tới, bình tĩnh kích hoạt Đạo cổ bất diệt thể bao phủ toàn thân chủ động chịu đòn. Mục đích thật là thăm dò lực lượng tu sĩ bên ngoài, không phải chém giết.","anchor":"Roi, Vương mỗ cũng có!"},{"chuong":"@c1646","importance":"normal","mucCt":"ky","tieuDe":"Rút lui khỏi Ngũ Hành tinh, phân tích đối thủ","text":"Rút lui an toàn khỏi Ngũ Hành tinh trên lưng U Minh thú đã huyễn hóa vô hình, áp chế thương thế rồi trở về Côn Hư. Đối phương không dám đuổi theo. Phân tích tu vi lão già họ Mã có thể mạnh hơn Chưởng Tôn, đã trải qua mấy lần huyền kiếp. Nhận ra bộ áo giáp tầng nhất tháp cao rất có thể thuộc về lão già họ Mã, nếu mặc vào tu vi sẽ khủng khiếp khó lường. Hắn vẫn còn hậu thủ là cây cung của Lý Quảng chưa dùng.","anchor":"Hắn còn có cây cung của Lý Quảng, dù không muốn dùng nhưng nếu thật sự có nguy cơ thì sẽ không do dự mà xuất ra"},{"mucCt":"ky","text":"Cưỡi U Minh thú chữa thương sau trận chiến, xác nhận Quy Nhất tông là lực lượng cướp đoạt hồn thứ ba đã bị bức ra toàn bộ, quyết tâm tự mình tham gia tìm kiếm hồn thứ ba. Rời Ngũ Hành tinh qua trận pháp ngân hà vào tiên giới. Trước khi vào, do tính cẩn thận đột ngột quay người chất vấn và vung gió lốc bảy đạo bổn nguyên thăm dò kẻ theo dõi, thực chất đề phòng lão già họ Mã bám theo. Bị Huyền La Đại Thiên Tôn bí mật theo sau nhưng không phát hiện. Trở về tiên giới đứng trước ngọn núi bế quan cũ, thần sắc ảm đạm tràn ngập nhung nhớ bi ai — hôm nay là một ngày đặc biệt mà mỗi năm hắn đều cố bận rộn để quên đi.","anchor":"Mỗi năm tới ngày này hắn đều muốn khiến cho mình quên đi, cũng làm cho mình bận rộn đủ mọi thứ để không thể nhớ nhung","bridge":true,"khoang":"@c1647"},{"chuong":"@c1648","importance":"normal","mucCt":"ky","tieuDe":"Nhập mộng ảo nhớ Lý Mộ Uyển","text":"Trong ngày kỷ niệm gặp Lý Mộ Uyển, Vương Lâm dùng tấm buồm mặt quỷ che thân ngồi một mình trên ngọn núi trong động phủ giới, uống rượu mạnh nhưng không xoa dịu được nỗi đau. Hắn mở Tỵ Thiên Quan vuốt ve khuôn mặt Lý Mộ Uyển đang hôn mê, rơi lệ, xác nhận một phần hồn phách của nàng đã bị mất và thề sẽ thu hồi bằng mọi giá bất kể trong tay ai. Hắn nhắc việc đã tiếp nhận Lý Thiến Mai, xin lỗi Uyển Nhi, thề cả đời không dính tới tình cảm nào nữa. Hắn thi triển thần thông Mặt quỷ nhập huyễn, mộng ảo ngàn năm — đặt tay lên mi tâm mình và mi tâm Lý Mộ Uyển, đưa thần thức vào mộng ảo tái hiện lần gặp gỡ đầu tiên hơn hai ngàn năm trước ở hải ngoại. Trong mộng, hắn cứu nàng khỏi trưởng lão dâm tà Tuyên Vũ Viên, chỉ liếc mắt phá tan tám phi kiếm và giết kẻ địch, ôm nàng, rồi mỉm cười nhìn nàng sợ hãi rời đi, ẩn nỗi đau dưới nụ cười. Hắn cảm nhận thời gian ở động phủ giới không còn dài, sắp tới Tiên Cương đại lục.","anchor":"Uyển Nhi.nhanh thôi, ta sẽ tới Tiên Cương đại lục.ở đó ta nhất định có biện pháp khiến nàng thức tỉnh"},{"importance":"normal","mucCt":"ky","chuong":"@c1649","tieuDe":"Dùng Hồn Phiên truy nguyên vạn cổ tìm hồn thứ ba","text":"Ngồi suốt đêm dưới trăng bên Lý Mộ Uyển trong Tỵ Thiên Quan, sáng sớm thu Tỵ Thiên Quan lại và thì thầm với Uyển Nhi. Xác định hướng tìm hồn thứ ba có thể lần đầu mối từ đạo nhân bảy màu và Chiến lão quỷ. Triệu Thanh Thủy tới, nghe nàng thừa nhận bản thân là một phách của Thất Thải Tiên Tôn. Cam kết sẽ giết hoặc phong ấn hồn thứ ba, không cho phép hồn cắn nuốt thất phách. Điểm mi tâm triệu ra Hồn Phiên mặt quỷ phóng đại mười trượng, cắn nuốt cả hai người, đưa thần thức vào thời vạn cổ khi Thất Thải Tiên Tôn bị phân chia ba hồn bảy phách để truy tìm hồn thứ ba.","anchor":"cuốn động thần thức của cả hai tiến vào trong năm tháng từ thời vạn cổ, trong tích tắc khi Thất Thải Tiên Tôn bị phân chia ba hồn bảy phách"},{"chuong":"@c1650","importance":"normal","mucCt":"ky","tieuDe":"Chủ động vào huyễn cảnh, minh ngộ bốn phách Thất Thải Tiên Tôn","text":"Vương Lâm dùng Thanh Thủy dẫn đường, mượn tấm buồm mặt quỷ chủ động tiến vào huyễn cảnh động phủ giới. Trong tầng một, chứng kiến Thanh Thủy tàn sát hoàng cung báo đại cừu, đồng cảm sâu sắc vì bóng lưng nhuộm máu giống chính hắn ở Đằng gia năm đó. Hắn gọi sư huynh, an ủi Thanh Thủy, rồi kích hoạt hắc khí chuyển sang tầng hai. Trong tầng hai, chứng kiến Thất Thải Tiên Tôn bị Liên Đạo Phi oanh kích vỡ nát, ba hồn bảy phách tán ra bốn phương. Hắn là nguồn gốc mọi vật nơi đây nên hiểu rõ hơn lần đạo nhân bảy màu vào trước. Quan sát bốn phách đầu tiên tiến vào luân hồi: phách đỏ đậm chủ sát chính là Thanh Thủy, phách xanh chứa toàn bộ tu vi chính là Tư Đồ Nam, phách cam chứa chính khí lương tri chính là Thanh Lâm, phách vàng đại biểu khí vận cơ duyên chính là Tham Lang. Minh ngộ rằng thiên tư biến hóa kinh người của Tư Đồ Nam là do hắn là phách của Thất Thải Tiên Tôn.","anchor":"Hắn là nguồn gốc của mọi vật nơi này, cho nên so với lần đó hắn đã hiểu ra không ít"},{"importance":"normal","mucCt":"ky","chuong":"@c1651","tieuDe":"Hé lộ tam hồn thất phách Thất Thải Tiên Tôn","text":"Chứng kiến phách thứ năm (lục) tiêu tán, nhận ra thân ảnh bên trong là Tán Linh Thượng nhân, tâm thần rung động dữ dội. Phách thứ sáu (lam) tiêu tán, sắc mặt tái nhợt khi nhận ra thân ảnh chính là Mộc Băng Mi — phách do tình cảm yêu hận của Thất Thải Tiên Tôn với Phàn San Mộng hóa thành. Phách thứ bảy (tím) quá mờ ảo, không nhìn rõ ai nhưng mơ hồ cảm giác đã gặp qua. Sau khi thất phách tiêu tán, tam hồn bay đi ba hướng: hồn thứ nhất hóa thành đạo nhân bảy màu nhận thần thông Tiên Tôn bay ra giới ngoại, hồn thứ hai luân hồi thành mãnh thú gặp Chiến lão quỷ đang độ huyền kiếp thất bại — đây là tiên duyên Chiến lão quỷ. Truy đuổi hồn thứ ba xuyên nhiều tinh vực: Triệu Hà → Côn Hư (lượn vòng) → Vân Hải, chứng kiến hồn thứ ba luân hồi nhiều lần thành mãng xà, thư sinh phàm nhân, đại thụ, tu sĩ Kết Đan. Hồn thứ ba luân hồi thành Tô Đạo tại Chu Tước Tinh, Triệu quốc — phàm nhân đại nho cả đời không tu đạo. Phát hiện nhân quả sâu xa: trong Mộng Đạo của mình đã được Tô Đạo nhận làm đệ tử nhưng chỉ thấy quả mà không tìm ra nhân. Cuối cùng chứng kiến hồn thứ ba tại Thanh Linh tinh, La Thiên Tinh Vực, luân hồi thành cá mấy trăm lần trong cùng con sông, cho tới khi ngư ông câu được — ngư ông nói vợ sắp sinh, ám chỉ hồn thứ ba chờ cơ hội đầu thai.","anchor":"Hắn nằm mơ cũng không nghĩ tới không ngờ cả nàng cũng là do một phách của Thất Thải Tiên Tôn biến thành"},{"chuong":"@c1652","importance":"major","mucCt":"ky","tieuDe":"Hồn thứ ba là Tạ Thanh","text":"Chứng kiến kiếp luân hồi cuối cùng của hồn thứ ba, thấy Tạ Thanh chào đời, chấn động nhận ra hồn thứ ba chính là đệ tử của mình. Ngộ ra vòng nhân quả tuần hoàn: năm đó điểm hóa Tạ Thanh nhận đệ tử kết nhân quả, trong Mộng Đạo gặp Tô Đạo làm sư phụ — hiện thực Tạ Thanh là đệ tử Vương Lâm, Mộng Đạo Vương Lâm là đệ tử Tô Đạo. Đối mặt câu hỏi giết hay không giết hồn thứ ba. Lùi ba bước phá sập toàn bộ huyễn cảnh, trở về hiện thực trong động phủ giới cùng Thanh Thủy, sắc mặt tái nhợt, ánh mắt đấu tranh.","anchor":"Hồn thứ ba là hắn."},{"importance":"normal","mucCt":"ky","chuong":"@c1653","tieuDe":"Giác ngộ biến số thiên đạo, tìm cách cứu Tạ Thanh","text":"Xác nhận hồn thứ ba của Thất Thải Tiên Tôn chính là đệ tử Tạ Thanh, thống khổ do dự không thể tự tay ra tay với đệ tử. Suy luận phách thứ bảy không nằm trong thiên đạo hiện tại (U Minh thú nuốt Thiên Vận Tử nhưng không có khí tức phách thứ bảy), chứng minh thiên đạo chưa hoàn chỉnh, nghi Thiên Vận Tử áo xám có thể mang phách thứ bảy. Liệt kê sáu phách đã biết: Thanh Thủy, Tư Đồ Nam, Tham Lang, Thanh Lâm, Mộc Băng Mi, Tán Linh thượng nhân. Được Huyền La Đại Thiên Tôn điểm chỉ, giác ngộ khái niệm biến số — bốn phách (Tham Lang, Thanh Lâm, Mộc Băng Mi, Tán Linh) đã qua luân hồi trở thành thân thể độc lập tách biệt khỏi Thất Thải Tiên Tôn, trong khi Thanh Thủy và Tư Đồ Nam chưa xảy ra biến số. Nhận ra nếu nắm được lực lượng biến số trong thiên đạo có thể khiến hồn thứ ba Tạ Thanh độc lập, ngăn tam hồn dung hợp. Một bước biến càn khôn tới La Thiên Tinh Vực, dựa nhân quả sư đồ cảm nhận Tạ Thanh đang ở tu chân tinh phía đông La Thiên, hướng đó mà đi.","anchor":"Nếu có thể nắm được lực lượng này trong tay thì có thể khiến cho hồn thứ ba độc lập"},{"importance":"normal","mucCt":"ky","chuong":"@c1654","tieuDe":"Tạ Thanh tử vong, thu hồn thứ ba, Không Diệt khí sơ hiện","text":"Tới tu chân tinh phía đông La Thiên, gặp lại đệ tử Tạ Thanh tại u cốc hoa lan. Đau đớn khi biết Tạ Thanh chính là hồn thứ ba của Thất Thải Tiên Tôn và sắp chết. Nhớ lại cảnh quen biết Tạ Thanh, so sánh với Thập Tam — đều là đệ tử của mình. Từng nói với Thanh Thủy phải giết hồn thứ ba nhưng lúc này không thể vì đau đớn như phải giết con. Phẫn nộ chất vấn trời, tuyên thề cả đời muốn diệt trời bất kể trời động phủ giới hay Tiên Cương đại lục. Toàn thân bộc phát khí thế ngưng tụ thành thanh kiếm hư ảo mang khí tức Không Diệt — lần đầu sơ hiện, khiến Huyền La Đại Thiên Tôn kinh hãi. Sau khi Tạ Thanh khí tuyệt thân vong, bước tới thu lấy hồn thứ ba từ thất khiếu. Khi nắm hồn thứ ba, thiên địa biến sắc, tứ đại tinh vực ầm vang, giới ngoại cũng kinh thiên.","anchor":"Vương Lâm ta từ trong luân hồi thiên kiếp tìm được vận mệnh của chính mình"},{"importance":"major","mucCt":"ky","chuong":"@c1655","tieuDe":"Tạ Thanh qua đời, dung nhập hồn thứ ba","text":"Chứng kiến đệ tử Tạ Thanh gọi tiếng sư tôn cuối cùng rồi mỉm cười qua đời trong sơn cốc đầy thu lan trên tu chân tinh La Thiên. Phẫn nộ với thiên ý trêu người, tuyên bố sẵn sàng hủy diệt thiên không nếu thiên ý không tôn trọng ý niệm. Xác nhận hồn thứ ba xuất hiện trong thi thể Tạ Thanh, coi nó là đệ tử chứ không phải Thất Thải Tiên Tôn, thề sẽ giúp Tạ Thanh ngưng tụ thành hồn thức tỉnh trí nhớ. Nhắm mắt dung nhập hồn thứ ba vào cơ thể, kích hoạt trung tâm động phủ mở ra, toàn bộ động phủ giới chấn động.","anchor":"Có vi sư ở đây, ngươi chắc chắn có thể ngưng tụ thành hồn một lần nữa, thức tỉnh trí nhớ"},{"importance":"normal","mucCt":"ky","chuong":"@c1656","tieuDe":"An táng Tạ Thanh, phô bày hồn thứ ba trước quần hùng","text":"Nhận ra đại môn trung tâm động phủ (từng bị thiên đạo đánh vỡ ở chiến trường ngoại vực Chu Tước Tinh) ngưng tụ lại hoàn chỉnh trước tu chân tinh. Cúi nhìn thi thể Tạ Thanh quỳ trong sơn cốc, bi ai thì thào rồi dùng thu lan an táng nàng thành ngôi mộ, khiến từ đó mỗi mùa thu hoa lan ngập tràn tu chân tinh vô danh. Nghe Chiến lão quỷ cam đoan an toàn cho tiên giới và hứa mở đường Tiên Cương đại lục, nghe đạo nhân bảy màu hứa cho thê tử sống lại và tặng toàn bộ động phủ giới, nhưng không đáp, không động tâm vì quan hệ với Tạ Thanh, Thanh Thủy, Tư Đồ Nam. Nhắm mắt đợi quần hùng tới đủ rồi mở mắt tuyên bố mọi người đều muốn hồn này, giơ tay phải phô bày hồn thứ ba lấp lóe u quang trước mặt hàng loạt cường giả.","anchor":"Những người đáng tới cũng đã tới rồi.các người đơn giản đều muốn hồn này"},{"importance":"normal","mucCt":"ky","chuong":"@c1657","tieuDe":"Cuộc săn hồn — mở đại môn động phủ","text":"Trước mặt tất cả tu sĩ, Vương Lâm tuyên bố đây là cuộc săn hồn thứ ba, cảnh cáo kẻ nào muốn giết hắn lấy hồn thì phải chuẩn bị bị giết. Hắn dùng hồn thứ ba mở đại môn động phủ — chỉ người có hồn thứ ba mới làm được — cánh cửa tách đôi, cơn lốc cực mạnh đẩy lùi tất cả trừ hắn, rồi bước vào khi cửa mới mở ba phần. Bên trong, hắn nhận ra trung tâm động phủ chính là cánh cửa thông tới Tiên Cương đại lục. Thông qua trí nhớ hồn thứ ba bị Tạ Thanh phong ấn, hắn biết bí mật sát chiêu cuối cùng của Thất Thải Tiên Tôn mà không ai khác biết, nhưng cần tích đủ sát lục mới dùng được. Hắn lên kế hoạch dùng ba trăm tàn nguyên giới để giết đối thủ yếu, tích lũy sức mạnh cho trận quyết chiến cuối cùng với đạo nhân bảy màu và Chiến lão quỷ. Cuối cùng bước vào giọt sương trên đóa hoa khổng lồ, phát hiện bên trong là một vùng tinh không tỏa ánh sáng như ngọc, tràn ngập tinh vân.","anchor":"Đây là một cuộc săn hồn! Hoặc các ngươi là thợ săn, hoặc ta là thợ săn"},{"mucCt":"ky","text":"Vương Lâm dung nhập vào đại đỉnh trung tâm động phủ, khuôn mặt hiện trên mặt đỉnh bị hắc khí bao quanh. Bên trong phát hiện đóa hoa vàng năm cánh mang ba trăm giọt sương, mỗi giọt là một thế giới thất bại của Thất Thải Tiên Tôn khi sáng tạo động phủ giới. Nhờ ký ức hồn thứ ba hiểu rõ lai lịch ba trăm tàn giới và phân loại ba loại (tiên thú biến dị, phàm nhân sinh sôi, không sinh linh). Tản thần thức lục soát chín tu chân tinh trong tàn giới loại ba, không tìm thấy gì. Sau nửa canh giờ phát hiện sóng gợn vô hình lan từ ngọn núi trọc hình kiếm trên tu chân tinh thứ năm, dò xét nhưng núi hoàn toàn bình thường. Thử truyền thần niệm vào ngọn núi để định quy tắc, thiên địa ầm vang, quy tắc mơ hồ sinh ra nhưng bị đè nén vì tàn giới không đủ lực ngưng tụ, quyết định thay đổi cách thức.","anchor":"Ta là người đầu tiên tới nơi này, định ra quy tắc","bridge":true,"khoang":"@c1658"},{"chuong":"@c1659","importance":"normal","mucCt":"ky","tieuDe":"Thí nghiệm quy tắc cấm phi hành, giết bốn đệ tử Thất Đạo Tông","text":"Ngồi trên đỉnh núi tu chân tinh trong tàn giới, ngưng tụ thành công quy tắc cấm phi hành (duy nhất trong nhiều quy tắc đã thử). Dùng huyết kiếm xuyên mi tâm giết lão già Thất Đạo Tông đầu tiên, sau đó hồn thứ ba bắt quyết tế huyết mạch và thần hồn nạn nhân cho thân thể kia — cánh tay đen kịt phủ hắc khí xuất hiện chụp bắt rồi biến mất. Năm ngày đắm chìm dung hợp ký ức hồn thứ ba. Ngày thứ sáu phục kích giết ba đệ tử Thất Đạo Tông (một Không Niết sơ kỳ, hai thiên nhân ngũ suy) trong chưa tới ba nhịp thở. Phát hiện dòng xoáy mới xuất hiện, bên trong là một nữ tử bí ẩn.","anchor":"Giết ba người không cần tới ba nhịp thở!"},{"chuong":"@c1660","importance":"normal","mucCt":"ky","tieuDe":"Dụ Tử Hà rời dòng xoáy, ra đòn chí mạng","text":"Nhận ra Tử Hà xuất hiện từ dòng xoáy, chủ động phóng huyết kiếm tấn công thăm dò, hai bên ngang sức. Bố trí kế tâm lý nhiều tầng: giả vờ vội vã rời đi như bị thương, khi Tử Hà phóng phi kiếm tím thử sức thì cố ý bộc phát sáu đạo bổn nguyên chấn nát phi kiếm rồi cười lạnh bỏ đi, dụ nàng suy luận ngược rằng hắn đang giấu thương tích. Tử Hà mắc bẫy, thu ngọc giản truyền tin, bước ra khỏi dòng xoáy truy đuổi, mất đường rút lui. Quy tắc tàn giới phát tác khiến thân thể nàng rơi vụt xuống, Vương Lâm lập tức quay người bộc phát huyết quang, huyết kiếm đánh thẳng mi tâm Tử Hà, máu đen phun ra từ ngực nàng, trọng thương.","anchor":"bỏ qua trạng thái giả trọng thương, tu vi trong nháy mắt bộc phát, bảy đạo bổn nguyên từ cấm chế bổn nguyên thì sáu đạo đồng loạt vờn quanh thân thể"},{"importance":"normal","mucCt":"ky","chuong":"@c1661","tieuDe":"Bắt sống Tử Hà, xông vào tàn giới Bạch Hổ","text":"Dùng huyết kiếm xuyên ngực Tử Hà, thi triển liên hoàn sáu đạo bổn nguyên (hỏa, lôi điện, sinh tử, nhân quả, chân giả, sát lục) đánh trọng thương cả thân thể lẫn nguyên thần nàng. Thi triển Định thân thuật một chỉ định thân, định thần, định hồn, rồi điểm chín chỉ phong ấn đại thành, thu Tử Hà vào tay áo, bắt sống thay vì giết vì trên người nàng còn nhiều thứ khiến hắn hứng thú. Toàn bộ chiến đấu không quá mười nhịp thở. Rời tàn giới trước, xông qua dòng xoáy vào một tàn giới khác nơi Bạch Hổ chiến tướng đã thiết lập quy tắc. Dùng thần thức quét toàn tinh không, nhận ra quy tắc đã tồn tại, chủ động đứng yên giữ mình ngoài quy tắc. Giả vờ tạo dòng xoáy rời đi để thử phản ứng Bạch Hổ, từ đó tìm ra đáp án. Nghe Bạch Hổ đề nghị đánh cuộc cược hồn thứ ba đổi nô bộc vạn năm, bề ngoài bình tĩnh nhưng khóe miệng lộ nụ cười.","anchor":"Thần sắc Vương Lâm bình tĩnh, chỉ là trên mặt lại lộ ra một tia mỉm cười mà người khác khó có thể phát hiện"},{"mucCt":"ky","text":"Vương Lâm phân tích quy tắc bàn cờ trên tu chân tinh thứ ba, nhận ra Đạo Cổ truyền thừa của mình cũng có lực lượng huyết mạch, phối hợp tu vi còn mạnh hơn Bạch Hổ. Tiến vào tàn giới, huyết mạch bộc phát khiến lực áp chế phân tán cho ba người, phá vỡ tính toán của Bạch Hổ, đồng thời nới lỏng áp chế cho nam tử Ngũ Hành tinh. Thần thức dung nhập binh lính, chiến đấu trên chiến trường trăm vạn đại quân, giết địch binh tích hắc khí ngưng tụ thành giáp đen toàn thân rồi hắc mã, cưỡi ngựa lao thẳng về phía tướng lãnh bạch giáp của Bạch Hổ. Diệt mười hắc giáp binh trong nửa nén hương. Ý thức rõ thời gian cấp bách vì đạo nhân bảy màu đang truy tới.","anchor":"hắc khí bên ngoài thân thể Vương Lâm liền ngưng tụ co rút lại, bất ngờ hóa thành một bộ áo giáp màu đen","bridge":true,"khoang":"@c1662"},{"chuong":"@c1663","importance":"normal","mucCt":"ky","tieuDe":"Thắng Bạch Hổ trong giới cờ, giơ đao chờ nguy cơ","text":"Trong ván cờ giới, Vương Lâm hóa chiến tướng hắc giáp đối đầu chiến tướng bạch giáp của Bạch Hổ Thánh Hoàng. Lần va chạm đầu, trường đao đối trường thương cùng hủy, hai ngựa va đầu chết, hư ảnh Đạo cổ Vương Lâm (không phải Diệp Mịch) hiện ra. Bạch Hổ từ chối nhận thua, giết gần mười vạn binh lính không phân địch ta để tái tạo lực lượng. Vương Lâm chọn thôn phệ chiến tướng kim giáp (tu sĩ Ngũ Hành tinh) bằng bản năng thôn hồn, lập tức tăng mạnh, tái tạo giáp mũ giáp, dưới thân ngưng tụ hắc long thay ngựa. Quyết chiến lần hai, một đao kèm hư ảnh Đạo cổ chẻ đôi chiến tướng bạch giáp từ mi tâm. Tuyên bố thu Bạch Hổ làm nô bộc. Bổn tôn cảm nhận nguy cơ mãnh liệt, hợp nhất với phân thân, nuốt toàn bộ khí tức bạch giáp, ngưng tụ đại đao đạt lực lượng giới hạn tàn giới, giơ đao chờ sẵn. Tay trái bắt quyết hóa ô lửa nhỏ rồi biến mất.","anchor":"Một đao này đã đạt tới lực lượng giới hạn của giới này!"},{"chuong":"@c1664","importance":"normal","mucCt":"ky","tieuDe":"Nhất đao mượn lực cả giới chém đạo nhân bảy màu","text":"Ngưng tụ toàn bộ tu vi vào một đao, hấp thu cơn lốc hắc khí, áo giáp, toàn bộ binh lính trên bàn cờ Bạch Hổ, đánh tan quy tắc Bạch Hổ khiến Bạch Hổ phun máu. Đường đao mượn quy tắc cả tàn giới xuyên tinh không vạn trượng chém thẳng đạo nhân bảy màu, đánh vỡ hai cánh Thất Thải Đạo Liên, lực lượng trùng kích phá hủy bảy tu chân tinh, tàn giới hủy diệt hoàn toàn. Khi đạo nhân phản công bằng năm cánh hoa còn lại, dùng Phần Giới Cổ Tán đã bí mật huyễn hóa sẵn bằng tay trái (tiêu hao sinh cơ) biến thành ô lửa chặn đỡ, nương lực trùng kích lùi ba bước dung hợp dòng xoáy thoát thân. Trước khi rời đi kịp hạ mệnh lệnh đầu tiên cho Bạch Hổ chiến tướng: bắt tu sĩ Ngũ Hành tinh vì có chỗ quan trọng cần dùng.","anchor":"Đây chính là mệnh lệnh đầu tiên Vương Lâm giao cho Bạch Hổ chiến tướng."},{"mucCt":"ky","text":"Bị đạo nhân bảy màu truy kích xuyên ba trăm tàn giới, dùng thuật Tê Thiên (lực cánh tay Diệp Mịch) xé hư không phá dòng xoáy xóa dấu vết. Phát hiện tàn giới có mãnh thú ngủ say, ghi nhớ vị trí không kích thích. Bày kế trong kế: kế thứ nhất cố ý khiến tấm màn ngăn cách các giới sắp sụp đổ để đối phương tập trung đối phó; kế thứ hai dùng tấm buồm mặt quỷ biến thành tu chân tinh tầm thường, kết hợp lặp hành động xuyên giới cả trăm lần tạo thói quen tiềm thức cho kẻ truy kích. Lừa thoát tất cả kẻ truy kích kể cả đạo nhân bảy màu và Chiến lão quỷ. Đi ngược hướng quay lại tàn giới mãnh thú, quyết định dùng Tam mệnh thuật phản kích, bắt quyết áp tay lên mặt đất bắt đầu chuẩn bị.","anchor":"việc Vương Lâm hành động lặp đi lặp lại cả trăm lần, xuyên qua tấm màn ngăn cách các giới cả trăm lần khiến người truy kích có thói quen theo tiềm thức","bridge":true,"khoang":"@c1665"},{"chuong":"@c1666","importance":"major","mucCt":"ky","tieuDe":"Bảy tầng mai phục kinh thiên","text":"Trên tu chân tinh sa mạc cát vàng cuối cùng, Vương Lâm phát hiện Mục Ngư dưới lòng đất đã nuốt hết các tu chân tinh khác trong tinh vực. Hắn lần lượt bố trí bảy tầng mai phục: Phần Giới Cổ Tán vô hình che phủ thiên địa, Thất Thải Đạo Thương cắm xuống mặt đất, bổn tôn Đạo Cổ triệu hồi Khai Thiên Phủ toàn lực rồi ẩn đi, buồm mặt quỷ hút gần nửa máu tươi tạo ảo cảnh, U Minh thú ẩn sương mù, vòng máu kích Mục Ngư dưới lòng đất, cung Lý Quảng triệu hồi bằng huyết mạch tiên nhân cuối cùng. Tiêu hao gần nửa máu tươi và cực nhiều tinh lực, thần sắc uể oải. Sau đó đốt hương đen phát tín hiệu, khống chế Tử Hà truyền thần niệm vào ngọc giản truyền âm rồi vỡ vụn làm mồi nhử. Mục tiêu không phải giết mà là trọng thương một trong hai kẻ thù (đạo nhân bảy màu hoặc Chiến lão quỷ) để phá thế cân bằng lực lượng giữa hai bên.","anchor":"Bảy tầng mai phục, tạo thành một cái bẫy kinh thiên!"},{"importance":"normal","mucCt":"ky","chuong":"@c1667","tieuDe":"Giăng bẫy toàn lực thi triển Phần Giới Cổ Tán","text":"Phân thân ngồi trên tu chân tinh cát vàng, tay cầm cung Lý Quảng uốn cong như trăng non chờ đợi. Lấy hồn thứ ba từ mi tâm phóng thích toàn bộ khí tức làm mồi nhử, tuyên bố ai tới gần một trượng được lấy hồn. Đốt chiến hương dẫn dụ đệ tử Thất Đạo Tông, ngọc giản Tử Hà vỡ triệu tập ba chiến tướng. Đạo nhân bảy màu, Chiến lão quỷ, tam đại chiến tướng và các tu sĩ đều lao vào tinh cầu. Kích hoạt Phần Giới Cổ Tán — lần đầu bất chấp tất cả thi triển, cổ tán khổng lồ hiện ra chống trời biến bầu trời thành biển lửa đỏ rực, đóng cửa quan ngăn đường lui. Dung nhập hỏa bổn nguyên vào cổ tán, hư hỏa thiêu đốt tâm thần tu sĩ bên trong. Thu ba thành giết ba đệ tử Thất Đạo Tông chưa đạt bước thứ ba. Thu sáu thành khiến tam đại chiến tướng đồng loạt sắc mặt đại biến. Cố ý dùng lực cổ tán ngăn Lam Mộng Đạo Tôn ở bên ngoài để bảo vệ.","anchor":"Phần Giới Cổ Tán từ khi Vương Lâm học được đây là lần đầu tiên hắn bất chấp tất cả thi triển ra!"},{"importance":"normal","mucCt":"ky","chuong":"@c1668","tieuDe":"Sáu tầng phục sát động","text":"Thi triển Phần Giới Cổ Tán đạt cực hạn tám thành, sức sống tuôn ra điên cuồng, toàn thân già nua quá nửa. Tung đệ nhị phục trường thương bảy màu phá tan hoàn toàn đài sen bảy màu của đạo nhân bảy màu. Bổn tôn ngàn trượng hiện ra cầm Khai Thiên Phủ vung về phía bảy màu, cố ý để búa vỡ bạo phát toàn bộ uy lực. Tung đệ tứ phục Quỷ Kiếm Huyết Phàm vây khốn Chiến lão quỷ khiến hắn mê man bất động. Triệu hồi U Minh Thú nuốt hàng loạt đệ tử Thất Đạo Tông và lục phi, khiến đạo nhân bảy màu hoảng sợ khoảnh khắc thay cho Định Thân Thuật. Vỗ tay lên mặt đất dùng mật thuật Bạch Hổ kết hợp phương pháp thao túng lực lượng học từ đệ nhị Chu Tước kích thích Mục Ngư biến dị thức tỉnh, vòng tròn máu nổ tung bao vây bảy màu. Cả phân thân lẫn bổn tôn đều trọng thương nghiêm trọng, nhờ Đạo Cổ bất diệt thể dung hợp hồi phục nhưng vẫn cực kỳ suy nhược.","anchor":"Hắn chính là chủ trận, còn bố trí mai phục, nhưng lại gặp phải thương thế mức này, có thể thấy được đạo nhân bảy màu hùng mạnh như thế nào!"},{"mucCt":"ky","text":"Nắm thời cơ đạo nhân bảy màu bị tám con Mục Ngư vây đánh, Vương Lâm kéo cung Lý Quảng bắn tiễn thứ nhất xuyên qua hào quang bảy màu đâm trúng ngực đối thủ, nhưng bảy màu kịp túm đuôi tên nên không bị xuyên thủng. Sức phản lực khiến Vương Lâm khóe miệng tràn máu, tu chân tinh vỡ vụn. Mũi tên bị bảy màu rút ra liền tiêu tan và tự quay về dây cung, Vương Lâm lập tức kéo cung bắn tiễn thứ hai.","anchor":"tay phải cầm cây cung của Lý Quảng giơ mạnh lên tay trái kéo dây cung","bridge":true,"khoang":"@c1669"},{"chuong":"@c1670","importance":"normal","mucCt":"ky","tieuDe":"Cạn kiệt huyết mạch tiên nhân, triệu hồi Liên Đạo Phi làm lá chắn","text":"Bắn tiễn thứ hai từ cung Lý Quảng xuyên thủng ngực đạo nhân bảy màu gây trọng thương. Kim quang huyết mạch tiên nhân trong đồng tử gần như tiêu tan, chỉ còn đủ sức cho một cung cuối. Bắn tiễn thứ ba va chạm chín mặt trời nổ tung, tạo sức mạnh hủy diệt ba trăm tàn giới, kim quang huyết mạch tiên nhân hoàn toàn tiêu tan. Đã chuẩn bị từ trước, bấm quyết triệu hồi Liên Đạo Phi từ không gian trữ vật ra phía trước làm lá chắn chống lực hủy diệt. Liên Đạo Phi có tiên nhân bất diệt thể hoàn chỉnh, chắn toàn bộ mà lông tóc không hư tổn. Sự xuất hiện của Liên Đạo Phi khiến đạo nhân bảy màu lần đầu tiên bỏ chạy, toàn trường chấn động.","anchor":"Vương Lâm hiểu rõ bản thân chỉ còn lại sức mạnh cho một cung, cũng là một cung cuối cùng"},{"importance":"normal","mucCt":"ky","chuong":"@c1671","tieuDe":"Thu Mục Ngư, thoát Chiến lão quỷ, gặp Vân Na","text":"Thu được ba con Mục Ngư trong ba trăm giới đang sụp đổ, mất con thứ tư vào tay Huyền La Đại Thiên Tôn (tổng cộng mất sáu con). Hư trương thanh thế bằng lời thách thức về lực bắn cung Lý Quảng, khiến Chiến lão quỷ do dự không đuổi theo, đây là kết quả hài lòng nhất trong bảy tầng sát cục. Dẫn người điên vào dòng xoáy rời ba trăm giới, bị trọng thương phun máu. Tiến vào đệ nhị hoa của Ngũ hoa bát môn — thế giới hoàn toàn đóng băng do Thất Thải Tiên Tôn tạo dựa trên ký ức về Đông Lâm tông. Gặp nữ Cổ Thần Vân Na, được nàng nhận là chủ nhân mới vì mang phân hồn Thất Thải Tiên Tôn, được đề nghị dung hợp tâm thần huyết cuối cùng của Diệp Mịch để chữa thương.","anchor":"Hắn năm đó khi giết Hướng gia lão tổ ở La Thiên Tinh Vực đã từng cảm nhận được khí tức này"},{"chuong":"@c1672","importance":"major","mucCt":"ky","tieuDe":"Hấp thu nguyên thần huyết, Diệp Mịch đoạt xá thất bại","text":"Được nữ Cổ Thần trao giọt nguyên thần huyết cuối cùng của Diệp Mịch, kiểm tra bằng thần thức rồi vỗ vào mi tâm hấp thu. Nguyên thần huyết đầy đủ khiến thân thể phình to hơn trăm trượng, xương cốt chắc hơn, Đạo cổ lực mạnh mẽ hơn. Nguyên thần Diệp Mịch ngưng tụ thành thực chất rồi hóa khói xông vào thất khiếu mưu đoạt xá, nhưng Vương Lâm có hồn huyết được cổ Tổ tán thành nên Diệp Mịch không thể đối kháng, sau ba canh giờ tiêu tán hoàn toàn thành một bộ phận Đạo cổ truyền thừa. Thương thế hoàn toàn khôi phục, đã có hơn phân nửa Đạo cổ truyền thừa, còn thiếu mắt trái, trái tim hoặc cánh tay trái của Đạo cổ. Đồng ý giúp nữ Cổ Thần rời khỏi động phủ giới.","anchor":"Hắn đã đạt được sự tán thành của cổ Tổ, đạt được hồn huyết"},{"importance":"major","mucCt":"ky","chuong":"@c1673","tieuDe":"Dung hợp cánh tay trái Diệp Mịch","text":"Hoàn tất dung hợp giọt máu Cổ Thần cuối cùng, Đạo Cổ lực tràn khắp toàn thân, tinh điểm trên mi tâm và hai mắt ngưng thật, u quang đậm hơn. Cảm ứng sự kêu gọi từ sâu trong tầng băng, bay tới Đông Lâm Trì đóng băng phía sau ngọn núi. Phát hiện cánh tay trái khổng lồ của Diệp Mịch phong ấn dưới hồ băng nửa trong suốt. Dùng huyết kiếm đâm tầng băng nhưng bị bật lại, chuyển sang thi triển Đạo Cổ bất diệt chỉ phá băng suốt mấy canh giờ, tạo hố sâu bốn trượng. Thu khối băng chứa lực lượng giống bổn nguyên vào không gian trữ vật. Lộ da tay cánh tay trái Diệp Mịch tỏa khí tức Đạo Cổ nồng đậm, đặt tay trái lên hấp thu ba ngày, cánh tay thu nhỏ hóa làn khói chui vào tay hắn — dung hợp thành công. Nay đã có cả hai cánh tay Diệp Mịch, uy lực thuật Tê Thiên sẽ tăng mạnh. Hứa giúp nữ Cổ Thần rời khỏi nơi này, nói rõ ân oán phân minh.","anchor":"cánh tay trái hóa thành một làn khói chui vào trong tay Vương Lâm"},{"importance":"major","mucCt":"ky","chuong":"@c1674","tieuDe":"Dung hợp cánh tay trái Diệp Mịch, xâm nhập cổ mộ","text":"Dung hợp hoàn toàn cánh tay trái Diệp Mịch từ khí tức trong hồ băng, cánh tay trở nên thô ráp xuất hiện ký hiệu phức tạp, tinh điểm tam tộc cổ biến hóa kịch liệt, mơ hồ xuất hiện hình ảnh tinh điểm thứ chín. Dùng thuật Tê Thiên với sức mạnh hai tay xé đôi hồ băng và mặt đất, xuyên vào ngũ hoa bát môn qua khe nứt khổng lồ. Đi qua đệ tam hoa đã chết hoàn toàn, từ bỏ kế hoạch mai phục tại đó vì Chiến lão quỷ đa nghi. Tiến vào đệ tứ hoa, phát hiện thế giới bên trong chính là vùng đất cổ mộ nơi năm đó đạt Đạo Cổ truyền thừa, do Thất Thải Tiên Tôn bố trí. Quyết định liều mạng xuống tầng hai cổ mộ để hấp thu trái tim Diệp Mịch, nếu thành công sẽ đạt Cổ Thần cửu tinh và Cổ Ma cửu tinh. Đã nắm toàn bộ bản đồ tầng một, tiến thẳng tới cửa vào tầng hai.","anchor":"Phú quý hiểm trung cầu, cả đời Vương Lâm đều phải chu du trong tử vong"},{"importance":"normal","mucCt":"ky","chuong":"@c1675","tieuDe":"Xác nhận Dĩ Ti Chi Khôi tại tầng hai cổ mộ","text":"Xâm nhập vùng đất cổ mộ, dựa ký ức hồn thứ ba nhận ra khí tức kinh khủng tầng hai chính là Dĩ Ti Chi Khôi — sát chiêu cả đời Thất Thải Tiên Tôn tế luyện, đại thành sau khi giết Diệp Mịch. Tiết lộ mỗi lần giết người đều dùng phương pháp trong ký ức hồn thứ ba để tế hồn, tạo liên lạc kỳ dị với Dĩ Ti Chi Khôi. Suy luận vùng đất cổ mộ rất có khả năng do Thất Thải Tiên Tôn tạo ra để nuôi dưỡng Dĩ Ti Chi Khôi. Đi qua truyền tống trận cổ xưa vào tầng hai, đối mặt Dĩ Ti Chi Khôi hình đầu lâu khổng lồ trên ngọn núi, bị tiếng gầm đẩy lùi ngàn trượng và trào máu dù đã dùng Đạo cổ lực phòng hộ. Nhận ra muốn khống chế Dĩ Ti Chi Khôi phải giết thêm tu sĩ có đại thần thông để tế hồn. Ẩn thân khi đệ tam phi tới, sau đó hiện thân chặn dư âm tiếng gầm cho nàng, lạnh lùng từ chối sự giúp đỡ nhưng đệ tam phi đưa ra chuỗi hạt châu có thể hóa bảy kim môn.","anchor":"Nó chính là Dĩ ti chi khôi!"},{"mucCt":"ky","text":"Hỏi tên thật Đường San, biết nàng thuộc Thiên Môn Đạo. Đối đầu ánh mắt Vân Dật Phong khiến hắn lùi nửa bước, nhận thệ huyết thách đấu đường đường chính chính. Dùng quyền Đạo Cổ phá trường đao, sau đó triệu hai cánh tay Diệp Mịch thi triển Tê Thiên Thuật đại thành xé hư không, phá tan hoàn toàn Bát Đao Trảm Thần Hồn. Tuyên bố ngay cả Định Thân Thuật cũng không dùng. Vân Dật Phong thừa nhận thua, thệ huyết hoá lời thề ràng buộc. Cảm nhận ba luồng khí tức quen thuộc tới gần, sai Vân Dật Phong tấn công Chưởng Tôn, phóng huyết kiếm đẩy lùi Chưởng Tôn một bước. Được Đường San thi triển Thất Diện Kim Môn phòng hộ lên người, lần đầu chứng kiến thần thông phòng hộ có thể dùng cho người khác.","anchor":"Thuật Tê Thiên đã đại thành, uy lực của nó cực kỳ kinh người","bridge":true,"khoang":"@c1676"},{"importance":"normal","mucCt":"ky","chuong":"@c1677","tieuDe":"Lùi ba bước dẫn dụ Huyền La xuất thủ","text":"Bị Chưởng Tôn phán đoán đã cạn sức sau ba lần giương cung, không còn dùng được cung Lý Quảng. Thi triển Tê Thiên Thuật chống lại Chưởng diệt tam đạo của Chưởng Tôn, phá được hai tầng đầu nhưng bị kim ấn tầng ba vượt qua. Không hoảng loạn, tỉnh táo lùi ba bước từ xa tới ngay sau lưng Huyền La rồi khoanh chân ngồi xuống, ánh mắt chạm Huyền La trong vô hình — ép Huyền La ra tay. Huyền La chỉ tay biến kim ấn thành pháp bảo thực chất lơ lửng trước mặt Vương Lâm. Nhìn thấy rõ biểu cảm hoảng sợ và cúi đầu của Vân Dật Phong sau sự kiện này.","anchor":"thần sắc không một chút hoảng loạn, cực kỳ tinh tảo"},{"importance":"normal","mucCt":"ky","chuong":"@c1678","tieuDe":"Nhận chủ kim ấn, bành trướng thân Cổ Thần, vây đánh Chưởng Tôn","text":"Nhận chủ kim ấn vô chủ do Huyền La sáng tạo từ hư ảo, nuốt vào miệng tế luyện trong nguyên thần. Lần đầu tiên hoàn toàn bành trướng thân thể Cổ Thần lên mấy vạn trượng, cùng Thác Sâm phong tỏa trước sau Chưởng Tôn. Phóng hơn mười lá Cổ Tức Diệp phong kín đường lui Chưởng Tôn, thi triển Tê Thiên Thuật xé thiên địa lao tới. Dùng Định Thân Thuật chặn ngụm nguyên thần huyết màu vàng của Chưởng Tôn, phóng huyết kiếm xuyên qua vai Chưởng Tôn khiến hắn phun máu. Lực phản phệ trong cơ thể bộc phát khiến sắc mặt tái nhợt.","anchor":"thân thể hắn lần đầu tiên hoàn toàn bành trưởng"},{"importance":"normal","mucCt":"ky","chuong":"@c1679","tieuDe":"Tế hồn Chưởng Tôn, Dĩ Ti hiện thân lần đầu","text":"Chỉ huy Lam Mộng Đạo Tôn phong ấn Chưởng Tôn ba nhịp thở. Trong ba nhịp thở, dùng Mộng Đạo (mặt quỷ huyễn cảnh) điểm mi tâm Chưởng Tôn, dung hợp hồn rồi tế hồn cho Dĩ Ti, nuốt mất nửa hồn Chưởng Tôn. Bị phản đòn phun máu tươi lui lại. Triệu hồi Dĩ Ti hiện thân lần đầu tiên từ ngọn núi hắc khí, sương đen bao phủ chiến trường, Dĩ Ti đánh bại Chưởng Tôn trong sương mù. Nhận ra Dĩ Ti chưa đạt đỉnh Không Kiếp Sơ Kỳ như ký ức Thất Thải Tiên Tôn miêu tả, chỉ tương đương mấy lần huyền kiếp, cần tế hồn thêm để khống chế. Thu Chưởng Tôn bất tỉnh (còn nửa hồn) vào không gian trữ vật, tuyên bố để cho người điên năm đó thức tỉnh rồi quyết định sống chết.","anchor":"Hồn của ngươi vẫn còn một nửa, ta không giết ngươi, ngươi là nô bộc của người điên năm đó"},{"importance":"normal","mucCt":"ky","chuong":"@c1680","tieuDe":"Nhận truyền thừa trái tim Diệp Mịch","text":"Thương cảm cho Chưởng Tôn — kẻ một đời kiêu hùng nhưng vận mệnh bi thảm, luân hồi nhân quả giống việc năm xưa vây giết Phong Tôn. Cảm tạ đồng minh và kết thúc nhân quả: nói với Lam Mộng Đạo Tôn ân nghĩa đã xong, tuyên bố với Đường San hai bên cân bằng, kết thúc ân oán với Vân Dật Phong. Lao xuống tầng cuối vùng đất cổ mộ qua hố sâu lộ ra sau khi ngọn núi Ác quỷ Dĩ Ti sụp đổ. Chịu đựng cộng hưởng trái tim Diệp Mịch khiến mạch máu căng phồng, ho ra máu. Ngồi khoanh chân trên trái tim khổng lồ, dùng thần niệm thuyết phục Diệp Mịch. Hứa ba điều: hoàn thành di nguyện Diệp Mịch, chiếu cố thân nhân ở Tiên Cương đại lục, tìm mắt trái về cho Diệp Mịch. Trái tim chấp nhận đập cùng nhịp, Đạo Cổ khí tức mênh mông tràn vào cơ thể, tám tinh điểm trên mi tâm xoay tròn, xuất hiện dấu hiệu hình thành tinh điểm thứ chín.","anchor":"Tám tinh điểm trên mi tâm của hắn chợt xoay tròn, mơ hồ xuất hiện dấu hiệu hình thành tinh điểm thứ chín!"},{"importance":"major","mucCt":"ky","chuong":"@c1681","tieuDe":"Minh ngộ thần thông nhịp tim","text":"Tại tầng cuối cùng vùng đất cổ mộ, hấp thu khí tức Đạo cổ từ trái tim Diệp Mịch, nhịp tim dần hòa với nhịp đập trái tim Diệp Mịch. Tinh điểm trên mi tâm trong hai mắt có dấu hiệu hình thành tinh điểm thứ chín. Minh ngộ nguyên lý dùng nhịp tim bản thân dẫn động nhịp tim đối phương, có thể khiến vỡ tim hoặc khống chế. Tính toán sáng tạo thần thông mới kết hợp lôi bổn nguyên, Mộng Đạo và hư hỏa. Cuối chương, tiếng tim đập và khí tức Đạo cổ tràn ra khỏi tầng cuối cùng, lan tới chiến trường tầng thứ hai.","anchor":"Tinh điểm trên mi tâm trong hai mắt điên cuồng xoay chuyển, không ngờ đều có dấu hiệu hình thành tinh điểm thứ chín"},{"chuong":"@c1682","importance":"major","mucCt":"ky","tieuDe":"Xuất hiện với ngân mục, thi triển Tâm Động Lôi Âm đấu Chiến lão quỷ","text":"Bước ra từ tầng cuối vùng đất cổ mộ sau khi nhận trọn truyền thừa Diệp Mịch, diện mạo biến đổi hoàn toàn: da phủ ký hiệu, đôi mắt màu bạc (ngân mục), mi tâm chín tinh điểm, mắt phải chín ma tinh, mắt trái tám yêu tinh đang chảy máu. Dùng ngân mục nhìn qua chỗ Huyền La Đại Thiên Tôn, mơ hồ thấy được điều người khác không thấy. Dùng thần thông Tâm Động Lôi Âm — tiếng tim đập ầm ầm khuếch tán thành âm thanh duy nhất thiên địa — đặt bàn tay đen kịt lên ngực Huyền Vũ chiến tướng đánh bay. Chủ động bảo Lam Mộng và lão Mã nghỉ ngơi, tự mình đảm đương trận chiến với Chiến lão quỷ đã dung hợp hồn phách Thất Thải Tiên Tôn. Tiếng tim đập dẫn động trái tim Chiến lão quỷ khiến hắn đau đớn phải áp chế.","anchor":"trái tim trong thân thể Vương Lâm ầm ầm vang lên, âm thanh kinh thiên động địa"},{"chuong":"@c1683","importance":"major","mucCt":"ky","tieuDe":"Lần đầu thi triển Đạo Cổ Vô Tiên","text":"Chuyển hóa toàn bộ tu vi thành khí tức Đạo cổ, tuyên bố tiếp nối trận chiến năm xưa giữa Diệp Mịch và Thất Thải Tiên Tôn. Dùng Tâm Động Lôi Âm khống chế nhịp tim Chiến lão quỷ suýt khiến tim hắn tan vỡ. Ngưng tụ chín tinh điểm Cổ Thần và mười bảy tinh điểm yêu ma vào quyền Đạo cổ đấu bảy chữ Chiến của Chiến lão quỷ, sáu chữ vỡ nhưng chữ cuối nổ khiến hắn khạc máu. Lần lượt thi triển ba bước: Thần Chấn binh tu liệt vị (Cổ Thần cửu tinh xoay thiên địa), Yêu Thuật phong hỏa thành sơn (Cổ Yêu bát tinh tạo lốc phong hỏa), Ma Đạo sinh tử nghịch động (Cổ Ma cửu tinh biến sức sống thành tử khí). Cuối cùng dung hợp tam tộc thành tuyệt chiêu Đạo Cổ Vô Tiên, triệu ra hư ảnh đầu lâu Cổ Tổ khổng lồ cao ngang thiên địa, hóa đá toàn bộ cổ mộ từ tầng một đến tầng cuối cùng Chiến lão quỷ và hai hồn Thất Thải Tiên Tôn. Nhận ra dung nhan đầu lâu quen thuộc từ huyết mạch, chính là Cổ Tổ. Dù dốc sức, Chiến lão quỷ vẫn phá hóa đá thoát thân. Kiệt sức khạc máu, tự nhận vẫn không phải đối thủ do thiếu mắt trái khiến Cổ Yêu chưa đạt cửu tinh. Quyết định đi tìm đệ ngũ hoa, mở cửa lớn động phủ, mượn sức mạnh Tiên Cương phong ấn Chiến lão quỷ.","anchor":"Cố gắng thi triển Đạo cổ vô tiên, hay là để cho hắn chạy thoát"},{"importance":"normal","mucCt":"ky","chuong":"@c1684","tieuDe":"Tiến vào thế giới ký ức đệ ngũ hoa","text":"Vương Lâm bước vào thử thách cuối cùng ở trung tâm động phủ, tiến vào đệ ngũ hoa của Ngũ Hoa Bát Môn trận. Hồn thứ ba (ký ức cả đời Thất Thải Tiên Tôn) tạo thành thế giới bảy màu, Vương Lâm hóa thành hình dạng Tô Đạo (Thất Thải Tiên Tôn thời trẻ), mặc đạo bào xanh có lực phòng hộ chống đòn toàn lực tu sĩ vấn Đỉnh, đeo ngọc bội trong suốt. Đã ở trong thế giới này hơn hai tháng mà chưa tìm được chân môn. Nhận ra hình dạng hiện tại giống pho tượng bảy màu lấy từ Tham Lang, chỉ thiếu vẻ tang thương. Cảm giác bản thân chưa hoàn toàn dung hợp với hồn thứ ba ở mức độ sâu. Khi thanh niên đồng môn phụng mệnh đại sư huynh tới bắt nạt, Vương Lâm dùng ánh mắt uy áp khiến đối phương hồn bay phách tán, rồi túm cổ nhấc lên cảnh cáo, không để lịch sử bắt nạt lặp lại. Dẫn thanh niên lên đỉnh núi tới đại điện, nơi gần trăm tu sĩ tụ tập cung nghênh sư tôn xuất quan, trời đổ mưa lớn ngay khi hắn bước vào sân.","anchor":"Không được trêu chọc ta, không một lần nào nữa, rõ chưa?"},{"chuong":"@c1685","importance":"major","tieuDe":"Nghịch chuyển ký ức, ngộ phương pháp phá bát môn","text":"Trong thế giới ký ức hồn thứ ba (danh phận Tô Đạo tại Đông Lâm Tông), được sư tôn gọi vào đại điện cùng Chu Lập để tranh tư cách học Vân Đạo Thiên Thuật. Quyết định nghịch chuyển ký ức thay vì thuận theo (vì nếu dung hợp hoàn toàn, Tạ Thanh sẽ vĩnh viễn không thức tỉnh). Bùng phát sát khí đáp trả ánh mắt uy hiếp của Chu Lập, chỉ tám nhịp thở hoàn thành vận chuyển vân khí, mây mù hóa rồng nuốt sạch sương mù Chu Lập khiến hắn phun máu. Được sư tôn chọn làm đệ tử học Vân Đạo Thiên Thuật — đảo ngược hoàn toàn lịch sử gốc. Khi ký ức bị thay đổi, thiên địa vặn vẹo, tám luồng khí tức bát môn bốc lên. Ngộ ra phương pháp cốt lõi: thay đổi ký ức tạo mâu thuẫn hỗn loạn, từ đó cảm nhận vị trí bát môn và tìm cánh cửa thực sự.","anchor":"Mâu thuẫn và hỗn loạn càng lớn thì ta lại càng cảm nhận được rõ ràng, thậm chí có thể từ đó tìm ra được cánh cửa thực sự!","mucCt":"ky"},{"mucCt":"ky","text":"Trong thế giới đệ ngũ hoa, Vương Lâm hồi tưởng ký ức hồn thứ ba (Tô Đạo) về quá khứ tại Đông Lâm Tông. Bắt đầu tu luyện Vân Đạo Thiên Thuật do sư tôn Tô Đạo truyền thụ, hấp thu vân khí từ sông, cây cỏ, mây đen trên bình nguyên suốt hơn hai tháng. Mây mù cuối cùng hóa bảy con vân long chui vào thất khiếu, đồng tử biến thành mây mù, đạt tầng thứ chín chỉ kém đại viên mãn. Nhờ quá trình tu luyện không ngừng kích thích ký ức hồn thứ ba, tìm ra vị trí đệ nhất quan trong bát môn. Lao tới vùng rừng rậm, phát hiện đệ nhất quan không phải cây đại thụ mà chính là con mãng xà trăm trượng — trên lưng nó hiện cánh cửa biến ảo. Nắm cổ mãng xà, từng bước tiến về phía cánh cửa.","anchor":"Thời gian hai tháng đã tu luyện Vân Đạo Thiên Thuật này tới tầng thứ chín, chỉ còn kém một chút là đại viên mãn","bridge":true,"khoang":"@c1686"},{"mucCt":"ky","text":"Rời đám cây cối sau khi xác nhận mãng xà là bát môn nhưng không phải cửa thực, quyết định lợi dụng cuộc thi đấu Đông Lâm Tông để nghịch chuyển ký ức hồn thứ ba tìm cửa thật. Được sư tôn chọn làm một trong ba đệ tử dự thi cùng Chu Lập và Tần Mai. Tại quảng trường khai mạc, bình tĩnh trước uy áp của mấy trăm cường giả, thu hút hơn mười ánh mắt chú ý — hoàn toàn đảo ngược kịch bản ký ức cũ khi Tô Đạo chỉ run rẩy cúi đầu. Khi Tần Mai bắt chuyện, mỉm cười thong dong hào hiệp khiến nàng ngạc nhiên. Tiến vào khe Đông Lâm, xuất hiện ở bình nguyên cỏ dại đúng vị trí trong ký ức Thất Thải Tiên Tôn, tự nhủ sẽ thay đổi tất cả.","anchor":"Ta đã tới, tất cả sẽ thay đổi","bridge":true,"khoang":"@c1687"},{"importance":"normal","mucCt":"ky","chuong":"@c1688","tieuDe":"Phá hủy đệ ngũ hoa, bát môn hiển lộ","text":"Đóng vai Tô Đạo trong thế giới đệ ngũ hoa (ký ức hồn thứ ba Thất Thải), cướp toàn bộ ngọc bội lệnh bài của các đệ tử cửa thứ nhất tỷ thí Đông Lâm Tông. Đánh bại Côn Bằng khiến hắn vứt ngọc bội bỏ chạy, phá sập núi giết chết Chu Lập. Quét sạch ngọc bội rồi xé trời bước ra ngoài tuyên bố đứng đầu tỷ thí. Hành động nghịch chuyển ký ức khiến hồn thứ ba hỗn loạn rồi hưng phấn, thế giới đệ ngũ hoa sụp đổ hoàn toàn, khí tức bát môn hiển lộ toàn bộ như cột khí bốc lên chín tầng mây. Khi giết Chu Lập đã cảm nhận được vị trí tam môn trong bát môn. Đông Lâm Trì ở hậu sơn là thứ duy nhất không sụp đổ.","anchor":"Ta, Tô Đạo, là người đứng đầu trong cuộc tỷ thí này!"},{"importance":"normal","mucCt":"ky","chuong":"@c1689","tieuDe":"Nhập Đông Lâm Trì, tám bổn nguyên chân thân, mở đại môn","text":"Nhập Đông Lâm Trì trong thế giới ký ức đệ ngũ hoa, nước ao bổn nguyên khiến bảy đạo bổn nguyên (hỏa, lôi, sinh tử, nhân quả, chân giả, sát lục, cấm chế) đạt viên mãn và ngưng tụ thành bảy bổn nguyên chân thân hình dáng giống Vương Lâm. Thủy bổn nguyên (đạo thứ tám, đạt được tại Ngũ Hành Tinh) hấp thu toàn bộ nước ao còn lại mà đại thành, ngưng tụ chân thân thứ tám. Tu vi đột phá từ Không Linh hậu kỳ lên Không Linh đỉnh, chỉ cách Không Huyền một bước — cần bổn nguyên thứ chín để cửu cửu quy nhất. Tuy nhiên tu vi này là hư ảo trong ký ức, sẽ tiêu tán khi trở về thực tại, nhưng trải nghiệm và hiểu biết về Đông Lâm Trì là thật. Kêu gọi Tô Đạo (hồn thứ ba) giúp tìm cánh cửa thật, đổi lại hoàn thành tâm nguyện vào Đông Lâm Trì. Dùng Vân Đạo Thiên Thuật cùng tám bổn nguyên chân thân vượt qua Chiến lão quỷ, tới trước đại môn động phủ giới. Dồn toàn bộ Đạo Cổ lực và tám bổn nguyên chân thân đánh ra một chưởng, mở được khe hở trên đại môn khổng lồ, trở thành người đầu tiên mở được đại môn này sau phong bế. Khí tức thần chính Tiên Cương đại lục tràn vào.","anchor":"Tu vi Không Linh hậu kỳ của Vương Lâm ầm ầm tăng mạnh!"},{"chuong":"@c1690","importance":"major","mucCt":"ky","tieuDe":"Phong ấn lưỡng hồn Thất Thải, Chiến lão quỷ giải thoát","text":"Kích hoạt hai đạo phong ấn do Tạ Thanh để lại, chờ dung hợp khí tức Tiên Cương đại lục. Dùng tám bổn nguyên chân thân đánh chưởng, lần đầu tiên khiến Chiến lão quỷ cùng lưỡng hồn Thất Thải Tiên Tôn lui bước. Nương lực phản chấn cùng tám bổn nguyên đập cửa, mở rộng đại môn động phủ giới tới gần ba phần. Phóng hai đạo phong ấn phong ấn lưỡng hồn Thất Thải Tiên Tôn, cắt đứt liên hệ chúng với Chiến lão quỷ. Không ngăn cản Chiến lão quỷ lao vào đại môn trước khi chết, thốt lời Tạ Thanh vừa là đệ tử vừa là sư tôn của hắn.","anchor":"Đây là lần đầu tiên Vương Lâm đối mặt với Chiến lão quỷ có thể khiến hắn lui bước!"},{"importance":"normal","mucCt":"ky","chuong":"@c1691","tieuDe":"Đại môn mở — tiễn biệt và gọi Huyền La lộ diện","text":"Chứng kiến đại môn động phủ giới mở ra, kim môn hoàng kim nối tới Tiên Cương đại lục. Hồi tưởng hơn hai ngàn năm gian khổ, nhớ Lý Mộ Uyển và Tạ Thanh, hứa sẽ đánh thức Uyển Nhi và làm Tạ Thanh sống lại ở Tiên Cương. Tám bổn nguyên chân thân tiêu tán khi trở lại thân xác, Thủy bổn nguyên chỉ còn chút thành tựu, bảy bổn nguyên ẩn trong thân, trở về trạng thái trước biến hóa Đông Lâm Trì. Tuyên bố xóa bỏ ân oán cũ trong động phủ giới, ôm quyền tiễn biệt tất cả tu sĩ muốn rời đi. Phóng thích Bạch Hổ chiến tướng và tu sĩ trung niên Ngũ Hành Tinh bị giam. Tiễn đoàn Ngũ Hành Tinh, ba chiến tướng Huyền Vũ, Chu Tước, Bạch Hổ, và Đường San qua kim môn. Sau khi mọi người rời đi, ôm quyền vái về phía hư vô, gọi đích danh Huyền La Đại Thiên Tôn lộ diện, nói rõ kẻ này đã bám theo hắn từ Ngũ Hành Tinh tới Tiên Giới rồi tới trung tâm động phủ.","anchor":"Huyền La Đại Thiên Tôn tiền bối, người theo ta một đoạn đường từ Ngũ Hành Tinh tới Tiên Giới, lại tới cả trung tâm của động phủ này"},{"chuong":"@c1692","importance":"major","mucCt":"ky","tieuDe":"Huyền La mời làm đệ tử, quyết không bỏ Uyển Nhi","text":"Huyền La Đại Thiên Tôn hiện thân giao tiếp trực diện, tự suy đoán đúng cách Vương Lâm biết thân phận mình (thu thần thức tu sĩ Ngũ Hành Tinh, Mục Ngư cảm nhận khí tức). Huyền La tiết lộ thân phận: một trong Cửu Dương, Đại Thiên Tôn của Đạo Cổ nhất mạch tại Tiên Cương đại lục. Huyền La xác định mời Vương Lâm làm đệ tử duy nhất, đặc biệt hài lòng vì hắn chưa từng xin giúp đỡ. Vương Lâm trầm tư chưa đồng ý vì lo cho Uyển Nhi và bằng hữu. Huyền La giải thích quy tắc Tiên Cương đại lục: sinh linh không có huyết mạch sẽ bị hồn phi phách tán, tiếp dẫn giả là lừa gạt. Huyền La tiết lộ hồn Uyển Nhi không hoàn chỉnh, một phần đã biến mất không dấu vết. Vương Lâm chảy huyết lệ tuyệt vọng, tuyên bố thà ở lại động phủ giới vĩnh viễn với Uyển Nhi chứ không một mình tới Tiên Cương. Huyền La đề xuất Thiên Dương luân hồi chuyển thế thuật cho bằng hữu, riêng Uyển Nhi cho năm phần mười cơ hội mang trực tiếp đi, thất bại thì cả hai tử vong. Vương Lâm ghi nhận mang ân Huyền La.","anchor":"ta sở dĩ muốn mở cánh cửa động phủ này, muốn đi tới Tiên Cương đại lục toàn bộ là vì nàng"}],"nhanMach":[{"ten":"Duẫn Đông Thân","tag":"khac","quanHe":"Phó tông chủ Quy Nhất Tông, từ chối cho Vương Lâm vào gặp Nạp Đa","ghiChu":"@c1634"},{"ten":"Duẫn Đông Thân","tag":"doi-thu","quanHe":"Trưởng lão Quy Nhất tông, từng đối thoại với Vương Lâm trước khi hắn tiến vào Ngũ Hành đại trận","ghiChu":"@c1635"},{"ten":"Thủy Tướng","tag":"doi-thu","quanHe":"Ngũ tiên Thủy Tướng của Quy Nhất tông, đối thủ trong thủy trận","ghiChu":"Bị Vương Lâm đánh bại nhưng nhờ áo giáp hồi phục"},{"ten":"Vân Dật Phong","tag":"doi-thu","quanHe":"Đối thủ ngang sức","ghiChu":"Giao chiến ngang tay tại Ngũ Hành tinh, từng gặp trong thiên kiếp ở viễn cổ tiên vực"},{"ten":"Tạ Đông Minh","tag":"khac","quanHe":"Cha của Tạ Thanh trong kiếp luân hồi cuối cùng — Vương Lâm chứng kiến cảnh hắn sinh con"},{"ten":"Tạ Thanh","tag":"su-mon","quanHe":"Đệ tử, đồng thời là hồn thứ ba của Thất Thải Tiên Tôn","ghiChu":"Xác nhận tại @c1652"},{"ten":"Vân Na","tag":"dong-minh","quanHe":"Nữ Cổ Thần nhận Vương Lâm là chủ nhân mới của Đông Lâm tông, đề nghị dung hợp tâm thần huyết Diệp Mịch","gap":"@c1671"},{"ten":"Vân Dật Phong","tag":"dong-minh","quanHe":"Đối thủ chuyển thành thuộc hạ qua thệ huyết","ghiChu":"Thua trận đường đường chính chính, thề nghe lệnh Vương Lâm trong vùng trung tâm động phủ"},{"ten":"Tạ Thanh","tag":"ban-be","quanHe":"Tri kỷ, hồn phách ẩn trong thân Vương Lâm","ghiChu":"Vương Lâm từ chối dung hợp hoàn toàn hồn thứ ba để bảo vệ Tạ Thanh"},{"ten":"Chu Lập","tag":"doi-thu","quanHe":"Đại sư huynh trong ký ức Đông Lâm Tông, khinh thị Tô Đạo","ghiChu":"Bị Vương Lâm dùng sát khí chấn nhiếp, thua trong cuộc tranh tư cách học Vân Đạo Thiên Thuật"},{"ten":"Liên Đạo Phi","tag":"su-mon","quanHe":"Sư tôn trong ký ức Đông Lâm Tông","ghiChu":"Truyền tư cách học Vân Đạo Thiên Thuật cho Vương Lâm (thân phận Tô Đạo)"},{"ten":"Tần Mai","tag":"khac","quanHe":"Đồng môn trong ký ức hồn thứ ba, từng có tình ý với Tô Đạo","ghiChu":"@c1687"},{"ten":"Côn Bằng","tag":"doi-thu","quanHe":"Thiên tài Đông Lâm Tông trong ký ức, bị Vương Lâm đánh bại","ghiChu":"@c1688"},{"ten":"Huyền La Đại Thiên Tôn","tag":"doi-thu","quanHe":"Kẻ bí ẩn bám theo Vương Lâm suốt hành trình từ Ngũ Hành Tinh tới Tiên Giới, bị Vương Lâm gọi đích danh lộ diện","ghiChu":"@c1691"},{"ten":"Huyền La Đại Thiên Tôn","tag":"su-mon","quanHe":"Được mời làm đệ tử duy nhất","ghiChu":"Huyền La là Đại Thiên Tôn Đạo Cổ nhất mạch, một trong Cửu Dương. Vương Lâm mang ân."}],"tuViMoc":[{"chuong":"@c1640","canhGioi":"Thủy bổn nguyên (mầm mống — bổn nguyên thứ tám)","text":"Nhờ hấp thu Càn Khôn Nhất Tích, Vương Lâm có được mầm mống thủy bổn nguyên, là thực bổn nguyên thứ tám, cần dung hợp nhiều lần mới đại thành.","importance":"major"},{"chuong":"@c1680","canhGioi":"Đạo Cổ tám tinh điểm (sắp chín)","text":"Sau khi nhận truyền thừa trái tim Diệp Mịch, Đạo Cổ khí tức tràn vào cơ thể, tám tinh điểm trên mi tâm xoay tròn, xuất hiện dấu hiệu hình thành tinh điểm thứ chín.","importance":"minor"},{"chuong":"@c1682","canhGioi":"Ngân Mục (đệ nhất tượng cửu khúc tam tượng)","text":"Hai mắt biến thành ngân mục (mắt bạc) sau truyền thừa Diệp Mịch kết hợp hồn huyết cổ Tổ, đạt đệ nhất tượng trong cửu khúc tam tượng — lưỡng khúc ngân mục kim thân. Ngay Diệp Mịch cũng không có được ngân mục này. Thuộc hệ cổ Tộc, không phải tu vi chính.","importance":"major"},{"chuong":"@c1689","canhGioi":"Không Linh đỉnh (hư ảo)","text":"Tám đạo bổn nguyên ngưng tụ chân thân trong Đông Lâm Trì (thế giới ký ức), tu vi đột phá từ Không Linh hậu kỳ lên Không Linh đỉnh. Tu vi này là hư ảo, sẽ tiêu tán khi rời ký ức, nhưng trải nghiệm thật.","importance":"major"}]},"nguon":["@c1633","@c1634","@c1635","@c1636","@c1637","@c1638","@c1639","@c1640","@c1641","@c1642","@c1643","@c1644","@c1645","@c1646","@c1647","@c1648","@c1649","@c1650","@c1651","@c1652","@c1653","@c1654","@c1655","@c1656","@c1657","@c1658","@c1659","@c1660","@c1661","@c1662","@c1663","@c1664","@c1665","@c1666","@c1667","@c1668","@c1669","@c1670","@c1671","@c1672","@c1673","@c1674","@c1675","@c1676","@c1677","@c1678","@c1679","@c1680","@c1681","@c1682","@c1683","@c1684","@c1685","@c1686","@c1687","@c1688","@c1689","@c1690","@c1691","@c1692"],"canhGioiCaoNhat":"Huyền Kiếp","trangThai":"song","cn":"王林","gioiTinh":"nam","tinhCach":[]},{"id":"thanh-long","name":"Thanh Long","tabs":{"kinhLich":[{"chuong":"@c1633","importance":"normal","mucCt":"vua","tieuDe":"Liên thủ thất bại, kinh hãi nhận ra thiên đạo","text":"Tấn công Vương Lâm bằng hư ảnh Thanh Long vạn trượng nhưng bị Khai Thiên Phủ chém tan. Liên thủ cùng ba chiến tướng khác vẫn thất bại. Gầm lên đe dọa sẽ giết sạch tiên giới của Vương Lâm. Run rẩy nhận ra sương mù thiên đạo — thứ năm xưa đã cắn nuốt Liên Đạo Phi.","anchor":"Thiên đạo! Đây là thiên đạo!"},{"importance":"bridge","mucCt":"gon","chuong":"@c1667","tieuDe":"Bị nhốt trong Phần Giới Cổ Tán","text":"Cảm ứng ngọc giản Tử Hà vỡ, tìm tới tu chân tinh, tiến vào tinh cầu và bị Phần Giới Cổ Tán nhốt, sắc mặt đại biến khi tán thu sáu thành.","anchor":"ngay cả đám người tam đại chiến tướng cũng đồng loạt sắc mặt đại biến"},{"importance":"bridge","mucCt":"vua","chuong":"@c1668","tieuDe":"Kiêng kị Vương Lâm","text":"Từ biển lửa xông ra, nhìn cảnh bảy màu và Chiến lão quỷ chật vật, ánh mắt lộ vẻ kiêng kị chưa từng có đối với Vương Lâm.","anchor":"Thanh Long chiến tướng hít sâu ánh mắt nhìn về phía Vương Lâm lộ ra một vẻ kiêng kị chưa từng có"},{"chuong":"@c1670","importance":"normal","mucCt":"gon","tieuDe":"Tử vong trong vụ nổ hủy diệt","text":"Ở gần trung tâm vụ nổ chín mặt trời va tiễn thứ ba, bị sức mạnh hủy diệt chạm phải, toàn thân tan vỡ, trực tiếp tử vong.","anchor":"Thanh Long chiến tướng ở hơi gần một chút liền bị sức mạnh này chạm phải, lập tức toàn thân ầm ầm tan vỡ, trực tiếp tử vong"}],"nhanMach":[],"tuViMoc":[]},"nguon":["@c1633","@c1667","@c1668","@c1670"],"trangThai":"tu-vong"},{"id":"huyen-vu","name":"Huyền Vũ","tabs":{"kinhLich":[{"chuong":"@c1633","importance":"normal","mucCt":"vua","tieuDe":"Cảm nhận thiên đạo, coi Vương Lâm là chúa tể kinh khủng nhất","text":"Liên thủ tấn công Vương Lâm, triệu hồi hư ảnh Huyền Vũ tràn ngập sóng biển nhưng thất bại. Cảm nhận lực thôn phệ thiên đạo bao phủ toàn thân, trong mắt hắn Vương Lâm đã hóa thành chúa tể kinh khủng nhất.","anchor":"Trong mắt hắn Vương Lâm đã hóa thân thành chúa tể kinh khủng nhất!"},{"importance":"bridge","mucCt":"gon","chuong":"@c1667","tieuDe":"Bị nhốt trong Phần Giới Cổ Tán","text":"Cảm ứng ngọc giản Tử Hà vỡ, tìm tới tu chân tinh, tiến vào tinh cầu và bị Phần Giới Cổ Tán nhốt, sắc mặt đại biến khi tán thu sáu thành.","anchor":"ngay cả đám người tam đại chiến tướng cũng đồng loạt sắc mặt đại biến"},{"importance":"bridge","mucCt":"vua","chuong":"@c1668","tieuDe":"Sợ hãi hối hận","text":"Sắc mặt tái nhợt, nghĩ tới thiên đạo của Vương Lâm nổi lên sợ hãi, hối hận đáng lẽ không nên tới nơi này.","anchor":"hắn nghĩ tới thiên đạo của Vương Lâm, trong lòng nổi lên sự sợ hãi, thậm chí hắn còn có chút hối hận, đáng lẽ mình không nên tới nơi này!"},{"importance":"bridge","mucCt":"gon","chuong":"@c1669","tieuDe":"Bị gợn sóng cung Lý Quảng đánh trúng","text":"Cùng hai chiến tướng khác bị gợn sóng cung Lý Quảng đánh trúng, đồng loạt phun máu, hoảng sợ lui ra tinh không.","anchor":"tam đại chiến tướng kia ánh mắt lộ ra vẻ hoảng sợ, bọn họ cũng đã từng chứng kiến uy lực của mũi tên này"},{"chuong":"@c1670","importance":"bridge","mucCt":"gon","tieuDe":"","text":"Hoảng sợ điên cuồng bỏ chạy khi vụ nổ hủy diệt lan ra, khiếp sợ khi thấy Liên Đạo Phi xuất hiện.","anchor":"hai người Huyền Vũ cùng với Chu Tước đang bỏ chạy kia cũng xoay mạnh người"},{"importance":"bridge","mucCt":"gon","chuong":"@c1681","text":"Giao chiến với tu sĩ trung niên từ Ngũ Hành tinh, khó phân thắng bại.","anchor":"Huyền Vũ chiến tướng. Chu Tước chiến tướng bất ngờ cũng ở trong đó"},{"chuong":"@c1682","importance":"normal","mucCt":"vua","tieuDe":"Bị Tâm Động Lôi Âm dẫn động trái tim, bị Vương Lâm đánh bay","text":"Theo lệnh Chiến lão quỷ lao vào tầng cuối giết Vương Lâm, nhanh hơn Chu Tước ba trượng. Khi tới gần bị tiếng tim đập ầm ầm dẫn động trái tim đau đớn như bị bóp nát, rồi bị bàn tay đen kịt của Vương Lâm đặt lên ngực đánh bay, phun máu.","anchor":"đôi tai hắn ầm vang, trái tim đau đớn như bị một bàn tay bóp lấy"},{"importance":"bridge","mucCt":"gon","chuong":"@c1691","tieuDe":"Tạ lỗi Vương Lâm — tặng ngọc giản rồi rời đi","text":"Hồi tưởng Thất Đạo Tông và Thất Thải Tiên Tôn, tạ lỗi với Vương Lâm, đưa một ngọc giản rồi cùng Chu Tước và Bạch Hổ bay vào kim môn rời đi.","anchor":"Vương đạo hữu, chuyện trước kia. ôi"}],"nhanMach":[],"tuViMoc":[]},"nguon":["@c1633","@c1667","@c1668","@c1669","@c1670","@c1681","@c1682","@c1691"],"trangThai":"song","aliases":["Huyền Vũ chiến tướng","Huyền Vũ"],"tinhCach":[],"gioiTinh":"nam"},{"id":"chu-tuoc","name":"Chu Tước","tabs":{"kinhLich":[{"chuong":"@c1633","importance":"bridge","mucCt":"gon","text":"Liên thủ tấn công Vương Lâm bằng hư ảnh Chu Tước nhưng thất bại, đứng sững sợ hãi khi nhận ra thiên đạo.","anchor":"Thiên đạo! Đây là thiên đạo!"},{"importance":"bridge","mucCt":"gon","chuong":"@c1667","tieuDe":"Bị nhốt trong Phần Giới Cổ Tán","text":"Cảm ứng ngọc giản Tử Hà vỡ, tìm tới tu chân tinh, tiến vào tinh cầu và bị Phần Giới Cổ Tán nhốt, sắc mặt đại biến khi tán thu sáu thành.","anchor":"ngay cả đám người tam đại chiến tướng cũng đồng loạt sắc mặt đại biến"},{"importance":"bridge","mucCt":"vua","chuong":"@c1668","tieuDe":"Khiếp sợ trước phục sát","text":"Tâm tư phức tạp nhất trong tam đại chiến tướng, rất khó đè nén sự khiếp sợ trong lòng trước cảnh tượng Vương Lâm bày bố phục sát.","anchor":"Chu Tước chiến tướng có tâm tư phức tạp nhất, lúc này nhìn cảnh tượng trước mắt rất khó đè nén sự khiếp sợ trong lòng"},{"chuong":"@c1670","importance":"bridge","mucCt":"gon","tieuDe":"","text":"Cùng Huyền Vũ điên cuồng bỏ chạy, ánh mắt khiếp sợ khi thấy Liên Đạo Phi.","anchor":"hai người Huyền Vũ cùng với Chu Tước đang bỏ chạy kia cũng xoay mạnh người"},{"importance":"bridge","mucCt":"gon","chuong":"@c1681","text":"Bất ngờ xuất hiện, cùng Huyền Vũ chiến tướng giao chiến hai tu sĩ trung niên Ngũ Hành tinh.","anchor":"Chu Tước chiến tướng bất ngờ cũng ở trong đó"},{"chuong":"@c1682","importance":"normal","mucCt":"ky","tieuDe":"Bị ác quỷ Dĩ Ti hút máu héo rũ","text":"Theo lệnh Chiến lão quỷ xâm nhập tầng cuối, cũng bị ảnh hưởng tiếng tim đập vội lui lại. Bị ác quỷ Dĩ Ti từ tầng cuối lao ra đụng trúng, ôm cổ cắn hút máu khiến thân thể nhanh chóng héo rũ, rồi bị đạp nện xuống đất.","anchor":"mang theo nụ cười nanh ác, cắn lên cổ Chu Tước chiến tướng"},{"importance":"bridge","mucCt":"gon","chuong":"@c1691","tieuDe":"Cùng Huyền Vũ rời động phủ giới","text":"Cùng Huyền Vũ trầm mặc hồi tưởng Thất Đạo Tông rồi bay vào kim môn rời đi.","anchor":"nhớ cảnh tượng tứ đại chiến tướng bọn họ và Thất Thải Tiên Tôn quen biết"}],"nhanMach":[],"tuViMoc":[]},"nguon":["@c1633","@c1667","@c1668","@c1670","@c1681","@c1682","@c1691"],"trangThai":"song","aliases":["Chu Tước chiến tướng","Chu Tước"],"tinhCach":[],"gioiTinh":"nam"},{"id":"bach-ho","name":"Bạch Hổ","tabs":{"kinhLich":[{"chuong":"@c1633","importance":"bridge","mucCt":"gon","text":"Liên thủ tấn công Vương Lâm bằng hư ảnh Bạch Hổ nhưng thất bại, đứng sững sợ hãi khi nhận ra thiên đạo.","anchor":"Thiên đạo! Đây là thiên đạo!"},{"importance":"normal","mucCt":"ky","chuong":"@c1661","tieuDe":"Thiết lập quy tắc tàn giới, đề nghị đánh cuộc","text":"Là người đầu tiên bước vào tàn giới này nên đã thiết lập toàn bộ quy tắc. Đang lợi dụng cuộc đại chiến trăm vạn quân trên tu chân tinh thứ ba để hấp thu sát khí. Xuất hiện dưới dạng hư ảo trên bầu trời, có sợi dây nối vô hình với viên đại tướng áo giáp trắng cưỡi bạch mã phía dưới. Tự tin chỉ có đạo nhân bảy màu hoặc Chiến lão quỷ mới thoát khỏi quy tắc. Chủ động đề nghị Vương Lâm đánh cuộc: bại thì mất hồn thứ ba, thắng thì Bạch Hổ lấy huyết mạch thề theo lời thề Tiên Cương đại lục cam tâm làm nô bộc vạn năm.","anchor":"Ngươi nếu thắng thì lão phu sẽ dùng lời thề của Tiên Cương đại lục, cam tâm nghe lệnh ngươi, làm nô bộc cho ngươi vạn năm!"},{"mucCt":"ky","text":"Bạch Hổ định ra quy tắc bàn cờ trên tu chân tinh thứ ba, tự tin lợi thế huyết mạch tiên nhân sẽ áp đảo. Khi Vương Lâm tiến vào và bộc lộ huyết mạch Đạo Cổ truyền thừa, Bạch Hổ chấn động vì không ngờ đối phương cũng có lực lượng huyết mạch. Thần thức biến thành tướng lãnh mặc bạch giáp cưỡi bạch mã, phái mười hắc giáp binh tấn công Vương Lâm nhưng đều bị giết sạch trong nửa nén hương. Buộc phải lui lại kéo giãn khoảng cách.","anchor":"Hắn không ngờ lại có lực lượng huyết mạch! Không thể nào.","bridge":true,"khoang":"@c1662"}],"nhanMach":[],"tuViMoc":[]},"nguon":["@c1633","@c1661","@c1662"]},{"id":"chien-lao-quy","name":"Chiến lão quỷ","tabs":{"kinhLich":[{"chuong":"@c1633","importance":"normal","mucCt":"ky","tieuDe":"Thất Thải Tiên Tôn chiếm quyền thân thể, kiêng kỵ thiên đạo","text":"Đứng xa quan sát, sững lại khi u Minh thú mở miệng phóng sương mù thiên đạo. Hồn phách Thất Thải Tiên Tôn trong thân gào thét rồi chiếm quyền kiểm soát thân thể, tỏa ra khí tức riêng. Thất Thải Tiên Tôn kiêng kỵ vì nơi này là động phủ giới — nắm thiên đạo nghĩa là nắm mọi thứ, nhưng nhận định thiên đạo cắn nuốt có cực hạn và tự tin có thủ đoạn chống đỡ. Hỏi Vương Lâm có tìm được hồn thứ ba chưa.","anchor":"Thứ ta định đoạt lấy không ngờ là thiên đạo"},{"importance":"normal","mucCt":"vua","chuong":"@c1649","tieuDe":"Nhận định hồn thứ ba ở La Thiên","text":"Đi theo phía sau tứ đại chiến tướng, bảo trì cân bằng. Nhận định hồn thứ ba có lẽ đang ở La Thiên, nơi hắn ở lâu nhất, không rõ hồn thứ ba là người hay thú.","anchor":"Xem ra có lẽ hồn thứ ba đang ở La Thiên rồi. Thời gian ta ở La Thiên là dài nhất"},{"importance":"normal","mucCt":"vua","chuong":"@c1651","tieuDe":"Hé lộ tiên duyên với hồn thứ hai Thất Thải Tiên Tôn","text":"Được hé lộ tiên duyên: khi độ huyền kiếp thất bại, toàn thân thối rữa, nguyên thần tan nát, rơi lên tu chân tinh, gặp con mãnh thú có đôi mắt kỳ dị — chính là hồn thứ hai của Thất Thải Tiên Tôn luân hồi.","anchor":"Hắn độ huyền kiếp thất bại, toàn thân thối rữa, nguyên thần tan nát"},{"importance":"bridge","mucCt":"gon","chuong":"@c1653","text":"Đi phía sau tứ đại chiến tướng trong La Thiên Tinh Vực, đôi mắt bừng sáng, nắm rõ thần sắc Vụ thú.","anchor":"Chiến lão quỷ đi phía sau tứ đại chiến tướng, lúc này đôi mắt bừng sáng"},{"importance":"normal","mucCt":"ky","chuong":"@c1655","tieuDe":"Lộ hư ảnh tam hồn Thất Thải Tiên Tôn","text":"Tốc độ nhanh hơn tứ đại chiến tướng, vượt qua bọn họ lao về phía trung tâm động phủ. Thần sắc âm trầm ẩn sợ hãi, biết nếu đạo nhân bảy màu tìm được hồn thứ ba trước thì hắn sẽ bị cắn nuốt tử vong. Bên ngoài thân hắn bất ngờ hiện ra hư ảnh khổng lồ — một trong tam hồn của Thất Thải Tiên Tôn: sương mù làm áo choàng, đôi mắt âm u, tóc bạc phất phơ, che phủ cả mảng tinh không. Quyết nếu đạo nhân bảy màu đạt được hồn thứ ba thì sẽ thừa lúc đối phương tiêu hóa mà liều chết phản kích.","anchor":"Hư ảnh bên ngoài thân thể Chiến lão quỷ chính là một trong tam hồn của Thất Thải Tiên Tôn"},{"mucCt":"vua","text":"Xuất hiện trong tinh không trước đại môn, tóc bạc trắng, hư ảnh áo choàng bao phủ, thở phào vì hồn thứ ba ở Vương Lâm chứ không phải đạo nhân bảy màu. Bị cơn lốc từ đại môn đẩy lui, truyền âm chiêu dụ Vương Lâm: cam đoan an toàn cho tiên giới, hứa mở cánh cửa thông Tiên Cương đại lục, chỉ cần giao hồn thứ ba.","anchor":"ngươi đưa hồn thứ ba cho ta, lão phu cam đoan ngươi và cả tiên giới an toàn","bridge":true,"khoang":"@c1656"},{"mucCt":"vua","text":"Hư ảnh trên người nhìn chằm chằm bóng lưng Vương Lâm biến mất, hàn quang lóe lên. Tuyệt đối không cho phép đạo nhân bảy màu đoạt được hồn thứ ba, theo sát ngay sau tiến vào đại môn.","anchor":"Hắn tuyệt đối không cho phép đạo nhân bảy màu đoạt được hồn thứ ba","bridge":true,"khoang":"@c1657"},{"chuong":"@c1658","importance":"bridge","mucCt":"gon","text":"Theo sau đạo nhân bảy màu dung nhập vào đại đỉnh, khuôn mặt hiện trên sườn đỉnh trông dữ tợn.","anchor":"Sau đó Chiến lão quỷ cũng cất bước, dung nhập vào trong đại đỉnh"},{"chuong":"@c1665","importance":"bridge","mucCt":"gon","text":"Xuất hiện nửa ngày sau tại vị trí dòng xoáy biến mất, thân thể không chút khí tức giống người chết, truy kích theo hướng sai rồi rời đi, bị kế Vương Lâm đánh lừa hoàn toàn.","anchor":"Chiến lão quỷ xuất hiện ở nơi mà dòng xoáy biến mất, thân thể không chút khí tức, giống hệt người chết"},{"mucCt":"vua","text":"Đang theo dõi một đám tu sĩ, khi ngọc giản vỡ liền dừng lại, sắc mặt âm trầm sát khí tỏa ra, quay đầu tới tu chân tinh. Không thể cưỡng lại hồn thứ ba, gần như đồng thời với đạo nhân bảy màu tiến vào tinh cầu, bị Phần Giới Cổ Tán nhốt bên trong.","anchor":"Chiến lão quỷ kia cũng khó có thể nhịn được, gần như cùng với đạo nhân bảy màu đồng thời tiến vào tinh cầu này","bridge":true,"khoang":"@c1667"},{"mucCt":"vua","text":"Thoát biển lửa sau đạo nhân bảy màu, ánh mắt tham lam lao tới hồn thứ ba của Vương Lâm. Bị đệ tứ phục Quỷ Kiếm Huyết Phàm nuốt lấy, lập tức mê man khoanh chân ngồi không cử động.","anchor":"Chiến lão quỷ kia thân thể đột nhiên dừng lại, trong mắt lập tức hiện lên vẻ mê man","bridge":true,"khoang":"@c1668"},{"chuong":"@c1670","importance":"bridge","mucCt":"vua","tieuDe":"Quan sát từ sương mù mặt quỷ","text":"Ở trong sương mù mặt quỷ, mở mắt quan sát toàn bộ diễn biến nhưng không ra tay, không rõ ý đồ.","anchor":"Chiến lão quỷ đang bị vây trong đám sương mù mặt quỷ đã sớm mở hai mắt"},{"mucCt":"vua","text":"Bước ra khỏi sương mù mặt quỷ, do dự giữa đuổi giết Vương Lâm và truy kích đạo nhân bảy màu bị trọng thương. Vì e dè cung Lý Quảng và tính cẩn thận nên không đánh cuộc, cuối cùng chọn truy kích đạo nhân bảy màu để dung hồn.","anchor":"do tính cách cẩn thận nên hắn không muốn đánh cuộc","bridge":true,"khoang":"@c1671"},{"importance":"bridge","mucCt":"gon","chuong":"@c1674","text":"Khuôn mặt của hắn là một trong hai khuôn mặt cực rõ nét còn lại trên cây đinh bảy màu, tỏa hắc quang hấp dẫn hắc khí.","anchor":"Chiến lão quỷ.người này tính tình đa nghi, đặt bẫy hắn rất khó khăn"},{"importance":"normal","mucCt":"ky","chuong":"@c1680","tieuDe":"Tu vi gần đạt mức Thất Thải Tiên Tôn","text":"Đuổi tới vùng đất cổ mộ tầng hai, thần thức cực cường quét ngang. Thân phát ánh sáng bảy màu do đã cắn nuốt đạo nhân bảy màu, hai hồn chưa dung hợp nhưng mang lại lợi ích lớn, tu vi gần đạt mức Thất Thải Tiên Tôn năm xưa. Bị Lam Mộng Đạo Tôn, Đồ Ti, Vân Dật Phong và Đường San hợp lực chặn lại.","anchor":"Bản thân Chiến lão quỷ là hạng người tu vi cao thâm, sau khi dung hợp lại cắn nuốt đạo nhân bảy màu, lúc này đã đạt tới rất gần Thất Thải Tiên Tôn năm đó!"},{"importance":"normal","mucCt":"ky","chuong":"@c1681","tieuDe":"Tách hồn phách Thất Thải Tiên Tôn khỏi thân","text":"Giao chiến với Lam Mộng Đạo Tôn và lão già họ Mã ở tầng thứ hai. Muốn đột phá xuống tầng cuối cùng giết Vương Lâm đoạt hồn thứ ba nhưng bị ngăn cản. Phất tay khiến Vân Dật Phong suýt chết, dùng chữ Chiến trên mi tâm phá vỡ lam quang. Bị phong tỏa bởi tiếng đàn cổ cầm và đại thần thông ngũ hành, vỗ mi tâm tách hồn phách Thất Thải Tiên Tôn ra khỏi thân thể chống cự — hư ảnh mặc áo choàng, hai tay gập chữ thập va chạm hai bàn tay khổng lồ.","anchor":"Một chữ Chiến từ trên mi tâm Chiến lão quỷ nhanh chóng bành trướng ra ngoài"},{"chuong":"@c1682","importance":"normal","mucCt":"vua","tieuDe":"Khôi phục bá đạo, đối đầu Vương Lâm bị Tâm Động Lôi Âm áp chế","text":"Hồn phách Thất Thải Tiên Tôn phân ly khỏi thân, Chiến lão quỷ khôi phục bá đạo năm xưa, dùng hai chữ Chiến đánh trọng thương hai nam tử Ngũ Hành tinh. Ra lệnh Huyền Vũ và Chu Tước vào tầng cuối giết Vương Lâm. Sau đó dung hợp lại với hồn phách Thất Thải Tiên Tôn lao về phía Vương Lâm, nhưng bị thần thông tiếng tim đập dẫn động trái tim đau đớn, phải đặt tay lên ngực áp chế.","anchor":"Sắc mặt Chiến lão quỷ biến đổi, tay phải giơ lên đặt vào ngực, cố gắng áp chế không cho trái tim đập mạnh"},{"mucCt":"ky","text":"Giao chiến với Vương Lâm, bị Tâm Động Lôi Âm khống chế tim suýt vỡ, phải tự nhấn ngực chặn nhịp đập. Viết bảy chữ Chiến đón quyền Đạo cổ, sáu chữ vỡ nhưng chữ cuối nổ gây thương tích cho Vương Lâm. Bị Thần Chấn làm thiên địa xoay, sợ hãi cắn lưỡi phun máu nuốt quỷ Dĩ Ti. Bị Ma Đạo biến sức sống thành tử khí. Cuối cùng bị Đạo Cổ Vô Tiên hóa đá cùng hai hồn Thất Thải Tiên Tôn, nhưng phá vỡ đá thoát ra, hai hồn bị cưỡng ép dung nhập trở lại vào thân thể, phun máu hoảng sợ bỏ chạy. Nỗi sợ hãi giống như khi nhìn thấy cung Lý Quảng.","anchor":"Hắn sợ, cũng giống như lúc nhìn thấy cây cung Lý Quảng của Vương Lâm, sự sợ hãi tràn ngập tâm thần","bridge":true,"khoang":"@c1683"},{"importance":"bridge","mucCt":"gon","chuong":"@c1689","text":"Cố phá hạn chế xâm nhập thế giới đệ ngũ hoa, khi thế giới ký ức sụp đổ liền lao tới nhưng không đuổi kịp Vương Lâm.","anchor":"Chiến lão quỷ giống như đang nối giận, nhanh chóng phóng tới"},{"chuong":"@c1690","importance":"major","mucCt":"ky","tieuDe":"Giải thoát khỏi Thất Thải và cái chết","text":"Cảm nhận nguy cơ sinh tử từ phong ấn dung hợp khí tức Tiên Cương, uy hiếp Vương Lâm giao hồn thứ ba. Tấn công bằng chữ 'chiến' kim sắc cùng hư ảnh Thất Thải Tiên Tôn nhưng bị tám bổn nguyên chân thân Vương Lâm đẩy lui. Bỏ chạy nhưng không tránh được hai đạo phong ấn — lưỡng hồn Thất Thải trong thân bị phong ấn, cắt đứt liên hệ. Sau khi mất lưỡng hồn, minh mẫn trở lại, thú nhận giấc mộng cả đời là mở đại môn động phủ, năm đó độ Huyền Kiếp thất bại rồi bị hồn phách Thất Thải dung hợp, lẽ ra đã chết từ lâu. Cảm ơn Vương Lâm, thân thể tiêu tán, nửa còn lại hóa cầu vồng lao vào đại môn, tan thành mây khói — chết.","anchor":"Giấc mộng cả đời ta chính là muốn mở đại môn của động phủ này."}],"nhanMach":[],"tuViMoc":[]},"nguon":["@c1633","@c1649","@c1651","@c1653","@c1655","@c1656","@c1657","@c1658","@c1665","@c1667","@c1668","@c1670","@c1671","@c1674","@c1680","@c1681","@c1682","@c1683","@c1689","@c1690"],"aliases":["Chiến Không Liệt","Lão quái vật"],"trangThai":"song","gioiTinh":"nam","canhGioiCaoNhat":"Gần đạt mức Thất Thải Tiên Tôn năm xưa","tinhCach":[]},{"id":"that-thai-tien-ton","name":"Thất Thải Tiên Tôn","tabs":{"kinhLich":[{"chuong":"@c1633","importance":"normal","mucCt":"vua","tieuDe":"Hiện thân qua Chiến lão quỷ, nhận định thiên đạo có cực hạn","text":"Gào thét trong thân Chiến lão quỷ rồi chiếm quyền kiểm soát thân thể, tỏa khí tức riêng. Nhận định nắm thiên đạo trong động phủ giới chẳng khác nắm mọi thứ, nhưng thiên đạo cắn nuốt có cực hạn — Liên Đạo Phi từng tự bạo phân chia thoát được. Hỏi Vương Lâm có tìm được hồn thứ ba chưa, giọng khổ sở thê lương.","anchor":"Nắm trong tay thiên đạo chẳng khác nào nắm tất cả mọi thứ trong tay"},{"chuong":"@c1634","importance":"bridge","mucCt":"gon","text":"Được nhắc là chủ nhân động phủ giới Côn Hư tinh vực, người duy nhất được lão già hắc bào Quy Nhất Tông coi trọng.","anchor":"Cho dù hắn là Vương Lâm thì đã sao"},{"chuong":"@c1650","importance":"normal","mucCt":"vua","tieuDe":"Bị Liên Đạo Phi oanh kích vỡ nát, ba hồn bảy phách tán ra","text":"Trong huyễn cảnh tầng hai, bị Liên Đạo Phi oanh kích thân thể vỡ nát hoàn toàn, nguyên thần và hồn phách hóa thành ba hồn bảy phách tán ra bốn phương tám hướng. Bảy phách bảy màu lần lượt tiến vào luân hồi, bốn phách đầu được xác nhận danh tính: đỏ đậm (sát) là Thanh Thủy, xanh (tu vi) là Tư Đồ Nam, cam (chính khí) là Thanh Lâm, vàng (khí vận) là Tham Lang.","anchor":"Thân thể Thất Thải Tiên Tôn hoàn toàn vỡ nát, nguyên thần và hồn phách lần lượt thay đổi, hóa thành ba hồn bảy phách"},{"importance":"normal","mucCt":"ky","chuong":"@c1651","tieuDe":"Hé lộ chi tiết tam hồn thất phách","text":"Quá trình sụp đổ được hé lộ toàn diện. Phách thứ năm (lục) = bản năng, am hiểu thuật phân thân, hóa thành Tán Linh Thượng nhân. Phách thứ sáu (lam) = tình cảm yêu hận dành cho đạo lữ duy nhất Phàn San Mộng, hóa thành nữ tử — chính là Mộc Băng Mi, qua vô số luân hồi đều lần lượt ôn nhu rồi lạnh lùng. Phách thứ bảy (tím) = sự điên cuồng, phẫn nộ, không cam lòng trước khi sụp đổ, danh tính chưa rõ. Tam hồn: hồn thứ nhất lóe ánh sáng bảy màu bay ra giới ngoại hóa thành đạo nhân bảy màu, nhận được toàn bộ thần thông cả đời Tiên Tôn. Hồn thứ hai gào thét tiến vào luân hồi tại La Thiên Tinh Vực, hóa thành mãnh thú gặp Chiến lão quỷ — là tiên duyên của Chiến lão quỷ. Hồn thứ ba bay xa nhất, trải qua nhiều lần luân hồi xuyên tinh vực, cuối cùng tại Thanh Linh tinh luân hồi thành cá mấy trăm lần trong cùng con sông.","anchor":"Phách thứ sáu do tình hóa thành này ẩn chứa tâm tình phức tạp của Thất Thải Tiên Tôn"},{"importance":"bridge","mucCt":"gon","chuong":"@c1654","tieuDe":"Nhắc tới thân phận tam hồn thất phách","text":"Tạ Thanh tiết lộ hồn thứ ba của Thất Thải Tiên Tôn chính là bản thân mình; tứ đại chiến tướng là thủ hạ cũ đã đổi tâm tư; trong bảy phách còn hai phách chưa chia cách.","anchor":"Hồn thứ ba của Thất Thải Tiên Tôn là ta"},{"chuong":"@c1666","importance":"bridge","mucCt":"vua","text":"Được nhắc đến là nguồn trí nhớ của Vương Lâm (hồn thứ ba) về Mục Ngư. Năm xưa đã đem một con Mục Ngư nhỏ vào ba trăm tàn giới nuôi dưỡng nhưng vì thân thể phân chia nên thành chuyện tiếc nuối.","anchor":"Năm đó hắn đã đem một con Mục Ngư còn nhỏ vào trong ba trăm tàn giới"},{"mucCt":"gon","text":"Hồn phách bị Chiến lão quỷ vỗ mi tâm tách ra, hiện hư ảnh mặc áo choàng mặt bị che kín, duỗi hai tay gập chữ thập va chạm hai bàn tay khổng lồ kim sắc và hắc sắc.","anchor":"Đó là hồn phách của Thất Thải Tiên Tôn lúc này đã chia lìa với thân thể Chiến lão quỷ","bridge":true,"khoang":"@c1681"},{"chuong":"@c1682","importance":"normal","mucCt":"vua","tieuDe":"Hồn phách phân ly rồi dung hợp lại với Chiến lão quỷ","text":"Hồn phách phân ly khỏi thân Chiến lão quỷ, áo choàng bao phủ, song chưởng đánh tan thần thông cánh tay kim sắc của lão Mã và phong ấn cổ cầm của Lam Mộng. Sau đó được Chiến lão quỷ dung hợp trở lại thành một thể để đối đầu Vương Lâm.","anchor":"cánh tay kim sắc trên bầu trời lập tức sụp đổ"},{"mucCt":"vua","text":"Qua thế giới ký ức đệ ngũ hoa, lộ ra tên thật thời trẻ là Tô Đạo, thuộc một tông phái trên đại lục Tiên Cương. Thiên tư tuyệt hảo nhưng tính cách mềm yếu, sư tôn bế quan nên bị đồng môn đố kỵ bài xích, mười năm sau mới được sư tổ phát hiện tài năng. Dung mạo thời trẻ giống pho tượng bảy màu, chỉ thiếu vẻ tang thương.","anchor":"Thất Thải Tiên Tôn tính cách vốn rất mềm yếu, chứ không kiêu hùng như sau này","bridge":true,"khoang":"@c1684"},{"chuong":"@c1685","importance":"normal","tieuDe":"Ký ức bị Vương Lâm nghịch chuyển tại Đông Lâm Tông","text":"Ký ức hồn thứ ba được tái hiện: năm xưa tính cách nhu nhược, bị Chu Lập khinh thị và đàn áp, khi thi vận chuyển vân khí phải 20 nhịp thở vì sợ hãi, mây mù ít, bị hút hư ảnh, mất tư cách học Vân Đạo Thiên Thuật, chỉ nhận Thất Thải Tiên Thuật. Nay Vương Lâm nghịch chuyển toàn bộ kết cục này.","anchor":"Thất Thải Tiên Tôn năm đó tính cách nhu nhược, không nói những chuyện này ra","mucCt":"vua"},{"chuong":"@c1686","importance":"bridge","mucCt":"vua","text":"Ký ức được Vương Lâm hồi cố: năm xưa tại Đông Lâm Tông không đạt tư cách tu hành Vân Đạo Thiên Thuật, thi đấu thất bại, tâm lý vặn vẹo, sau được sư tổ giáo hóa tỉnh ngộ, bị khu trừ khỏi tông rồi tự sáng tạo Thất Đạo Tông, ngày thành đạo bắt giết Chu Lập.","anchor":"hóa thành sự tàn nhẫn và sát khí, cuối cùng tự sáng tạo ra Thất Đạo Tông, trở thành tông chủ Thất Thải Tiên Tôn"},{"chuong":"@c1687","importance":"bridge","mucCt":"gon","tieuDe":"Hồi ức bị Chu Lập ngược đãi tại đệ nhất quan","text":"Trong ký ức, năm xưa tại đệ nhất quan bị Chu Lập đoạt lệnh bài và ngược đãi tàn nhẫn, đây là nguyên nhân chính khiến tính cách biến đổi từ nhu nhược thành âm mưu thâm độc.","anchor":"Chính ở nơi này Tô Đạo cũng bị Chu Lập ngược đầi tàn nhẫn, tuy rằng không giết, nhưng loại thương tổn này cũng khiến Tô Đạo cả đời khó quên"},{"importance":"bridge","mucCt":"gon","chuong":"@c1688","tieuDe":"","text":"Hồn thứ ba bị Vương Lâm nghịch chuyển ký ức trong đệ ngũ hoa, từ hỗn loạn chuyển sang hưng phấn, khiến thế giới ký ức sụp đổ hoàn toàn và khí tức bát môn hiển lộ.","anchor":"hồn thứ ba của Thất Thải trong sự hỗn loạn này đang trở nên hưng phấn"},{"mucCt":"vua","text":"Được Vương Lâm gọi bằng tên Tô Đạo, kêu gọi giúp tìm cánh cửa thật đổi lại việc hoàn thành tâm nguyện vào Đông Lâm Trì. Lộ thêm quá khứ: từng được sư tổ Đông Lâm Tông bồi dưỡng nhưng chưa từng vào được Đông Lâm Trì, bị khu trừ khỏi tông môn ngay khi đạt tư cách. Sự cố chấp khiến Đông Lâm Trì là vật duy nhất còn ổn định khi thế giới ký ức sụp đổ.","anchor":"Tô Đạo, ngươi lưu lại Đông Lâm Trì chẳng lẽ là muốn ta hoàn thành tâm nguyện của ngươi","bridge":true,"khoang":"@c1689"}],"nhanMach":[{"ten":"Liên Đạo Phi","tag":"su-mon","quanHe":"Sư tôn tại Đông Lâm Tông","ghiChu":"Đối đãi tốt nhưng thường xuyên bế quan"},{"ten":"Chu Lập","tag":"doi-thu","quanHe":"Đại sư huynh tại Đông Lâm Tông","ghiChu":"Khinh thị Tô Đạo, uy hiếp trong cuộc thử thách vân khí"}],"tuViMoc":[]},"nguon":["@c1633","@c1634","@c1650","@c1651","@c1654","@c1666","@c1681","@c1684","@c1685","@c1686","@c1687","@c1688","@c1689","@c1690","@c1682"],"aliases":["Đạo nhân bảy màu","Thất Thải Tiên Tôn","Tô Đạo","Thất Thải đạo nhân"],"trangThai":"song","gioiTinh":"nam","cn":"七彩仙尊","tinhCach":[]},{"id":"dao-nhan-bay-mau","name":"Đạo nhân bảy màu","tabs":{"kinhLich":[{"chuong":"@c1633","importance":"normal","mucCt":"vua","tieuDe":"Tập hợp đủ Cửu huyền huyết mạch, chuẩn bị truy tìm hồn thứ ba","text":"Trong Côn Hư, cầm chín huyết cầu lớn đã tập hợp đủ Cửu huyền huyết mạch. Định dùng lực lượng này huyễn hóa luân hồi để tìm hồn thứ ba đã trốn vào luân hồi năm xưa, cho rằng hồn thứ ba ở tại Côn Hư.","anchor":"Cửu huyền huyết mạch rốt cục đã tập hợp được toàn bộ"},{"mucCt":"ky","text":"Đã lục soát gần hết Côn Hư trừ Ngũ Hành tinh mà không tìm ra đầu mối hồn thứ ba. Nhớ trong mộng huyễn ở khe Vân Hải tinh vực thấy hồn thứ ba bay hướng Côn Hư nhưng bị Vương Lâm cắt ngang ảo thuật nên không rõ hồn có dừng lại không. Tay cầm giọt máu trong suốt chứa huyết mạch chúng sinh, chỉ phát hồng quang khi gặp sinh linh ngoại lai luân hồi vào động phủ giới. Hận Vương Lâm càng sâu. Cất bước tới Triệu Hà tiếp tục tìm kiếm.","anchor":"Nếu vậy ta sẽ đi khắp tứ đại tinh vực. Ta không tin là hồn thứ ba này có thể rời khỏi động phủ giới","bridge":true,"khoang":"@c1649"},{"importance":"normal","mucCt":"vua","chuong":"@c1651","tieuDe":"Hé lộ là hồn thứ nhất Thất Thải Tiên Tôn","text":"Được xác nhận là hồn thứ nhất của Thất Thải Tiên Tôn. Vừa xuất hiện đã lóe ánh sáng bảy màu, bay ra giới ngoại, nhận được toàn bộ thần thông cả đời Tiên Tôn.","anchor":"phương hướng bay đi mơ hồ là giới ngoại của vạn cổ năm tháng sau đó"},{"importance":"bridge","mucCt":"gon","chuong":"@c1653","text":"Từ nơi tiếp giáp với Triệu Hà bước ra La Thiên Tinh Vực, không có đầu mối, bắt đầu tìm kiếm.","anchor":"Hắn không có chút đầu mối, lúc này bắt đầu tìm kiếm trong La Thiên"},{"mucCt":"vua","text":"Đang tìm hồn thứ ba trong La Thiên, sắc mặt đại biến khi cảm nhận trung tâm động phủ mở ra. Phẫn nộ ngập trời vì có người tìm được hồn thứ ba trước, điên cuồng lao tới nơi động phủ mở ra.","anchor":"Hồn thứ ba, có người tìm được hắn rồi! Trung tâm động phủ mở ra!","bridge":true,"khoang":"@c1655"},{"mucCt":"vua","text":"Bước ra từ sương mù, thở phào khi thấy hồn thứ ba không rơi vào tay Chiến lão quỷ. Bị cơn lốc từ đại môn đẩy lui không thể tiến tới. Đưa điều kiện hấp dẫn hơn Chiến lão quỷ: hứa cho thê tử Vương Lâm sống lại, không cướp thiên đạo, tặng toàn bộ động phủ giới, suốt đời không quay lại — chỉ cần hồn thứ ba.","anchor":"ngươi cho ta hồn thứ ba thì bổn tôn có thể cho thê tử của ngươi sống lại","bridge":true,"khoang":"@c1656"},{"mucCt":"vua","text":"Ánh mắt bừng sáng tham lam khi thấy hồn thứ ba, sát khí trở nên nồng đậm, quyết phải giết Vương Lâm cho bằng được. Bị lốc đẩy lùi khi cửa mở, nhưng là người đầu tiên lao vào đại môn sau khi lốc tiêu tán.","anchor":"Sát khí trong mắt đạo nhân bảy màu trở nên nồng đậm, trong khi lui lại đã quyết phải giết Vương Lâm cho bằng được","bridge":true,"khoang":"@c1657"},{"chuong":"@c1658","importance":"bridge","mucCt":"gon","text":"Là người đầu tiên tiến vào động phủ sau khi đại môn mở, bay thẳng vào đại đỉnh mà đống đổ nát không phản ứng, khuôn mặt hiện trên sườn đỉnh bị hắc khí vờn quanh.","anchor":"Đạo nhân bảy màu là người đầu tiên tiến vào"},{"mucCt":"vua","text":"Đã đi qua gần trăm giới truy tìm Vương Lâm không được, sắc mặt âm trầm lo lắng. Xé không gian di chuyển, cuối cùng cảm nhận được khí tức Vương Lâm ở không xa, vô cùng kích động tiếp tục truy tới.","anchor":"Gần lắm rồi, ta có thể cảm nhận được hắn. Hắn ở không xa phía trước!","bridge":true,"khoang":"@c1662"},{"mucCt":"ky","text":"Xé dòng xoáy xâm nhập tàn giới, cảm nhận khí tức Vương Lâm và tuyên bố tìm được hắn. Bị đường đao mượn lực cả giới chém trúng, triệu Thất Thải Đạo Liên biến thành nụ hoa phòng ngự nhưng vẫn bị đánh vỡ hai cánh hoa. Đây là lần thứ ba trong đời cảm nhận nguy cơ, hai trong ba lần đều do Vương Lâm gây ra. Phản công bằng năm cánh hoa còn lại kết hợp đích thân lao tới, nhảy vào dòng xoáy chụp một trảo nhưng hụt, thề đuổi giết Vương Lâm rồi nhảy vào dòng xoáy đuổi theo.","anchor":"Vương Lâm, bổn tôn tìm được ngươi rồi. Lần này ta xem ngươi làm sao mà trốn","bridge":true,"khoang":"@c1664"},{"chuong":"@c1665","importance":"bridge","mucCt":"vua","text":"Liên tục truy kích Vương Lâm xuyên các tàn giới, phát hiện kế phá tấm màn ngăn cách và âm thầm củng cố tấm màn bằng ánh sáng bảy màu định tương kế tựu kế, nhưng thực tế đã rơi vào kế thứ hai của Vương Lâm, bị ảo thuật tấm buồm mặt quỷ và thói quen tiềm thức đánh lừa, truy kích theo hướng sai.","anchor":"Chút tiểu xảo này mà cũng dám dùng trước mặt bổn Tôn"},{"mucCt":"vua","text":"Xuyên phá vách ngăn từng giới truy tìm Vương Lâm nhưng khí tức đã tiêu tan, nổi giận thề giết. Đến tu chân tinh nhận ra mãnh thú ngủ say dưới lòng đất nên do dự, nhưng không thể cưỡng lại hồn thứ ba, lao vào tinh cầu và bị Phần Giới Cổ Tán bao vây.","anchor":"Vương Lâm, nếu không giết được ngươi, lão phu thề không bỏ qua!","bridge":true,"khoang":"@c1667"},{"mucCt":"ky","text":"Là người đầu tiên xông ra khỏi biển lửa nhờ cũng được truyền thừa thuật Phần Giới Cổ Tán. Dùng đài sen bảy màu chống đỡ nhưng bị trường thương bảy màu của Vương Lâm phá tan hoàn toàn, năm cánh hoa còn lại lần lượt vỡ, đài sen nổ tung. Triệu hồi trường thương bảy màu y hệt đối chọi, hai thương va chạm kinh thiên động địa. Chịu Khai Thiên Phủ tự hủy bạo phát, tóc rũ rượi mắt điên cuồng tiếp tục lao tới. Bị U Minh Thú làm hoảng sợ khoảnh khắc, thốt lên gọi Thiên Đạo. Tỉnh lại thì lập tức bị vòng tròn máu nổ tung bao vây kết hợp Mục Ngư thức tỉnh.","anchor":"trên mặt bảy màu lộ ra một vẻ âm trầm, hắn gần như không cần nghĩ ngợi, giơ tay phải lên vung tay áo, một thanh trường thương bảy màu giống y hệt hiện ra","bridge":true,"khoang":"@c1668"},{"mucCt":"ky","text":"Thi triển thần thông Lục bạt sơn hề triệu hoán cánh tay bảy màu khổng lồ, túm lấy con Mục Ngư thứ nhất lôi khỏi lòng đất ném xa khiến nó trọng thương. Bị tám con Mục Ngư còn lại đồng loạt vây đánh, cùng lúc bị Vương Lâm bắn tiễn Lý Quảng trúng ngực, kịp túm đuôi tên nên thân thể không bị xuyên thủng. Dữ tợn rút mũi tên khỏi ngực, máu tươi tung tóe, sắc mặt tái nhợt.","anchor":"Ở chỗ ngực của hắn bị máu tươi nhuốm đỏ, mũi tên Lý Quảng hung hăng đâm vào ngực hắn","bridge":true,"khoang":"@c1669"},{"chuong":"@c1670","importance":"normal","mucCt":"ky","tieuDe":"Bị trọng thương, thi triển chín mặt trời, lần đầu bỏ chạy","text":"Bị tiễn thứ hai của Vương Lâm xuyên thủng ngực, trọng thương. Bộc phát toàn bộ tu vi thi triển thần thông mạnh nhất — chín mặt trời chói lọi. Chín mặt trời va chạm tiễn thứ ba nổ tung tạo sức mạnh hủy diệt, phá hủy ba trăm tàn giới, giết Thanh Long chiến tướng. Lộ mưu đồ thật: hắn muốn Chưởng Tôn đưa cung Lý Quảng cho Vương Lâm để dụ Liên Đạo Phi ra và để Vương Lâm kết oán rồi dùng cung đả thương Chiến lão quỷ, vì cả hắn lẫn Chiến lão quỷ đều không dùng được cung do không hoàn chỉnh. Khi thấy Liên Đạo Phi xuất hiện, lần đầu tiên trong trận đánh với Vương Lâm chọn cách bỏ chạy.","anchor":"Hắn vốn có ý định khiến cho Vương Lâm dùng cây cung này để dụ Liên Đạo Phi ra"},{"importance":"bridge","mucCt":"gon","chuong":"@c1674","text":"Khuôn mặt trên cây đinh bảy màu mơ hồ rồi hoàn toàn tiêu tán, Vương Lâm nhận định hắn không còn đáng sợ.","anchor":"Đạo nhân bảy màu đã không còn khiến ta sợ hãi"},{"chuong":"@c1683","importance":"bridge","mucCt":"gon","text":"Hồn bị Chiến lão quỷ phóng ra từ thất khiếu dùng làm lớp phòng hộ, bị Đạo Cổ Vô Tiên hóa đá rồi bị cưỡng ép dung nhập trở lại vào thân Chiến lão quỷ.","anchor":"từ trong thất khiếu của hắn lập tức lan ra làn khói bảy màu, nhanh chóng ngưng tụ lại ở bên ngoài thân thể hắn, bất ngờ hóa thành hồn của đạo nhân bảy màu"}],"nhanMach":[],"tuViMoc":[]},"nguon":["@c1633","@c1649","@c1651","@c1653","@c1655","@c1656","@c1657","@c1658","@c1662","@c1664","@c1665","@c1667","@c1668","@c1669","@c1670","@c1674","@c1682","@c1683"],"aliases":["Thất Thải Tiên Tôn","Thất Thải đạo nhân","Tô Đạo"],"trangThai":"tu-vong","canhGioiCaoNhat":"Thái Sơ cảnh"},{"id":"thanh-nien-bi-an","name":"Thanh niên bí ẩn","aliases":["Huyền La Đại Thiên Tôn","Thanh niên bí ẩn","Thanh niên tóc đen trường sam đen"],"tabs":{"kinhLich":[{"mucCt":"vua","text":"Xuất hiện từ đám huyết sắc trong tinh không Côn Hư, không ai trong động phủ giới phát hiện. Phát hiện vị trí Vương Lâm, gọi hắn là đứa nhỏ, quyết định đi theo xem xét.","anchor":"Đứa nhỏ này ta chưa hiểu, cũng nên đi theo xem xét một phen","bridge":true,"khoang":"@c1635"},{"chuong":"@c1637","importance":"bridge","mucCt":"vua","text":"Đứng bên ngoài Ngũ Hành tinh quan sát trận chiến, lần đầu biết tên Vương Lâm, cười vui vẻ nhận xét hắn nhìn ra bí mật áo giáp danh tiếng ở tiên tộc là rất giỏi.","anchor":"Đứa nhỏ này hóa ra tên là Vương Lâm"},{"mucCt":"ky","text":"Trôi nổi bên ngoài tinh không Ngũ Hành tinh quan sát toàn bộ trận chiến, thần sắc dở khóc dở cười. Nhìn ra rõ ràng Thủy Tướng không hề luyện hóa Vương Lâm mà đang vô tình trợ giúp cảm ngộ thủy bổn nguyên. Nhận xét Vương Lâm có huyết mạch Đạo cổ, tiên nhân thuật, bảy đạo bổn nguyên, cấm chế bổn nguyên tồn tại trong tơ máu đồng tử hóa thành quy tắc — chưa từng thấy trên bất cứ ai. Kết luận: Đạo tiên song tu.","anchor":"đứa nhỏ này có huyết mạch Đạo cổ, lại có tiên nhân thuật, điểm này đúng là cực khó có được","bridge":true,"khoang":"@c1638"},{"mucCt":"vua","text":"Ở ngoài tinh không bên ngoài Ngũ Hành tinh chứng kiến toàn bộ, mỉm cười đắc ý khen Vương Lâm có gan hợp tính tình, gọi hắn là đứa nhỏ của Đạo cổ nhất tộc. Nhắc tới Quy Nhất tông, nói đám tiên nhân nơi này rất thú vị, thản nhiên biểu thị thực lực có thể phất tay diệt sạch sinh linh trên tu chân tinh.","anchor":"Tốt, quả nhiên là đứa nhỏ của Đạo cổ nhất tộc ta, có gan đối phó với tất cả những người dám mạo phạm hắn","bridge":true,"khoang":"@c1640"},{"mucCt":"ky","text":"Lơ lửng trong tinh không bên ngoài Ngũ Hành tinh quan sát trận pháp. Nhận định Cửu Chuyển Tâm Luân là danh trận Tiên Cương đại lục, cho rằng ngay cả Đạo cổ hoàng tôn đời này nếu chưa gặp cũng sẽ bị nhốt. Trong lòng có một tia chờ mong yếu ớt rằng Vương Lâm có thể phá, nhưng tự thấy kỳ vọng quá cao. Thất vọng khi Vương Lâm tới ngũ chuyển, giơ tay phải định ra tay cứu. Tới cửu chuyển thấy chuyển động chậm lại, hai mắt sững sờ, tay buông xuống không can thiệp, trái tim tĩnh lặng vạn cổ đập thình thịch.","anchor":"trái tim tĩnh lặng từ vạn cổ lúc này đập thình thịch","bridge":true,"khoang":"@c1642"},{"mucCt":"vua","text":"Quan sát toàn bộ quá trình Vương Lâm phá Cửu Chuyển Tâm Luân từ bên ngoài Ngũ Hành tinh, phân tích chính xác phương pháp thân tình dẫn tâm, nội tâm chấn động kịch liệt. Khi Vương Lâm nghịch chuyển trận pháp thì cười vang tán thưởng, khen hợp tính tình ta.","anchor":"Người này ta nhất định phải có!","bridge":true,"khoang":"@c1643"},{"chuong":"@c1644","importance":"bridge","mucCt":"vua","text":"Ở bên ngoài Ngũ Hành tinh, nghe thấy lời lão già tầng ba sỉ nhục Đạo Cổ nhất mạch, thần sắc âm trầm — cả đời chưa bao giờ gặp ai dám vũ nhục Đạo Cổ nhất mạch.","anchor":"Hắn cả đời này chưa bao giờ thấy ai dám vũ nhục Đạo cổ nhất mạch"},{"chuong":"@c1645","importance":"minor","mucCt":"gon","tieuDe":"Quan sát Đạo cổ bất diệt thể","text":"Quan sát Vương Lâm từ bên ngoài Ngũ Hành tinh, nhận xét Đạo cổ bất diệt thể cùng loại với tiên nhân bất diệt thể, thắc mắc Vương Lâm muốn làm gì.","anchor":"Đây là một loại thần thông cùng loại với tiên nhân bất diệt thể"},{"chuong":"@c1646","importance":"major","mucCt":"ky","tieuDe":"Giáng lâm Ngũ Hành tinh, chấn nhiếp toàn trường","text":"Thân ảnh mơ hồ giáng lâm Ngũ Hành tinh, chất vấn ai dám nói Đạo cổ nhất mạch đều là đám hoang dã. Uy áp kinh thiên khiến toàn bộ tu sĩ sợ hãi tột độ, ba nam tử trung niên phun máu bật bay, đại địa rung chuyển, mặt trời tắt sáng. Bóp cổ lão già mặc song hành khải, tay nhẹ vung phá nát bộ song hành giáp cường hãn như tờ giấy. Được lão già họ Mã run rẩy nhận diện danh tính.","anchor":"Người có thể tùy ý hủy diệt áo giáp của Quy Nhất tông như thế, chất vấn bá đạo như thế về chuyện bất kính với Đạo cổ nhất mạch thì chỉ có thể là một người"},{"importance":"normal","mucCt":"ky","chuong":"@c1647","tieuDe":"Thị uy Ngũ Hành tinh, đoạt giáp, đặt tiêu chí tuyển Vương Lâm","text":"Hiện thân ảnh mơ hồ trên Ngũ Hành tinh với uy áp cửu dương khiến mọi người không thể nhìn rõ diện mạo. Vuốt tay giết lão già mất áo giáp, phóng uy áp buộc tất cả quỳ gối. Khen Vân Dật Phong tâm trí cực cao nhưng tiếc không phải Đạo cổ nhất mạch. Phá tầng tháp thứ nhất, đoạt tấm áo giáp đen kịt, tuyên bố Quy Nhất tông nếu có tư cách thì cứ tới lấy lại. Ra lệnh bọn họ chưa được rời đi, phải làm hòn đá mài đao rèn luyện Vương Lâm. Bí mật theo Vương Lâm qua trận pháp ngân hà vào tiên giới, bị Vương Lâm thăm dò nhưng không lộ. Tổng kết đánh giá Vương Lâm qua bốn lần quan sát: bá đạo, minh ngộ, quyết đoán mưu trí, cẩn thận. Đặt tiêu chí cuối cùng cần kiểm chứng: trọng nghĩa tình. So sánh Vân Dật Phong với Vương Lâm, cho rằng Vân Dật Phong ưu tú hơn nhưng thuộc tiên tộc.","anchor":"Chẳng qua người ta muốn tuyển phải trọng nghĩa tình! Người này không biết có được hay không?"},{"chuong":"@c1648","importance":"bridge","mucCt":"vua","text":"Đứng trong ngọn núi quan sát Vương Lâm, phóng thần thức vào sương mù mộng ảo để xem, chứng kiến toàn bộ cảnh Vương Lâm nhập mộng nhớ Lý Mộ Uyển, trong lòng đau đớn cảm thán về nỗi bi ai khiến người ta phải vào mộng tìm hạnh phúc.","anchor":"Đây là nỗi nhớ nhung và bi ai gì mà có thể khiến người ta phải đi vào mộng ảo để tìm hạnh phúc"},{"mucCt":"vua","text":"Thấy Vương Lâm rơi vào vòng luẩn quẩn, điểm một ngón tay đưa ý niệm biến số vào đầu hắn. Tự suy tư thiên đạo huyền diệu, tiết lộ Cửu dương cũng đang tìm bước tiến tiếp theo nhưng chưa ai làm được, và thiên đạo xuất hiện đầu tiên ở Cổ Thần cảnh. Trên ngón trỏ có ấn ký màu đen giống hố đen xoay tròn tỏa khí tức thiên đạo.","anchor":"Thiên đạo, vật này xuất hiện đầu tiên ở cổ Thần cảnh, cổ Thần rất huyền ảo","bridge":true,"khoang":"@c1653"},{"importance":"normal","mucCt":"vua","chuong":"@c1654","tieuDe":"Kinh hãi nhận ra Không Diệt khí","text":"Đi theo Vương Lâm tới tu chân tinh, lần đầu tiên đại biến sắc mặt khi nhìn thấy thanh kiếm hư ảo bên người Vương Lâm. Nhận ra đó là khí tức của Không Diệt, vô cùng khiếp sợ.","anchor":"Không Diệt khí! Đây là khí tức của không diệt!"},{"mucCt":"gon","text":"Xuất hiện từ hư vô sau khi tất cả đã vào, trầm ngâm rồi thong dong tiến vào đại môn, tuyên bố khảo sát đối với Vương Lâm sẽ chấm dứt ở đây.","anchor":"Khảo sát đối với người này hẳn sẽ chấm dứt ở đây","bridge":true,"khoang":"@c1657"}],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Đối tượng quan sát, lần đầu biết tên, đánh giá cao"}],"tuViMoc":[]},"nguon":["@c1633","@c1635","@c1637","@c1638","@c1640","@c1642","@c1643","@c1644","@c1645","@c1646","@c1647","@c1648","@c1653","@c1654","@c1657"],"trangThai":"song","cn":"玄罗大天尊","gioiTinh":"nam"},{"id":"u-minh-thu","name":"U Minh thú","tabs":{"kinhLich":[{"chuong":"@c1633","importance":"normal","mucCt":"vua","tieuDe":"Phóng sương mù thiên đạo nuốt gần hết tiên nhân","text":"Mở miệng phóng sương mù tràn ngập tinh không mang khí tức tang thương, lực hút kinh thiên cuốn khoảng bảy tám mươi tiên nhân nuốt hết. Tứ đại chiến tướng nhận ra đây là thiên đạo. Sau đó truyền đạt cho Vương Lâm rằng rất khó nuốt được Chiến lão quỷ.","anchor":"Tinh không nếu ví là thiên địa thì thiên địa biến sắc, tinh thần nếu là phong vân thì phong vân cuồn cuộn"}]},"nguon":["@c1633"]},{"id":"nap-da","name":"Nạp Đa","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1634","importance":"bridge","mucCt":"vua","text":"Được nhắc đã bế quan ngàn năm cùng tông chủ và trưởng lão Quy Nhất Tông. Vương Lâm tới Ngũ Hành tinh theo ước hẹn năm xưa nhưng không gặp được.","anchor":"Nạp Đa trưởng lão ngàn năm trước đã bế quan, không hỏi thế sự"},{"mucCt":"vua","text":"Ngồi trên tầng chín tháp Ngũ Hành tinh, nhận ra Vương Lâm từ tu sĩ Nguyên Anh đã vượt xa mình, tự nhận chỉ là hậu nhân bảo vệ nơi này. Nhận định Vương Lâm chỉ Không Linh trung kỳ, có thể qua Ngũ Hành nhưng không thể qua đệ tam chuyển. Khi thấy Vương Lâm thu cả trận linh thì nhíu mày nhưng vẫn tự tin còn tứ quan và cửu chuyển, ánh mắt lộ hàn quang, không còn giao tình.","anchor":"Năm đó hắn chỉ là một tu sĩ Nguyên Anh, hơn một ngàn năm đã đạt tới mức này","bridge":true,"khoang":"@c1635"},{"chuong":"@c1637","importance":"bridge","mucCt":"gon","text":"Bị tu sĩ Quy Nhất tông nhắc tên trong bài xuyên tạc, vu rằng Nạp Đa trưởng lão năm xưa tha mạng Vương Lâm nhưng bị vô ơn.","anchor":"Nạp Đa trưởng lão Quy Nhất tông được chúng ta kính trọng năm đó cũng là gặp phải lúc Vương Lâm giết hại phàm nhân mới ra tay ngăn cản"},{"mucCt":"vua","text":"Được Thủy Tướng cầu viện trong lúc nguy cấp. Từ bầu trời thủy trận truyền vào lực lượng Ngũ Hành hệ kim (kim sinh thủy), khiến quả cầu nước Càn Khôn Nhất Tích thêm mạnh mẽ.","anchor":"bầu trời trên thủy trận liền có một dòng xoáy xuất hiện","bridge":true,"khoang":"@c1638"},{"mucCt":"vua","text":"Từ tháp cao quan sát qua thần thức, tự tin Vương Lâm không thoát được, phân tích mục đích Vương Lâm là tìm hồn thứ ba. Mặc bộ áo giáp kim quang tu vi tăng mạnh, dẫn đầu mấy trăm tu sĩ phóng thần thức nhập trận đè ép. Sau khi Vương Lâm thu bổn nguyên, thần thức bị tống ra, mê man nhận ra Vương Lâm đã nhận thổ linh, khiến hỏa linh vái lạy, lại lấy cả thủy bổn nguyên.","anchor":"Hắn nhận được thổ linh, khiến hỏa linh vái lạy, lại lấy cả thủy bổn nguyên do Càn Khôn Nhất tích biến thành","bridge":true,"khoang":"@c1639"},{"chuong":"@c1641","importance":"bridge","mucCt":"vua","text":"Được Đệ Cửu lão tổ dùng bàn tay hư ảo túm đưa lên tầng chín, phủ phục xưng hậu bối tử tôn, kể hết những gì biết về Vương Lâm cho lão tổ.","anchor":"Hậu bối tử tôn Nạp Đa xin ra mặt đệ cửu lão tổ"},{"mucCt":"vua","text":"Sùng kính lão tổ kim bào, ôm quyền vái. Năm xưa từng bị nhốt trong đệ tam chuyển của Cửu Chuyển Tâm Luân đã hôn mê, được lão tổ cứu, tu dưỡng rất lâu mới hồi phục, từ đó kính sợ trận pháp này. Tới cửu chuyển cũng tươi cười nghĩ Vương Lâm thua, nhưng khi chuyển động chậm lại thì kinh hãi.","anchor":"Năm đó hắn ở trong đệ tam chuyển đã hôn mê, được lão tổ cứu, tu dưỡng rất lâu mới khôi phục được","bridge":true,"khoang":"@c1642"},{"mucCt":"vua","text":"Sợ hãi trước biến đổi của Vương Lâm. Khi bị Cửu Chuyển Tâm Luân nghịch chuyển đánh ngược, sự sợ hãi năm xưa tràn ngập tâm thần, miễn cưỡng chịu tới đệ tứ chuyển thì phun máu hôn mê.","anchor":"Sự sợ hãi năm đó lúc này lại tràn ngập tâm thần, khiến Nạp Đa suýt nữa là bị sợ hãi khiến trở nên điên cuồng","bridge":true,"khoang":"@c1643"},{"chuong":"@c1644","importance":"bridge","mucCt":"gon","text":"Nằm trên mặt đất Ngũ Hành tinh sau nghịch động, được Vương Lâm nhìn thấy từ trên bầu trời.","anchor":"Hắn muốn xem nơi này rốt cục tồn tại cường giả tới bậc nào"}],"nhanMach":[{"ten":"Đệ Cửu lão tổ","tag":"cap-tren","quanHe":"Lão tổ đời thứ chín trong tông môn, triệu hắn lên tầng chín hỏi về Vương Lâm","ghiChu":"@c1641"}],"tuViMoc":[]},"nguon":["@c1634","@c1635","@c1636","@c1637","@c1638","@c1639","@c1641","@c1642","@c1643","@c1644"],"gioiTinh":"nam","cn":"纳多"},{"id":"duan-dong","name":"Duẫn Đông Thân","cn":"","aliases":["Duẫn Đông"],"gioiTinh":"nam","theLuc":[{"ten":"Quy Nhất Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Phó tông chủ Quy Nhất Tông trên Ngũ Hành tinh, giọng khàn khàn, ẩn vẻ khiếp sợ và kiêng kỵ. Được giao phụ trách tông phái khi tông chủ và các trưởng lão bế quan.","vaiTro":"Phó tông chủ Quy Nhất Tông, người ngăn cản Vương Lâm","tinhCach":"Cẩn trọng; có vẻ khiếp sợ và kiêng kỵ khi đối diện Vương Lâm; trung thành với tông phái","tabs":{"diem":[{"text":"Phó tông chủ Quy Nhất Tông, quản lý tông phái khi lãnh đạo bế quan","chuong":"@c1634"},{"text":"Trưởng lão Quy Nhất tông, người trực tiếp đối thoại với Vương Lâm trước khi hắn tiến vào Ngũ Hành đại trận","chuong":"@c1635"}],"kinhLich":[{"mucCt":"vua","text":"Đáp lời Vương Lâm khi hắn truyền âm vào Ngũ Hành tinh, tự xưng phó tông chủ. Nói Nạp Đa đã bế quan ngàn năm, từ chối cho Vương Lâm vào và cảnh báo sẽ khởi động Ngũ Hành Quy Nhất trận.","anchor":"Lão phu là phó tông chủ Quy Nhất Tông - Duẫn Đông Thân","bridge":true,"khoang":"@c1634"},{"mucCt":"gon","text":"Cùng ba trưởng lão khác họp bàn về Vương Lâm, đề xuất báo cho Nạp Đa.","anchor":"Giọng nói này chính là của Duẫn Đông Thân vừa đối thoại với Vương Lâm","bridge":true,"khoang":"@c1635"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Khách tìm tới Ngũ Hành tinh, Duẫn Đông Thân từ chối cho vào","ghiChu":"@c1634"},{"ten":"Nạp Đa","tag":"cap-tren","quanHe":"Trưởng lão Quy Nhất Tông, cấp trên của Duẫn Đông Thân","ghiChu":"@c1634"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối tượng đối thoại và giám sát khi Vương Lâm xâm nhập Ngũ Hành tinh","ghiChu":"@c1635"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1634","@c1635"]},{"id":"de-cuu-lao-to","name":"Đệ Cửu lão tổ","cn":"","aliases":["Lão già mặc hắc bào","Lão già mặc kim bào","Lão già mặc áo đen"],"gioiTinh":"nam","theLuc":[{"ten":"Quy Nhất Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Một trong bốn cường giả ngồi ở tầng thứ mười từ trên xuống trong tháp Quy Nhất Tông, đôi mắt cực bá đạo. Tự tin tuyệt đối vào Ngũ Hành đại trận, khinh thường mọi tu sĩ trong động phủ giới ngoại trừ Thất Thải Tiên Tôn.","vaiTro":"Cường giả tầng cao Quy Nhất Tông, có thể là chủ nhân thần thức bá đạo thách thức Vương Lâm","tinhCach":"Bá đạo; kiêu ngạo; khinh thường người ngoài; tự tin tuyệt đối","tabs":{"diem":[{"text":"Tuyên bố trong động phủ giới trừ Thất Thải Tiên Tôn chẳng ai đáng coi trọng, tự nhận lọt Ngũ Hành đại trận chỉ chống đỡ nửa nén nhang","chuong":"@c1634"},{"text":"Đối chưởng Vương Lâm bị bẻ gãy cánh tay, nhờ áo giáp nội liễm mới không tan xác","chuong":"@c1641"},{"text":"Nhận định chính xác Vương Lâm là người cổ tộc thuộc Đạo cổ nhất mạch","chuong":"@c1641"}],"kinhLich":[{"mucCt":"vua","text":"Ngồi ở tầng thứ mười từ trên xuống của tháp Quy Nhất Tông cùng ba người khác. Tuyên bố trong động phủ giới trừ Thất Thải Tiên Tôn chẳng ai đáng coi trọng, khẳng định Ngũ Hành đại trận ngay cả bản thân lọt vào cũng chỉ chống đỡ nửa nén nhang, Vương Lâm tuyệt đối không qua được ngũ quan.","anchor":"Cho dù hắn là Vương Lâm thì đã sao","bridge":true,"khoang":"@c1634"},{"mucCt":"gon","text":"Phất tay áo tạo mặt gương quan sát Vương Lâm, quyết định không cần đợi Nạp Đa mà cho kích hoạt trận pháp thử sức. Hoảng sợ khi thấy Vương Lâm thu trận linh.","anchor":"Lão phu đã quyết định rồi. Nạp Đa chưa chắc đã không biết việc này","bridge":true,"khoang":"@c1635"},{"importance":"bridge","mucCt":"gon","chuong":"@c1639","tieuDe":"Hưng phấn rồi sợ hãi trước kết cục Vương Lâm thu bổn nguyên","text":"Hưng phấn tin Càn Khôn Nhất Tích sẽ giết Vương Lâm, sau khi chứng kiến kết cục thì sợ hãi ngập trời nửa ngày không nói được lời nào.","anchor":"Nhất là lão già mặc áo đen đến nửa ngày cũng không thể nói gì, trong mắt trào dâng sự sợ hãi ngập trời."},{"mucCt":"vua","text":"Đối chưởng Vương Lâm qua dòng xoáy, bị bẻ gãy cánh tay phải phun máu tươi, nhờ áo giáp nội liễm trong cơ thể mới không tan xác. Nhận định Vương Lâm là người cổ tộc thuộc Đạo cổ nhất mạch, nghi đến từ Tiên Cương đại lục. Triệu Nạp Đa hỏi lai lịch Vương Lâm, giải thích nguyên lý Cửu Chuyển Tâm Luân — trận pháp hộ sơn Quy Nhất tông.","anchor":"Người cổ tộc. Lực lượng từ trong cơ thể hắn truyền ra thuộc về Đạo cổ nhất mạch!","bridge":true,"khoang":"@c1641"},{"mucCt":"vua","text":"Ngồi tầng tháp thứ chín giải thích cơ chế Cửu Chuyển Tâm Luân cho Nạp Đa, tự tin người thông minh càng không thoát nổi. Cúi nhìn cánh tay phải vẫn đau đớn dù vận chuyển tiên lực cũng không đỡ, lộ vẻ oán độc. Tới đệ cửu chuyển cười phá tuyên bố Vương Lâm chết chắc, rủ Nạp Đa đi nhặt xác. Nhưng chuyển động đột ngột chậm lại, hắn kinh hãi không thể tin.","anchor":"Cửu chuyển rồi, người này chết chắc rồi! Nạp Đa chuẩn bị theo lão phu đi nhặt xác người này!","bridge":true,"khoang":"@c1642"},{"importance":"normal","mucCt":"vua","chuong":"@c1643","tieuDe":"Chống nghịch chuyển tới đệ thất chuyển mới suy kiệt","text":"Không thể tin tu sĩ động phủ giới phá được Cửu Chuyển Tâm Luân, xác nhận đây là danh trận Tiên Cương đại lục. Khi bị trận pháp nghịch chuyển, cố điểm vào mi tâm bình tâm nhưng bị tiếng gào thét xung quanh quấy loạn, chống đỡ lâu nhất trong số tu sĩ Quy Nhất tông, phun máu héo rũ ở đệ thất chuyển.","anchor":"hắn tuyệt đối không thể ở đệ cửu chuyển mà đình chỉ sự vận chuyển của Cửu Chuyển Tâm Luân"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Kẻ xâm nhập Ngũ Hành tinh, bị lão già hắc bào khinh thường","ghiChu":"@c1634"},{"ten":"Thất Thải Tiên Tôn","tag":"khac","quanHe":"Người duy nhất được lão già hắc bào thừa nhận trong động phủ giới","ghiChu":"@c1634"},{"ten":"Nạp Đa","tag":"ho-hang","quanHe":"Hậu bối tử tôn trong tông môn, được triệu lên tầng chín hỏi về Vương Lâm","ghiChu":"@c1641"},{"ten":"Diệp Mịch","tag":"khac","quanHe":"Nhắc đến ba nghìn huyết mạch của Diệp Mịch khi phân tích lai lịch Vương Lâm","ghiChu":"@c1641"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1634","@c1635","@c1636","@c1639","@c1641","@c1642","@c1643"]},{"id":"nu-tu-trung-nien-quy-nhat","name":"Nữ tử trung niên (Quy Nhất Tông)","cn":"","aliases":[],"gioiTinh":"nu","theLuc":[{"ten":"Quy Nhất Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Một trong bốn cường giả ngồi ở tầng cao tháp Quy Nhất Tông, thần sắc khắc bạc, giọng the thé. Hi vọng Vương Lâm qua được ngũ quan để thấy cửu chuyển của Ngũ Hành quy nhất.","vaiTro":"Cường giả tầng cao Quy Nhất Tông","tinhCach":"Khắc bạc; thích thú trước thử thách","tabs":{"diem":[{"text":"Hi vọng Vương Lâm qua được ngũ quan để trận pháp thành Ngũ Hành quy nhất cửu chuyển","chuong":"@c1634"}],"kinhLich":[{"chuong":"@c1634","importance":"bridge","mucCt":"gon","text":"Ngồi cạnh lão già hắc bào ở tầng cao tháp Quy Nhất Tông, bày tỏ hi vọng Vương Lâm qua được ngũ quan.","anchor":"Ta thật sự là hi vọng hắn qua được ngũ quan"},{"mucCt":"gon","text":"Lộ thái độ thù hận liên quan đến Tư Đồ Nam, gọi hắn là kẻ phụ lòng người, muốn Vương Lâm chịu trừng phạt thay. Hai trưởng lão khác nhíu mày cảm thấy bất thường.","anchor":"Vương Lâm, ngươi quen biết với Tư Đồ Nam, hôm nay ngươi tiếp nhận sự trừng phạt thay cho kẻ phụ lòng người đó đi","bridge":true,"khoang":"@c1635"},{"chuong":"@c1636","importance":"bridge","mucCt":"gon","text":"Mong Vương Lâm bị thương trong hỏa trận nhưng chứng kiến hỏa linh quỳ bái hắn, sắc mặt tái mét lộ sợ hãi.","anchor":"Nàng hận Tư Đồ Nam lại càng hận tất cả những người quen biết với hắn"},{"importance":"bridge","mucCt":"vua","chuong":"@c1639","tieuDe":"Thề nhắm Tư Đồ Nam rồi bàng hoàng trước thất bại","text":"Mong Vương Lâm chết để Tư Đồ Nam bi thương, thề Tư Đồ Nam sẽ là mục tiêu tiếp theo. Sau khi chứng kiến Vương Lâm thu bổn nguyên thì không thể thừa nhận kết quả.","anchor":"Người chết rồi Tư Đồ Nam kia sẽ bi thương. Hắn càng bi thương càng phẫn nộ ta lại càng được giải hận!"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Kẻ xâm nhập Ngũ Hành tinh, nữ tử muốn xem hắn chịu được mấy chuyển","ghiChu":"@c1634"},{"ten":"Tư Đồ Nam","tag":"khac","quanHe":"Gọi Tư Đồ Nam là kẻ phụ lòng người, có tư thù tình cảm quá khứ","ghiChu":"@c1635"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1634","@c1635","@c1636","@c1639"]},{"id":"nam-tu-trung-nien-than-trong","name":"Nam tử trung niên (trưởng lão thận trọng, Quy Nhất tông)","gioiTinh":"nam","theLuc":[{"ten":"Quy Nhất tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Một trong bốn trưởng lão Quy Nhất tông canh giữ tầng dưới tháp Ngũ Hành tinh. Thận trọng, đề nghị không nên chọc Vương Lâm trước khi có chỉ thị của Nạp Đa.","vaiTro":"Trưởng lão Quy Nhất tông","tinhCach":"Thận trọng, cẩn thận","tabs":{"diem":[{"text":"Trưởng lão thận trọng nhất trong nhóm bốn, đề nghị chờ chỉ thị Nạp Đa","chuong":"@c1635"}],"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1635","tieuDe":"Bàn bạc đối phó Vương Lâm","text":"Cau mày đề nghị không nên chọc vào Vương Lâm trước khi có chỉ thị của Nạp Đa trưởng lão.","anchor":"Ta cũng đề nghị là trước khi có chỉ thị của Nạp Đa trưởng lão thì không nên chọc vào Vương Lâm này"},{"chuong":"@c1636","importance":"normal","mucCt":"vua","tieuDe":"Khoác tiên tổ chiến giáp nghênh chiến","text":"Triệu xuất tiên tổ chiến giáp màu xanh nước biển tỏa sóng nước từ tầng thứ mười, tạo trường thương bằng sóng nước. Tuyên bố dùng Ngũ Hành thủy trận bức Vương Lâm ra khỏi trận pháp, tiến vào cửu chuyển, nhờ Nạp Đa áp trận rồi hóa hơi nước biến mất.","anchor":"Trận tiếp theo là Ngũ Hành thủy trận. Ta sẽ thử xem có thể bức hắn ra khỏi trận pháp, trực tiếp tiến vào cửu chuyển hay không"}],"tuViMoc":[],"nhanMach":[{"ten":"Nạp Đa","tag":"cap-tren","quanHe":"Nạp Đa trưởng lão, cấp trên trong Quy Nhất tông","ghiChu":"@c1635"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1635","@c1636"]},{"id":"thuy-tuong","name":"Thủy Tướng","aliases":["Ngũ tiên Thủy Tướng","Nam tử trung niên áo tím","Nam tử trung niên"],"gioiTinh":"nam","theLuc":[{"ten":"Quy Nhất tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Bước thứ hai (nhờ áo giáp đánh ra lực lượng bước thứ ba)","trangThai":"song","blurb":"Nam tử trung niên tướng mạo anh tuấn, ngồi đối diện Nạp Đa trên tầng chín tháp Ngũ Hành tinh. Tự nhận chỉ là hậu nhân bảo vệ nơi này, tự tin vào lão tổ đang ngủ ở tầng trên.","vaiTro":"Hộ vệ tầng chín tháp Ngũ Hành tinh, Quy Nhất tông","tinhCach":"Tự tin, bình thản","tabs":{"diem":[{"text":"Ngồi cùng Nạp Đa trên tầng chín tháp, tự nhận chỉ là hậu nhân, tin tưởng lão tổ đang ngủ có thể hóa giải mọi thứ","chuong":"@c1635"},{"text":"Sở hữu thân thể thủy linh Ngũ Hành hoàn chỉnh, là linh hồn thủy trận khiến uy lực gia tăng gấp bội","chuong":"@c1637"},{"text":"Mặc áo giáp đặc biệt có thể đánh ra lực lượng bước thứ ba nhưng bị áo giáp điều khiển ngược","chuong":"@c1637"}],"kinhLich":[{"mucCt":"gon","text":"Ngồi đối diện Nạp Đa trên tầng chín, tự nhận chỉ là hậu nhân, nói chỉ cần một lão tổ ở tầng trên thức tỉnh là đủ hóa giải tất cả.","anchor":"Chỉ cần một trong mấy lão tổ ở tầng trên thức tỉnh là có thể hóa giải tất cả","bridge":true,"khoang":"@c1635"},{"mucCt":"ky","text":"Nổi lên từ biển trong Ngũ Hành thủy trận, dùng bốn bức tường nước vạn trượng bao vây và trường thương nước mưa huyễn hóa nhấn chìm Vương Lâm cùng người khổng lồ lửa, chín Kỳ Lân trong đại hải. Kiêu ngạo tuyên bố mình là thần tiên trong Ngũ Hành đại trận. Bị Vương Lâm xuất hiện sau lưng vỗ chưởng truyền lực lượng bổn nguyên và khí tức hủy diệt Đạo cổ, ngũ tạng tan nát, xương cốt chia lìa, phun máu bị đánh bay. Nhờ áo giáp phóng sinh cơ khôi phục thương thế. Bí mật áo giáp bị Vương Lâm nhìn thấu: tu vi thực sự không tới bước thứ ba, áo giáp điều khiển ngược người mặc.","anchor":"Chỉ có chút tu vi đó sao.ở nơi này ta chính là Ngũ Hành thủy linh","bridge":true,"khoang":"@c1637"},{"importance":"normal","mucCt":"ky","chuong":"@c1638","tieuDe":"Thi triển Càn Khôn Nhất Tích, lộ hình dạng thật","text":"Bị Vương Lâm yêu cầu cởi giáp đổi mạng, từ chối và lùi xa chuẩn bị phản công. Ném trường thương vào biển, phun máu bắt quyết, dùng thân thể thủy linh ngưng tụ toàn bộ nước biển và nước mưa thành quả cầu khổng lồ nhốt Vương Lâm, thi triển thần thông Càn Khôn Nhất Tích do tổ tiên truyền. Tuôn hết lực lượng áo giáp, thân thể héo rũ nổi đầy mụn mủ, lộ hình dạng thật — bản chất chỉ là tu sĩ thiên nhân tứ suy đã trải bốn lần suy kiếp. Dùng hết sức kêu gọi Nạp Đa trợ giúp, được lực lượng kim hệ bổ sung, tự tin tuyên bố Vương Lâm chết chắc nhưng thực tế đang vô tình giúp đối phương cảm ngộ thủy bổn nguyên.","anchor":"thân thể lập tức héo rũ, vẻ anh tuấn liền trở thành xấu xí, thân thể nổi đầy mụn mủ"},{"mucCt":"vua","text":"Dùng thần thông Càn Khôn Nhất Tích đè ép thủy cầu, phun máu tươi gia tốc co rút nhưng vô tình cung cấp thêm biến hóa bổn nguyên cho Vương Lâm minh ngộ. Sau khi Vương Lâm thu toàn bộ thủy bổn nguyên, run rẩy phun máu cười thảm lảo đảo, bị giữ lại một mình trong trận với Vương Lâm.","anchor":"Thân thể Thủy Tướng run lên, phun một ngụm máu tươi, cười thảm lảo đảo lui lại phía sau vài bước.","bridge":true,"khoang":"@c1639"},{"chuong":"@c1640","importance":"normal","mucCt":"vua","tieuDe":"Được Vương Lâm cứu mạng, mất áo giáp","text":"Bị Vương Lâm bắt lại khi bỏ chạy, được truyền sinh cơ vào mi tâm để ngăn áo giáp hút sạch sinh cơ cuối cùng. Áo giáp bị tháo khỏi thân thể bằng huyết kiếm, quá trình cực kỳ đau đớn. Sau khi tháo giáp, thân thể tràn đầy huyết vụ, cực kỳ suy yếu, biến mất trong Ngũ Hành thủy trận.","anchor":"mang theo vẻ buồn bã uể oải, biến mất trong Ngũ Hành thủy trận"},{"chuong":"@c1662","importance":"bridge","mucCt":"vua","text":"Binh lính do thần thức biến thành đóng vai binh trên bàn cờ tàn giới thứ ba, được hưởng lợi khi Vương Lâm tiến vào phân tán áp chế huyết mạch — binh lính tỏa kim quang, chiến lực tăng mạnh, kim quang ngưng tụ thành giáp vàng đơn giản.","anchor":"kim quang trên thân thể liền lóe lên hóa thành một bộ giáp màu vàng"}],"tuViMoc":[],"nhanMach":[{"ten":"Nạp Đa","tag":"dong-minh","quanHe":"Cùng trấn giữ tầng chín tháp Ngũ Hành tinh, đồng hạng hậu nhân Quy Nhất tông","ghiChu":"@c1635"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ tấn công trong thủy trận, bị Vương Lâm đánh bại"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1635","@c1636","@c1637","@c1638","@c1639","@c1640","@c1662"],"cn":"水将"},{"id":"lao-gia-tinh-niet-trung-ky","name":"Lão già Tịnh Niết trung kỳ","gioiTinh":"nam","theLuc":[{"ten":"Quy Nhất tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Tịnh Niết trung kỳ","trangThai":"song","blurb":"Tu sĩ Quy Nhất tông tu vi Tịnh Niết trung kỳ, kích động đám đông bằng bài diễn thuyết xuyên tạc Vương Lâm là kẻ sát nhân tàn ác.","vaiTro":"Tu sĩ Quy Nhất tông, kẻ xuyên tạc kích động đám đông chống Vương Lâm","tinhCach":"Giọng khàn khàn, giỏi kích động; thống hận giả tạo, nước mắt chảy dài","tabs":{"diem":[{"text":"Kích động mấy trăm tu sĩ Quy Nhất tông bằng lời xuyên tạc Vương Lâm giết toàn tộc họ Đằng vì tham bảo vật, vô ơn với Nạp Đa","chuong":"@c1637"}],"kinhLich":[{"mucCt":"vua","text":"Kích động mấy trăm tu sĩ Quy Nhất tông bằng bài diễn thuyết xuyên tạc: vu cho Vương Lâm giết toàn tộc họ Đằng vì tham bảo vật, giết phàm nhân, vô ơn với Nạp Đa trưởng lão. Giọng khàn khàn, nước mắt chảy dài, khiến những tu sĩ không biết Vương Lâm dần tin lời và trở nên phẫn nộ.","anchor":"lão già có tu vi tới Tịnh Niết trung kỳ lúc này hướng về bốn phía rống to một tiếng","bridge":true,"khoang":"@c1637"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối tượng bị xuyên tạc trước đám đông"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1637"]},{"id":"thien-van-tu","name":"Thiên Vận Tử","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1638","tieuDe":"Nhắc tặng giọt thủy bổn nguyên","text":"Được nhắc lại việc từng tặng Vương Lâm một giọt thủy bổn nguyên, trở thành một trong những chỉ dẫn tới đại đạo thủy bổn nguyên.","anchor":"lần trước Thiên Vận Tử tặng một giọt thủy bổn nguyên"},{"importance":"bridge","mucCt":"gon","chuong":"@c1653","text":"Được nhắc lại là một bộ phận của thiên đạo, trước kia đã cắn nuốt phách thứ bảy; Vương Lâm xác nhận phách thứ bảy không còn trong thiên đạo hiện tại sau khi U Minh thú nuốt Thiên Vận Tử.","anchor":"Thiên Vận Tử là một bộ phận của thiên đạo"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{}},"nguon":["@c1638","@c1653"]},{"id":"tu-do-nam","name":"Tư Đồ Nam","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1639","tieuDe":"Bị Quy Nhất tông đe dọa trực tiếp","text":"Bị nữ tử trung niên Quy Nhất tông thề nhắm tới là mục tiêu tiếp theo sau Vương Lâm.","anchor":"Tư Đồ Nam người tiếp theo sẽ là ngươi!"},{"chuong":"@c1650","importance":"normal","mucCt":"ky","tieuDe":"Được xác nhận là phách thứ hai của Thất Thải Tiên Tôn","text":"Được xác nhận chính là phách thứ hai (xanh) của Thất Thải Tiên Tôn, phách ẩn chứa toàn bộ tu vi không kiếp. Vương Lâm minh ngộ rằng thiên tư biến hóa kinh người của Tư Đồ Nam là do hắn là phách của Thất Thải Tiên Tôn.","anchor":"Hóa ra hắn là một phách của Thất Thải Tiên Tôn biến thành"},{"importance":"bridge","mucCt":"gon","chuong":"@c1653","text":"Được liệt kê là một trong sáu phách đã biết, cùng Thanh Thủy thuộc nhóm chưa xảy ra biến số, chưa hoàn toàn tách biệt khỏi Thất Thải Tiên Tôn.","anchor":"Còn Thanh Thủy và Tư Đồ Nam thì lại không có xảy ra biến số này"},{"importance":"bridge","mucCt":"vua","chuong":"@c1655","tieuDe":"Thức tỉnh đả tọa, Lam Mộng muốn mượn hồn phách","text":"Trong tiên giới, thức tỉnh từ đả tọa, thần sắc âm trầm yên lặng nhìn phía trước. Nhận được truyền âm từ Lam Mộng Đạo Tôn muốn mượn hồn phách.","anchor":"Tư Đồ Nam thức tỉnh từ đả tọa, thần sắc âm trầm, yên lặng nhìn về phía trước"},{"importance":"bridge","mucCt":"gon","chuong":"@c1657","text":"Ở tiên giới trầm mặc chú ý tới sự kiện đại môn động phủ giới mở ra, hiểu rằng người đầu tiên đi ra có thể là Thất Thải Tiên Tôn mới.","anchor":"Một số ít người biết được bí ẩn như Tư Đồ Nam và Thanh Thủy thì ở trong tiên giới trầm mặc, chú ý tới nơi này"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{}},"nguon":["@c1639","@c1650","@c1653","@c1655","@c1657"],"trangThai":"song"},{"id":"ke-la-dong-xoay-c1640","name":"Kẻ lạ trong dòng xoáy","cn":"","aliases":[],"gioiTinh":"nam","trangThai":"khong-ro","vaiTro":"Nhân vật bí ẩn xuất hiện từ dòng xoáy trong Ngũ Hành thủy trận, uy áp kinh khủng, muốn đoạt áo giáp Thủy Tướng","tinhCach":"Hống hách; coi thường người khác","blurb":"Kẻ bí ẩn giọng già nua, xuất hiện từ dòng xoáy khi Ngũ Hành thủy trận sụp đổ, uy áp kinh khủng. Vươn cánh tay khô héo đoạt áo giáp nhưng bị Vương Lâm đạp nát tay, nhận ra Vương Lâm là tu sĩ cổ quốc.","tabs":{"diem":[{"text":"Uy áp kinh khủng khiến Ngũ Hành thủy trận sụp đổ, nhưng bị Vương Lâm đạp nát cánh tay khi muốn đoạt áo giáp","chuong":"@c1640"}],"kinhLich":[{"mucCt":"gon","text":"Xuất hiện từ dòng xoáy với uy áp kinh khủng, vươn cánh tay khô héo đoạt áo giáp Thủy Tướng nhưng bị Vương Lâm bùng nổ toàn lực đạp nát, xương gãy vụn, cánh tay nổ tung. Nhận ra Vương Lâm là tu sĩ cổ quốc, người cổ tộc.","anchor":"Tu sĩ cổ quốc! Ngươi là người cổ tộc!","bridge":true,"khoang":"@c1640"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị Vương Lâm đạp nát tay khi đoạt áo giáp","ghiChu":"@c1640"}],"tuiDo":{}},"nguon":["@c1640"]},{"id":"diep-mich","name":"Diệp Mịch","gioiTinh":"nam","trangThai":"tu-vong","tabs":{"kinhLich":[{"chuong":"@c1641","importance":"bridge","mucCt":"gon","text":"Được Đệ Cửu lão tổ nhắc tới khi phân tích lai lịch Vương Lâm — lão cho rằng Vương Lâm không phải hậu nhân do ba nghìn huyết mạch của Diệp Mịch biến thành.","anchor":"Hắn không giống như hậu nhân do ba nghìn huyết mạch của Diệp Mịch biến thành"},{"chuong":"@c1672","importance":"normal","mucCt":"ky","tieuDe":"Nguyên thần đoạt xá thất bại, tiêu tán vĩnh viễn","text":"Nguyên thần huyết đầy đủ khiến nguyên thần Diệp Mịch ngưng tụ thành thực chất, mưu đoạt xá Vương Lâm bằng cách hóa khói xông vào thất khiếu. Tuy nhiên Vương Lâm có hồn huyết được cổ Tổ tán thành nên Diệp Mịch không thể đối kháng, sau ba canh giờ tiêu tán hoàn toàn trở thành một bộ phận Đạo cổ truyền thừa của Vương Lâm. Huyền La Đại Thiên Tôn tiết lộ Diệp Mịch xưa rải máu tươi cài nguyên thần huyết nhằm đoạt xá hậu bối truyền thừa, bình thường không thể thất bại nhưng Vương Lâm là ngoại lệ.","anchor":"Diệp Mịch không thể đối kháng, từ từ tiêu tán trở thành một bộ phận của Đạo cổ truyền thừa của Vương Lâm"},{"mucCt":"gon","text":"Cánh tay trái của Diệp Mịch phong ấn trong Đông Lâm Trì đóng băng được Vương Lâm phát hiện và dung hợp thành công, nay Vương Lâm đã có cả hai cánh tay của hắn.","anchor":"Ta sau khi dung hợp cánh tay phải của Diệp Mịch, thuật Tê Thiên đủ để xé tan thân thể tu sĩ bước thứ ba","bridge":true,"khoang":"@c1673"},{"importance":"bridge","mucCt":"gon","chuong":"@c1674","text":"Cánh tay trái được Vương Lâm dung hợp hoàn toàn, trái tim vẫn nằm ở tầng sâu nhất cổ mộ, được Huyền La Đại Thiên Tôn xác nhận đây là nơi tử vong.","anchor":"Truyền thừa của Diệp Mịch ngoài mắt trái ra thì chỉ còn có trái tim thôi"},{"importance":"normal","mucCt":"vua","chuong":"@c1680","tieuDe":"Trái tim truyền thừa cho Vương Lâm","text":"Trái tim khổng lồ trăm trượng ở tầng cuối vùng đất cổ mộ là di thể của Diệp Mịch. Thần niệm thê lương mang oán hận cực độ đòi Vương Lâm trả mắt trái. Sau khi Vương Lâm hứa ba điều, trái tim chấp nhận đập cùng nhịp, truyền Đạo Cổ khí tức cho Vương Lâm.","anchor":"Trả mắt trái lại cho ta!"}],"nhanMach":[],"tuViMoc":[]},"nguon":["@c1641","@c1645","@c1672","@c1673","@c1674","@c1680"]},{"id":"ba-lao-gia-trong-thap","name":"Ba lão già trong tháp","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Quy Nhất tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Ba cao thủ ẩn ở tầng thứ năm, sáu, bảy của ngọn tháp trên Ngũ Hành tinh. Đồng loạt xuất thủ phá vỡ Cửu Chuyển Tâm Luân đang bị nghịch chuyển, giải cứu tu sĩ Quy Nhất tông.","vaiTro":"Cao thủ ẩn trong tháp Quy Nhất tông trên Ngũ Hành tinh","tinhCach":"Ẩn mình không lộ diện; chỉ ra tay khi tình thế nguy cấp","tabs":{"diem":[{"text":"Ba thân ảnh từ ba tầng tháp đồng loạt lao ra phá trận, thực lực đủ phá Cửu Chuyển Tâm Luân đang nghịch chuyển","chuong":"@c1643"}],"kinhLich":[{"importance":"normal","mucCt":"gon","chuong":"@c1643","tieuDe":"Xuất thủ phá Cửu Chuyển Tâm Luân nghịch chuyển","text":"Từ tầng thứ bảy, sáu, năm của ngọn tháp trên Ngũ Hành tinh đồng loạt lao ra, vung tay áo cuốn tinh không phá vỡ trận pháp đang nghịch chuyển, giải cứu tu sĩ Quy Nhất tông.","anchor":"ba thân ảnh của ba lão già hóa thành cầu vồng gào thét lao ra"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{}},"nguon":["@c1643"]},{"id":"van-dat-phong","name":"Vân Dật Phong","cn":"云逸风","aliases":["Thanh niên hắc y"],"gioiTinh":"nam","theLuc":[{"ten":"Quy Nhất tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Đệ tử trung tâm đứng thứ ba của Quy Nhất tông trên Tiên Cương đại lục, trải qua vạn cổ trong động phủ giới gặp vô số cơ duyên, thực lực đủ tranh vị trí đệ nhất đệ tử. Từng xuất hiện trong thiên kiếp của Vương Lâm ở viễn cổ tiên vực.","vaiTro":"Đệ tử trung tâm thứ ba Quy Nhất tông Tiên Cương, đối thủ ngang sức Vương Lâm","tinhCach":"Trầm ổn; tự tin thâm hậu; không nao núng trước cường giả","tabs":{"diem":[{"text":"Đệ tử trung tâm thứ ba Quy Nhất tông, thực lực đủ tranh đệ nhất đệ tử, có thể vang danh tiên tộc trong cửu tông thập tam môn","chuong":"@c1644"},{"text":"Từng xuất hiện trong thiên kiếp Vương Lâm ở viễn cổ tiên vực, tìm kiếm thứ gì đó giữa các pho tượng Cổ Thần","chuong":"@c1644"},{"text":"Giao chiến ngang sức Vương Lâm cảnh Đạo Hư bằng Lục Hoa Ấn","chuong":"@c1644"},{"text":"Phân tích chính xác thiên đạo của Vương Lâm bị phân chia, không hoàn chỉnh, không thể nuốt được người tu vi cao thâm","chuong":"@c1646"},{"text":"Phân tích chính xác thiên đạo Vương Lâm không hoàn chỉnh, không thể nuốt người tu vi cao thâm, và suy đoán mục đích Vương Lâm đến Ngũ Hành tinh là bức lộ lực lượng ẩn giấu","chuong":"@c1646"},{"text":"Quân tử chân chính, không hề có mánh khoé trên thệ huyết — điều này vô tình cứu hắn thoát hoạ sát thân","chuong":"@c1676"},{"text":"Sở hữu thần thông Bát Đao Trảm Thần Hồn — phân thân bảy, bảy đao nối thành đao thứ tám khai thiên","chuong":"@c1676"}],"kinhLich":[{"mucCt":"ky","text":"Bước ra từ tầng thứ tư tháp cao Ngũ Hành tinh, chính là thanh niên Vương Lâm từng gặp trong thiên kiếp ở viễn cổ tiên vực. Thi triển Lục Hoa Ấn triệu sáu đóa hoa đen với sáu cánh tay trắng muốt, giao chiến ngang sức với Vương Lâm. Bị lực Đạo Cổ xâm nhập sinh ra hư ảnh Cổ Thần, Cổ Ma, Cổ Yêu cắn nuốt nguyên thần, phải dùng đan dược đen hóa giải nhưng chậm hơn Vương Lâm vài nhịp thở. Được hé lộ là đệ tử trung tâm thứ ba Quy Nhất tông Tiên Cương, trải vạn cổ trong động phủ giới, thực lực đủ tranh đệ nhất đệ tử.","anchor":"ở trong hàng đệ tử trung tâm đứng vị trí thứ ba","bridge":true,"khoang":"@c1644"},{"chuong":"@c1645","importance":"minor","mucCt":"vua","tieuDe":"Rút lui không can thiệp","text":"Nghe lời lão già trong tháp cao, nhíu mày nhìn Vương Lâm rồi thở dài bỏ đi, không hỏi tới chuyện này nữa. Nội tâm cuồng ngạo ăn sâu cốt tủy, coi việc dùng lời nhục mạ là hạ mình.","anchor":"thở dài một tiếng, thân thể uể oải rời đi, không hỏi tới chuyện này nữa"},{"chuong":"@c1646","importance":"normal","mucCt":"ky","tieuDe":"Phân tích thiên đạo và mục đích Vương Lâm","text":"Đứng bên cạnh lão già họ Mã trên Ngũ Hành tinh. Được hỏi ý kiến, phân tích thiên đạo đã bị phân chia nên Vương Lâm nắm giữ phần không hoàn chỉnh, không thể nuốt người tu vi cao thâm. Suy đoán Vương Lâm đến đây để bức lộ toàn bộ lực lượng ẩn giấu trước khi tìm kiếm hồn thứ ba, đánh giá đối phương là nhân vật đáng gờm. Khi Huyền La Đại Thiên Tôn xuất hiện, thần sắc đại biến, không dám cử động.","anchor":"Vãn bối không tin thiên đạo có thể nuốt được chúng ta"},{"importance":"normal","mucCt":"ky","chuong":"@c1647","tieuDe":"Bị uy áp Huyền La, thề trở thành Đại Thiên Tôn","text":"Dưới uy áp Huyền La Đại Thiên Tôn, kiên trì không quỳ cho đến khi phun máu mới sụp xuống. Được Huyền La khen kiên trì đáng nể nhưng tiếc không phải Đạo cổ nhất mạch. Sau khi Huyền La rời đi, nắm chặt tay thề sẽ trở thành Đại Thiên Tôn, mặt trời thứ mười một. Phân tích chính xác ý đồ Huyền La: đang khảo nghiệm Vương Lâm, muốn bọn họ làm hòn đá mài đao, nếu không tuân lệnh sẽ vĩnh viễn không rời được Ngũ Hành tinh.","anchor":"Sớm muộn gì cũng có ngày ta sẽ trở thành Đại Thiên Tôn, trở thành mặt trời thứ mười một!"},{"importance":"bridge","mucCt":"gon","chuong":"@c1655","tieuDe":"Tiến về La Thiên, muốn phân cao thấp với Vương Lâm","text":"Đi phía sau lão già họ Mã tiến về La Thiên, tuyên bố muốn quyết định cao thấp với Vương Lâm tại trung tâm động phủ giới.","anchor":"Vương Lâm, trận đánh giữa ngươi và ta còn chưa phân thắng bại"},{"importance":"bridge","mucCt":"gon","chuong":"@c1669","tieuDe":"Hoảng sợ trước cung Lý Quảng","text":"Bề ngoài bình tĩnh nhưng nội tâm hoảng sợ khi lần đầu chứng kiến cung Lý Quảng, tự thấy may mắn vì ở Ngũ Hành Tinh không bức Vương Lâm dùng cung, nhận định bản thân hoàn toàn không có khả năng chống cự.","anchor":"đối với cây cung này hắn không có một chút khả năng chống cự dù chỉ là một tiễn"},{"mucCt":"ky","text":"Cưỡi đài khổng lồ bao phủ cầu vồng đuổi theo Vương Lâm, tự xưng tên thách đấu đường đường chính chính, yêu cầu không dùng âm mưu quỷ kế và cây cung Lý Quảng. Đưa thệ huyết cam kết nếu thua sẽ nghe lệnh. Thi triển Bát Đao Trảm Thần Hồn phân thân bảy, bảy đao nối thành đao thứ tám, nhưng bị Vương Lâm dùng Tê Thiên Thuật đại thành phá tan hoàn toàn. Thừa nhận thua, thệ huyết hoá lời thề ràng buộc. Nhận lệnh Vương Lâm uống đan dược thi triển lại Bát Đao Trảm Thần Hồn tấn công Chưởng Tôn, được Đường San thi triển bảy kim môn phòng hộ lên người.","anchor":"Vân Dật Phong cũng là một quân tử, hắn không hề có mánh khoé gì ở trên thệ huyết này","bridge":true,"khoang":"@c1676"},{"mucCt":"vua","text":"Thi triển Bát Đao Trảm Thần Hồn Thuật phối hợp Đường San tấn công Chưởng Tôn, bảy đao bị phá nhưng đao thứ tám xông qua. Bị Chưởng Tôn đánh bại, bảy kim môn sụp đổ, phun máu bị thương nặng. Sau khi thấy Huyền La biến kim ấn thành pháp bảo thực chất, mắt hiện vẻ hoảng sợ rồi vội vàng cúi đầu — biểu cảm bị Vương Lâm nhìn thấy rõ.","anchor":"trong mắt hắn hiện lên vẻ hoảng sợ, lập tức nghĩ tới điều đó, vội vàng cúi đầu","bridge":true,"khoang":"@c1677"},{"mucCt":"vua","text":"Thi triển thần thông hóa con khỉ màu tím tấn công Chưởng Tôn, ác hầu theo thất khiếu nhập thể hắn. Sau đó thi triển thần thông mạnh nhất, phun máu rơi xuống đất.","anchor":"thần thông của Vân Dật Phong hóa thành thừa dịp Chưởng Tôn đang đối kháng","bridge":true,"khoang":"@c1678"},{"importance":"bridge","mucCt":"gon","chuong":"@c1679","text":"Bị lam quang kéo dung hợp góp sức phong ấn Chưởng Tôn, khi Dĩ Ti hiện hình lộ vẻ hoảng sợ.","anchor":"Ngay cả Vân Dật Phong kia cũng hít sâu, ánh mắt lộ ra vẻ hoảng sợ"},{"importance":"bridge","mucCt":"vua","chuong":"@c1680","tieuDe":"Nuốt đan dược chặn Chiến lão quỷ","text":"Cười khổ, nói Mã sư thúc cũng sẽ ra tay giúp Vương Lâm trì hoãn. Nuốt đan dược, tay phải chụp hư không hình thành áo giáp ngũ hành quang, ở lại chặn Chiến lão quỷ.","anchor":"xuất ra một nắm lớn đan dược, nuốt lấy, tay phải giơ lên chụp vào khoảng không một cái"},{"importance":"bridge","mucCt":"gon","chuong":"@c1681","text":"Bị Chiến lão quỷ phất tay, thương thế bộc phát suýt mất mạng, hai mắt nhắm nghiền bất động.","anchor":"Vân Dật Phong sắc mặt xám như tro tàn, hai mắt nhắm nghiền không nhúc nhích"},{"chuong":"@c1690","importance":"bridge","mucCt":"gon","tieuDe":"","text":"Thân ảnh huyễn hóa ra khi thế giới sụp đổ, ánh mắt phức tạp nhìn Vương Lâm phong ấn lưỡng hồn Thất Thải.","anchor":"Bọn họ thật không ngờ Vương Lâm này lại còn một chiêu như vậy."},{"mucCt":"vua","text":"Nội tâm phức tạp, không phân biệt Tiên Cương hay Ngũ Hành Tinh là nhà. Lưu luyến nhìn bốn phía, ôm quyền hẹn Vương Lâm phân thắng bại ở Tiên Cương đại lục rồi bay vào kim môn.","anchor":"Vương huynh, bảo trọng! Trận đánh của ngươi và ta còn chưa chấm dứt, ở Tiên Cương đại lục hẹn sẽ phân thắng bại","bridge":true,"khoang":"@c1691"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ ngang sức","ghiChu":"Giao chiến ngang tay tại Ngũ Hành tinh"},{"ten":"Lão già tóc bạc tầng ba","tag":"cap-tren","quanHe":"Cấp trên trên Ngũ Hành tinh, được lão hỏi ý kiến phân tích"},{"ten":"Lão già họ Mã","tag":"cap-tren","quanHe":"Cấp trên / cường giả cùng phe trên Ngũ Hành tinh","ghiChu":"Đứng bên cạnh lão phân tích tình hình khi được hỏi ý kiến"},{"ten":"Chưởng Tôn","tag":"doi-thu","quanHe":"Đối thủ, nhận lệnh Vương Lâm tấn công","ghiChu":"Thi triển Bát Đao Trảm Thần Hồn nhằm vào Chưởng Tôn"}],"tuiDo":{"phapBao":[],"danDuoc":[{"ten":"Đan dược màu đen","moTa":"Dùng để hóa giải lực Đạo Cổ xâm nhập nguyên thần, tốc độ chậm hơn Đạo Cổ bất diệt thể","nguon":"@c1644"}],"congPhap":[{"ten":"Lục Hoa Ấn","moTa":"Ấn quyết triệu sáu đóa hoa đen và sáu cánh tay, giao chiến ngang sức Vương Lâm","nguon":"@c1644"}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1644","@c1645","@c1646","@c1647","@c1655","@c1669","@c1676","@c1677","@c1678","@c1679","@c1680","@c1681","@c1690","@c1691"]},{"id":"lao-gia-kim-bao","name":"Lão già kim bào","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Quy Nhất tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Tu sĩ Quy Nhất tông trên Ngũ Hành tinh, bị thương nặng trong nghịch động Cửu Chuyển Tâm Luân, gẫy tay đầy máu đen. Khi nghe Vương Lâm nói thì thần sắc đại biến, khóe miệng tràn máu tươi.","vaiTro":"Tu sĩ Quy Nhất tông Ngũ Hành tinh, bị thương nặng","tinhCach":"Không rõ","tabs":{"diem":[{"text":"Bị thương nặng trong nghịch động Cửu Chuyển Tâm Luân, gẫy tay đầy máu đen, khi nghe Vương Lâm nói thì thần sắc đại biến thổ huyết","chuong":"@c1644"}],"kinhLich":[{"chuong":"@c1644","importance":"bridge","mucCt":"vua","text":"Đã bị thương nặng sau nghịch động Cửu Chuyển Tâm Luân, gẫy tay đầy máu đen. Khi nghe Vương Lâm nói thần sắc đại biến, khóe miệng tràn máu tươi.","anchor":"thần sắc lão già kim bào bỗng nhiên đại biến"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối phương","ghiChu":"Bị Vương Lâm khiêu chiến, thổ huyết khi nghe lời"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1644"]},{"id":"ba-nam-tu-trung-nien-tien-cuong","name":"Ba nam tử trung niên Tiên Cương","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Quy Nhất tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Ba tu sĩ cổ đại từ Tiên Cương đại lục, tồn tại vô số năm trong tháp Ngũ Hành tinh, khí tức tang thương. Nhận ra Vương Lâm thuộc Đạo Cổ nhất mạch, đồng loạt ra tay nhưng bị lực trùng kích đẩy lui.","vaiTro":"Tu sĩ cổ đại Quy Nhất tông Tiên Cương ẩn trong tháp Ngũ Hành tinh","tinhCach":"Không rõ","tabs":{"diem":[{"text":"Ba người đồng loạt ra tay: một hóa cự long chín màu, một hóa quỷ ảnh khổng lồ, một thi triển Ngũ Hành — nhưng đều bị lực trùng kích từ hư ảnh Đạo Cổ sụp đổ đẩy lui","chuong":"@c1644"}],"kinhLich":[{"mucCt":"vua","text":"Nhận ra Vương Lâm thuộc Đạo Cổ nhất mạch, ba người đồng loạt ra tay — một hóa cự long chín màu, một hóa quỷ ảnh khổng lồ, một thi triển Ngũ Hành. Bị lực trùng kích từ hư ảnh Đạo Cổ sụp đổ đẩy lui mấy trăm trượng, không kịp ngăn Vương Lâm phá tháp.","anchor":"Ba người đồng thời cất bước, lao thẳng tới Vương Lâm","bridge":true,"khoang":"@c1644"},{"chuong":"@c1646","importance":"normal","mucCt":"gon","tieuDe":"Bị uy áp Đại Thiên Tôn đánh bật","text":"Bị uy áp Huyền La Đại Thiên Tôn khiến phun máu tươi, bật bay.","anchor":"Mới vừa rồi các ngươi dám nói Đạo cổ nhất mạch đều là đám người hoang dã sao"},{"mucCt":"vua","text":"Xuất hiện dưới dạng hư ảo ngồi khoanh chân đối diện Bạch Hổ chiến tướng trên bầu trời, thần sắc bối rối, trán đầy mồ hôi. Hóa thân thế tục là binh lính thiết giáp tàn phá phía đối địch. Mong thêm người đến để cùng giết Bạch Hổ chiến tướng.","anchor":"Đến đây đi, nhiều thêm vài người nói không chừng có thể g**t ch*t Bạch Hổ chiến tướng này!","bridge":true,"khoang":"@c1661"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối phương","ghiChu":"Bị Vương Lâm đánh lui bằng lực trùng kích hư ảnh Đạo Cổ"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1644","@c1646","@c1661"]},{"id":"lao-gia-tang-thu-ba","name":"Lão già tầng thứ ba","cn":"","aliases":["Lão già tầng ba","Lão già họ Mã","Mã Lương"],"gioiTinh":"nam","theLuc":[{"ten":"Quy Nhất tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ (mạnh hơn Chưởng Tôn, đã trải qua mấy lần huyền kiếp)","trangThai":"song","blurb":"Cường giả ẩn trong ba tầng tháp gốc từ Tiên Cương, chưa lộ diện, chỉ phát ra giọng nói già nua uy nghiêm. Tự tin sỉ nhục Đạo Cổ nhất mạch là nhánh yếu nhất, gọi cả sư tôn Vương Lâm là đám tu sĩ thế tục hoang dã. Lời nói hóa thành pháp tắc, uy thế cực mạnh.","vaiTro":"Cường giả ẩn trong tháp gốc Ngũ Hành tinh, sỉ nhục Đạo Cổ nhất mạch","tinhCach":"Uy nghiêm; cao ngạo; coi thường Đạo Cổ nhất mạch","tabs":{"diem":[{"text":"Giọng nói uy nghiêm như sấm dậy, lời nói hóa thành pháp tắc — cho thấy thực lực cực kỳ mạnh","chuong":"@c1644"},{"text":"Sỉ nhục cả Đạo Cổ nhất mạch mà không biết Huyền La Đại Thiên Tôn đang nghe","chuong":"@c1644"},{"text":"Tinh thông mộc và thổ Ngũ Hành, dùng roi xanh biếc hấp thu sinh cơ cây cỏ bổ sung bổn nguyên làm vũ khí","chuong":"@c1645"},{"text":"Khoác áo giáp Quy Nhất tông (mộc + thổ) tu vi tăng vọt nhưng chịu phản phệ nhánh cây chui vào da thịt","chuong":"@c1645"}],"kinhLich":[{"mucCt":"vua","text":"Sau khi tháp bị Vương Lâm phá sập bốn tầng dưới, từ ba tầng gốc còn lại phát ra giọng nói già nua uy nghiêm, gọi Vương Lâm là tiểu bối hoang dã Đạo Cổ, sỉ nhục cả Đạo Cổ nhất mạch là nhánh yếu nhất, kể cả sư tôn Vương Lâm tới cũng chỉ là đám tu sĩ thế tục hỗn tạp hoang dã.","anchor":"Tiểu bối hoang dã Đạo cổ, ngươi là người của nhánh yếu nhất trong Đạo cổ nhất mạch","bridge":true,"khoang":"@c1644"}],"tuViMoc":[{"chuong":"@c1645","canhGioi":"Không Huyền trung kỳ bước ba","text":"Tu vi gốc Không Huyền trung kỳ bước ba, khoác áo giáp Quy Nhất tông tăng lên Không Huyền hậu kỳ đỉnh phong.","importance":"minor"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối phương","ghiChu":"Sỉ nhục Vương Lâm và Đạo Cổ nhất mạch"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1644","@c1645","@c1646"]},{"id":"lao-gia-mac-song-hanh-khai","name":"Lão già mặc song hành khải","aliases":["Lão già mất áo giáp"],"trangThai":"tu-vong","tabs":{"kinhLich":[{"chuong":"@c1636","importance":"normal","mucCt":"vua","tieuDe":"Thỉnh tiên tổ chiến giáp, chuẩn bị dùng thủy trận bức Vương Lâm","text":"Thỉnh tiên tổ chiến giáp — bộ áo giáp xanh nước biển lan sóng nước xuất hiện trên thân, triệu hồi thanh trường thương sóng nước. Tuyên bố dùng Ngũ Hành thủy trận bức Vương Lâm ra khỏi trận pháp tiến vào cửu chuyển, nhờ Nạp Đa áp trận rồi hóa hơi nước tiêu tán.","anchor":"Trận tiếp theo là Ngũ Hành thủy trận. Ta sẽ thử xem có thể bức hắn ra khỏi trận pháp, trực tiếp tiến vào cửu chuyển hay không."},{"chuong":"@c1646","importance":"normal","mucCt":"vua","tieuDe":"Bị Huyền La Đại Thiên Tôn bóp cổ, phá nát giáp","text":"Cung kính đứng im khi lão già họ Mã trầm ngâm. Bị Huyền La Đại Thiên Tôn bóp cổ, bộ song hành giáp trên người bị phá nát vỡ vụn như tờ giấy vì trước đó đã nói bất kính về Đạo cổ nhất mạch.","anchor":"Song hành giáp cường hãn trên người lão già này yếu ớt giống như một tờ giấy, ầm ầm vỡ vụn"},{"importance":"normal","mucCt":"gon","chuong":"@c1647","tieuDe":"Bị Huyền La Đại Thiên Tôn giết chết","text":"Bị Huyền La Đại Thiên Tôn vuốt tay giết chết, hóa thành máu huyết tiêu tán.","anchor":"Lão già đã mất đi áo giáp lúc này hóa thành một đám máu huyết tiêu tán trong tay Huyền La Đại Thiên Tôn"}],"nhanMach":[],"tuViMoc":[]},"nguon":["@c1646","@c1647","@c1636"],"gioiTinh":"nam"},{"id":"ma-luong","name":"Mã Lương","aliases":["Lão già họ Mã","Lão già tóc bạc tầng ba"],"gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1646","importance":"major","mucCt":"ky","tieuDe":"Huyền La Đại Thiên Tôn giáng lâm, Mã Lương hoảng sợ","text":"Sau khi Vương Lâm rời đi, sắc mặt âm trầm nhìn bầu trời, do dự muốn đuổi theo nhưng kiêng dè. Nghe Vân Dật Phong phân tích thiên đạo của Vương Lâm không hoàn chỉnh, không thể nuốt được người tu vi cao thâm, đồng ý đối phương có chuẩn bị khác. Đang muốn quay về tháp cao thì Huyền La Đại Thiên Tôn giáng lâm Ngũ Hành tinh — run rẩy nhận ra danh tính đối phương, phun máu tươi, sợ hãi ngập trời.","anchor":"Lão già họ Mã phun một ngụm máu tươi, thân thể lảo đảo lùi lại phía sau, sự sợ hãi trong mắt đã trở nên ngập trời"},{"mucCt":"vua","text":"Không chống nổi uy áp Huyền La Đại Thiên Tôn, quỳ gối bỏ cuộc. Phân tích rằng Diệp Mịch năm đó tử vong trong động phủ giới, ba nghìn máu tươi hóa thành tam tộc cổ, Vương Lâm đạt truyền thừa Diệp Mịch nên Huyền La mới chú ý. Nhận định kế hoạch Quy Nhất tông ở Ngũ Hành tinh đã thất bại hoàn toàn.","anchor":"Kết hợp với chuyện Diệp Mịch năm đó tử vong sau khi tiến vào động phủ giới, ba nghìn máu tươi hóa thành tam tộc cổ","bridge":true,"khoang":"@c1647"},{"importance":"bridge","mucCt":"gon","chuong":"@c1655","tieuDe":"Dẫn nhóm Ngũ Hành tinh tiến về La Thiên","text":"Cầm đầu nhóm người trên Ngũ Hành tinh ẩn thế, do dự rồi thầm than, dẫn đầu tiến về La Thiên.","anchor":"dưới sự cầm đầu của lão già họ Mã, đám người này sau khi do dự một chút liền thầm than"},{"importance":"bridge","mucCt":"gon","chuong":"@c1656","text":"Cầm đầu đám người Ngũ Hành tinh xuất hiện cuối cùng trước đại môn, khiến mọi người chấn động.","anchor":"đám người Ngũ Hành tinh do lão già họ Mã cầm đầu"},{"importance":"bridge","mucCt":"gon","chuong":"@c1657","text":"Cầm đầu nhóm người Ngũ Hành tinh, là nhóm cuối cùng miễn cưỡng tiến vào đại môn.","anchor":"Người Ngũ Hành tinh do lão già họ Mã cầm đầu"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{}},"nguon":["@c1647","@c1655","@c1656","@c1657","@c1646"]},{"id":"ly-mo-uyen","name":"Lý Mộ Uyển","gioiTinh":"nu","trangThai":"song","tabs":{"kinhLich":[{"mucCt":"ky","text":"Nằm hôn mê trong Tỵ Thiên Quan trên tiên giới, được Vương Lâm mở nắp vuốt ve khuôn mặt, nước mắt hắn rơi ướt y phục. Vương Lâm xác nhận một phần hồn phách của nàng đã bị mất, trong thiên kiếp cũng không tìm được, thề sẽ thu hồi bằng mọi giá. Trong mộng ảo tái hiện lần gặp gỡ đầu tiên hơn hai ngàn năm trước ở hải ngoại: nàng bị trưởng lão Tuyên Vũ Viên đuổi giết, tiểu đội mười ba người đều chết, y sam bị xé, nàng cầu cứu Vương Lâm và tiết lộ có Thiên Ly Đan để hắn có lý do ra tay. Sau khi được cứu, nàng sợ hãi trước sức mạnh áp đảo, lui hơn trăm trượng cúi đầu tạ ơn rồi rời đi.","anchor":"Một phần hồn phách của nàng đã bị mất.trong thiên kiếp cũng không","bridge":true,"khoang":"@c1648"},{"importance":"bridge","mucCt":"vua","chuong":"@c1649","tieuDe":"Say ngủ trong Tỵ Thiên Quan","text":"Đang say ngủ trong Tỵ Thiên Quan suốt đêm trăng, được Vương Lâm giữ bên cạnh, sáng sớm Vương Lâm thì thầm rồi thu Tỵ Thiên Quan lại.","anchor":"Tỵ Thiên Quan hóa thành một đám u quang tiêu tán trước mặt hắn, bị hắn trân trọng thu lại"},{"importance":"bridge","mucCt":"gon","chuong":"@c1691","tieuDe":"Được Vương Lâm hứa đánh thức ở Tiên Cương","text":"Được Vương Lâm nhớ tới khi nhìn kim môn, hứa sẽ khiến nàng thức tỉnh ở Tiên Cương đại lục.","anchor":"Uyển nhi, cánh cửa do đã bị ta mở ra rồi. Ở nơi đó ta sẽ có thể khiến nàng thức tỉnh"},{"chuong":"@c1692","importance":"major","mucCt":"vua","tieuDe":"Hồn không hoàn chỉnh, năm phần mười cơ hội sống","text":"Huyền La tiết lộ hồn nàng không hoàn chỉnh, một phần đã biến mất không dấu vết, không thể chuyển thế đầu thai. Chỉ có năm phần mười cơ hội được Vương Lâm mang trực tiếp tới Tiên Cương đại lục, thất bại thì cả hai tử vong.","anchor":"Có điều rất kỳ quái đó là hồn của nàng không hoàn chỉnh, có một phần đã biến mất"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1648","@c1649","@c1691","@c1692"],"cn":"李慕婉","aliases":["Uyển Nhi"]},{"id":"ly-thien-mai","name":"Lý Thiến Mai","gioiTinh":"nu","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1648","importance":"bridge","mucCt":"gon","text":"Được Vương Lâm nhắc đến trong lúc độc thoại bên Lý Mộ Uyển, xác nhận hắn đã tiếp nhận nàng nhưng mang cảm giác tội lỗi.","anchor":"Uyển Nhi, ta đã tiếp nhận Lý Thiến Mai rồi, xin lỗi nàng"},{"importance":"bridge","mucCt":"vua","chuong":"@c1649","tieuDe":"Lặng lẽ quan sát Vương Lâm rồi rời đi","text":"Cùng phụ thân đứng trên ngọn núi xa quan sát Vương Lâm bên Lý Mộ Uyển trong đêm trăng, quay người dần đi xa, bóng lưng cô độc.","anchor":"Thân ảnh nữ tử kia lại càng như thế"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1648","@c1649"]},{"id":"truong-lao-tuyen-vu-vien","name":"Trưởng lão Tuyên Vũ Viên","aliases":["Nam tử dâm tà trong mộng ảo"],"gioiTinh":"nam","trangThai":"tu-vong","vaiTro":"Trưởng lão Tuyên Vũ Viên song tu môn, bị Vương Lâm giết trong quá khứ khi đuổi giết Lý Mộ Uyển","tinhCach":"Dâm tà, tàn nhẫn, giết cả tiểu đội mười ba người để cướp Thiên Ly Đan","blurb":"Trưởng lão của Tuyên Vũ Viên song tu môn, mặt mày trắng trẻo vẻ dâm tà. Đuổi giết Lý Mộ Uyển hơn hai ngàn năm trước ở hải ngoại, giết cả tiểu đội mười ba người và xé y sam nàng để cướp Thiên Ly Đan, bị Vương Lâm chỉ liếc mắt phá tan phi kiếm rồi vỡ tung mà chết.","theLuc":[{"ten":"Tuyên Vũ Viên","trangThai":"gan-bo"}],"tabs":{"diem":[{"text":"Trưởng lão dâm tà đuổi giết Lý Mộ Uyển vì Thiên Ly Đan, bị Vương Lâm giết chỉ bằng một cái liếc mắt","chuong":"@c1648"}],"kinhLich":[{"chuong":"@c1648","importance":"normal","mucCt":"gon","tieuDe":"Đuổi giết Lý Mộ Uyển, bị Vương Lâm giết","text":"Trong mộng ảo tái hiện quá khứ: đuổi giết Lý Mộ Uyển sau khi giết cả tiểu đội mười ba người và xé y sam nàng vì biết nàng có Thiên Ly Đan. Thi triển tám thanh phi kiếm tấn công Vương Lâm nhưng bị hắn liếc mắt phá tan, phun máu rồi bị lực vô hình cuốn vỡ tung chết.","anchor":"mặt mày trắng trẻo, vẻ mặt dâm tà, không nhanh không chậm đuổi theo nữ tử này"}],"tuViMoc":[],"nhanMach":[{"ten":"Lý Mộ Uyển","tag":"doi-thu","quanHe":"Mục tiêu truy sát vì Thiên Ly Đan"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị Vương Lâm giết khi đang đuổi giết Lý Mộ Uyển"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1648"]},{"id":"thanh-thuy","name":"Thanh Thủy","aliases":["Triệu Thanh Thủy"],"tabs":{"kinhLich":[{"mucCt":"ky","text":"Đang dạy Hồng Điệp tu luyện trong sơn cốc phía bắc tiên giới, cảm ứng thần thức Vương Lâm lập tức tới gặp. Chủ động thừa nhận biết bản thân là do một phách của Thất Thải Tiên Tôn biến thành, nói đã tìm được đáp án ở Thất Thải Giới nhưng trước đây không muốn thừa nhận nên không mở miệng. Khoanh chân ngồi trước Vương Lâm, nói động thủ đi, toàn lực hỗ trợ. Bị Hồn Phiên mặt quỷ cắn nuốt cùng Vương Lâm, thần thức tiến vào thời vạn cổ truy tìm hồn thứ ba.","anchor":"Ta biết bản thân là do một phách biến thành.tha lỗi cho ta đã không nói chuyện này với ngươi","bridge":true,"khoang":"@c1649"},{"chuong":"@c1650","importance":"normal","mucCt":"ky","tieuDe":"Được xác nhận là phách thứ nhất của Thất Thải Tiên Tôn","text":"Trong huyễn cảnh tầng một, tái hiện cảnh năm xưa Thanh Thủy tàn sát hoàng cung phàm gian đã hại gia đình hắn, giết lão già mặc hoàng bào, phóng hồng quang từ đôi mắt tiêu diệt mấy trăm tu sĩ thượng cổ. Sau khi đại cừu đã báo, hắn không hề sung sướng, nhắm mắt rơi nước mắt, sát khí tiêu tán. Được Vương Lâm an ủi, cùng chuyển sang tầng hai. Được xác nhận chính là phách thứ nhất (đỏ đậm) của Thất Thải Tiên Tôn, phách chủ sát, ẩn chứa sát lục cả đời.","anchor":"Thân ảnh đó đúng là Thanh Thủy"},{"chuong":"@c1652","importance":"normal","mucCt":"gon","tieuDe":"Tỉnh lại cùng Vương Lâm trong động phủ giới","text":"Ở tầng huyễn cảnh thứ nhất, mở mắt nhìn Vương Lâm thở dài. Sau ba bước lùi của Vương Lâm, huyễn cảnh sụp đổ hoàn toàn, cả hai đồng thời tỉnh lại trong động phủ giới trên đỉnh núi.","anchor":"Thanh Thủy mở đôi mắt, nhìn Vương Lâm, than nhẹ một tiếng."},{"importance":"bridge","mucCt":"vua","chuong":"@c1653","tieuDe":"Rời đi sau khi biết thân phận hồn thứ ba","text":"Đứng dậy nhìn Vương Lâm, biết thân phận hồn thứ ba và mối liên hệ với hắn, thầm than rồi cất bước rời đi. Được Vương Lâm liệt kê là một trong sáu phách đã biết, thuộc nhóm chưa xảy ra biến số, chưa hoàn toàn tách biệt khỏi Thất Thải Tiên Tôn.","anchor":"Còn Thanh Thủy và Tư Đồ Nam thì lại không có xảy ra biến số này"},{"importance":"bridge","mucCt":"vua","chuong":"@c1655","tieuDe":"Cảm nhận tiếng gọi, Lam Mộng muốn mượn hồn phách","text":"Trong tiên giới, đứng bên ngoài căn nhà nhìn bầu trời mờ đục, tâm thần cảm thấy tiếng kêu gọi xúc động. Nhận được truyền âm từ Lam Mộng Đạo Tôn muốn mượn hồn phách.","anchor":"Trong tâm thần hắn hình như có tiếng kêu gọi"},{"importance":"bridge","mucCt":"gon","chuong":"@c1657","text":"Cùng Tư Đồ Nam ở tiên giới trầm mặc chú ý, hiểu rằng nếu được như lời Vương Lâm thì kết thúc hoàn mỹ.","anchor":"Một số ít người biết được bí ẩn như Tư Đồ Nam và Thanh Thủy thì ở trong tiên giới trầm mặc"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{}},"nguon":["@c1649","@c1650","@c1652","@c1653","@c1655","@c1657"],"trangThai":"song"},{"id":"tu-dai-chien-tuong","name":"Tứ đại chiến tướng","tabs":{"kinhLich":[{"mucCt":"gon","text":"Kết trận pháp trong Vân Hải tinh vực, dùng hồ lô phun sương mù tạo Vụ thú truy tìm hồn thứ ba, hủy diệt toàn bộ sinh mạng trên đại lục hoang phế để Vụ thú hấp thu khí tức luân hồi, xác nhận hồn thứ ba từng luân hồi tại đây rồi tiến sang La Thiên.","anchor":"Nơi này tuy rằng không phải nhưng có thể khiến cho Vụ thú của tiên tôn dừng lại hấp thu thì hiển nhiên là hồn thứ ba của tiên tôn đại nhân đã từng ở nơi này luân hồi","bridge":true,"khoang":"@c1649"},{"importance":"bridge","mucCt":"gon","chuong":"@c1653","text":"Gào thét lao đi trong La Thiên Tinh Vực, theo Vụ thú tìm kiếm mục tiêu.","anchor":"tứ đại chiến tướng gào thét lao đi. Phía trước bọn họ là Vụ thú không ngừng ngẩng cái đầu khổng lồ"},{"importance":"bridge","mucCt":"vua","chuong":"@c1655","tieuDe":"Điên cuồng lao về phía trung tâm động phủ","text":"Đã ở La Thiên Tinh Vực, hoảng sợ phát hiện có người tìm được hồn thứ ba trước mình, điên cuồng lao về phía khí tức động phủ mở ra.","anchor":"Bọn họ cho rằng tốc độ tìm kiếm của mình là nhanh nhất nhưng giờ phút này lại hoảng sợ phát hiện ra"},{"importance":"bridge","mucCt":"gon","chuong":"@c1656","text":"Xuất hiện đồng loạt trước đại môn, bị cơn lốc đẩy lui, nhận ra hồn thứ ba đã bị Vương Lâm lấy và hắn đang bị bao vây.","anchor":"bốn người bọn họ sau khi xuất hiện liền lập tức bị lực lượng của cơn lốc đẩy bật về phía sau"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{}},"nguon":["@c1649","@c1653","@c1655","@c1656"]},{"id":"hong-diep","name":"Hồng Điệp","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1649","tieuDe":"Tu luyện cùng Thanh Thủy trong sơn cốc","text":"Đang tu luyện trong sơn cốc phía bắc tiên giới cùng Thanh Thủy, nhờ thiên tư bất phàm liền lĩnh ngộ lời chỉ điểm, nhìn theo hướng phụ thân biến mất với ánh mắt lo lắng.","anchor":"Hồng Điệp vốn thiên tư bất phàm, nghe xong liền hiểu ra rất nhiều"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{}},"nguon":["@c1649"]},{"id":"thanh-lam","name":"Thanh Lâm","nguon":["@c1650","@c1653"],"tabs":{"kinhLich":[{"chuong":"@c1650","importance":"normal","mucCt":"ky","tieuDe":"Được xác nhận là phách thứ ba của Thất Thải Tiên Tôn","text":"Được xác nhận chính là phách thứ ba (cam) của Thất Thải Tiên Tôn, phách chứa chính khí và lương tri. Giải thích vì sao Thanh Lâm cả đời bảo vệ Vũ tiên giới bất chấp bị Chưởng Tôn dụ hoặc và trọng thương.","anchor":"Trong nháy mắt khi phách này tiến vào luân hồi, Vương Lâm nhìn thấy thân ảnh bên trong chính là Thanh Lâm"},{"importance":"bridge","mucCt":"gon","chuong":"@c1653","text":"Được liệt kê là phách thứ tư trong sáu phách đã biết, thuộc nhóm đã xảy ra biến số, tách biệt khỏi Thất Thải Tiên Tôn.","anchor":"Thanh Thủy cũng vậy, Tham Lang cũng thế, cho dù là Mộc Băng Mi, Tán Linh thượng nhân"}]}},{"id":"tham-lang","name":"Tham Lang","nguon":["@c1650","@c1653","@c1684"],"tabs":{"kinhLich":[{"chuong":"@c1650","importance":"normal","mucCt":"ky","tieuDe":"Được xác nhận là phách thứ tư của Thất Thải Tiên Tôn","text":"Được xác nhận chính là phách thứ tư (vàng) của Thất Thải Tiên Tôn, phách đại biểu khí vận và cơ duyên cả đời. Người mang phách này vận khí kinh thiên, được thiên địa ủng hộ, pháp bảo tự giáng xuống.","anchor":"Trong nháy mắt khi phách này tiến vào luân hồi, Vương Lâm mơ hồ nhìn thấy thân ảnh của Tham Lang"},{"importance":"bridge","mucCt":"gon","chuong":"@c1653","text":"Được liệt kê là một trong sáu phách đã biết, thuộc nhóm bốn người đã xảy ra biến số, hoàn toàn tách biệt khỏi Thất Thải Tiên Tôn, trở thành chúng sinh thật sự.","anchor":"Thanh Thủy cũng vậy, Tham Lang cũng thế, cho dù là Mộc Băng Mi, Tán Linh thượng nhân"},{"importance":"bridge","mucCt":"gon","chuong":"@c1684","tieuDe":"","text":"Được nhắc tới: hình dạng Vương Lâm hóa thành trong đệ ngũ hoa giống pho tượng bảy màu lấy được từ Tham Lang.","anchor":"pho tượng bảy màu mà Vương Lâm lấy được từ Tham Lang"}],"nhanMach":[],"tuViMoc":[]},"gioiTinh":"nam"},{"id":"lien-dao-phi","name":"Liên Đạo Phi","nguon":["@c1650","@c1670","@c1671","@c1685"],"tabs":{"kinhLich":[{"chuong":"@c1650","importance":"bridge","mucCt":"gon","text":"Trong huyễn cảnh tầng hai, gầm rống khiến thiên đạo trọng thương sụp đổ, đồng thời oanh kích khiến Thất Thải Tiên Tôn vỡ nát.","anchor":"Liên Đạo Phi gầm rống, thiên đạo trọng thương sụp đổ, chia lìa tiêu tán"},{"chuong":"@c1670","importance":"normal","mucCt":"ky","tieuDe":"Bị triệu hồi ra trận, gây chấn động toàn trường","text":"Bị Vương Lâm triệu hồi từ không gian trữ vật ra giữa trận, đang ngủ say mặc quần áo lôi thôi. Có tiên nhân bất diệt thể hoàn chỉnh, sức mạnh hủy diệt lao vào mà lông tóc không hư tổn, chắn phần lớn lực hủy diệt cho Vương Lâm. Nửa tỉnh nửa mê phẫn nộ gào thét sẽ mách với ca ca rồi lại ngủ tiếp. Sự xuất hiện khiến đạo nhân bảy màu bỏ chạy, Chưởng Tôn suýt quỳ sụp gọi chủ nhân, Huyền Vũ và Chu Tước khiếp sợ, lão già họ Mã run rẩy kinh hoàng. Được Huyền La Đại Thiên Tôn nhận ra là đệ đệ của Liên Đạo Chân.","anchor":"người điên mặc quần áo lôi thôi, đang ngủ say ngáy khò khò bị hai tay Vương Lâm túm lấy trực tiếp xuất hiện ở phía trước hắn"},{"importance":"bridge","mucCt":"gon","chuong":"@c1671","tieuDe":"Chống đỡ lực hủy diệt rồi ngủ say","text":"Chống đỡ lực hủy diệt ba trăm giới sụp đổ khiến suy yếu quá nửa, sau đó lăn ra ngủ khò khò, được Vương Lâm dẫn theo thoát thân.","anchor":"Có người điên chống đỡ, Vương Lâm"},{"chuong":"@c1685","importance":"normal","tieuDe":"Xuất quan truyền thụ Vân Đạo Thiên Thuật","text":"Xuất quan sau thời gian dài bế quan, xuất hiện từ dòng xoáy khói xanh trong tiếng chuông thứ ba, được gần trăm tu sĩ Đông Lâm Tông cung nghênh. Gọi Tô Đạo và Chu Lập vào đại điện, truyền thụ khẩu quyết nhập môn Vân Đạo Thiên Thuật để hai người thi tuyển. Tuyên bố Tô Đạo (Vương Lâm) có tư cách học Vân Đạo Thiên Thuật, truyền Thất Thải Tiên Thuật cho Chu Lập. Dặn Tô Đạo tu luyện chuẩn bị cho cuộc thi đấu Đông Lâm Tông năm tháng sau.","anchor":"Tô Đạo, từ nay về sau ngươi chính là đệ tử thuộc hệ của vi sư, là người có tư cách học tập Vân Đạo Thiên Thuật này!","mucCt":"vua"}],"nhanMach":[{"ten":"Thất Thải Tiên Tôn","tag":"su-mon","quanHe":"Đệ tử, được truyền Vân Đạo Thiên Thuật (sau nghịch chuyển)","ghiChu":"Đối đãi tốt với Tô Đạo nhưng thường xuyên bế quan nên không biết Tô Đạo bị đối xử bất công"},{"ten":"Chu Lập","tag":"su-mon","quanHe":"Đệ tử, đại sư huynh Đông Lâm Tông","ghiChu":"Nhận Thất Thải Tiên Thuật sau nghịch chuyển"},{"ten":"Tô Đạo","tag":"su-mon","quanHe":"Đệ tử, được chọn làm truyền nhân chính hệ Vân Đạo Thiên Thuật","ghiChu":""},{"ten":"Vương Lâm","tag":"su-mon","quanHe":"Đệ tử (danh phận Tô Đạo)","ghiChu":"Chọn Tô Đạo làm người học Vân Đạo Thiên Thuật"}],"tuViMoc":[],"diem":[{"text":"Thường xuyên bế quan khiến Tô Đạo bị đãi ngộ bất công mà không biết. Chọn truyền nhân Vân Đạo Thiên Thuật dựa trên thực lực, công nhận Tô Đạo sau khi Vương Lâm nghịch chuyển.","chuong":"@c1685"}]},"trangThai":"song","aliases":["người điên","A Ngốc","Sư tôn Đông Lâm Tông"],"gioiTinh":"nam","canhGioiCaoNhat":"khong-ro","vaiTro":"Sư tôn Đông Lâm Tông, người nắm giữ và truyền thụ tam đại tối cường thần thông","tinhCach":[{"text":"Đối đãi tốt với đệ tử nhưng thường bế quan, không hay biết chuyện bất công trong tông phái"}],"blurb":"Sư tôn của Tô Đạo và Chu Lập tại Đông Lâm Tông, nam tử trung niên tóc đen bù xù, tiên phong đạo cốt. Thường xuyên bế quan, xuất quan truyền thụ Vân Đạo Thiên Thuật và chọn truyền nhân.","cn":"连道非","theLuc":[{"ten":"Đông Lâm Tông","trangThai":"gan-bo"}]},{"id":"moc-bang-mi","name":"Mộc Băng Mi","tabs":{"kinhLich":[{"importance":"normal","mucCt":"ky","chuong":"@c1651","tieuDe":"Hé lộ nguồn gốc từ phách thứ sáu Thất Thải Tiên Tôn","text":"Được Vương Lâm nhận ra chính là thân ảnh trong phách thứ sáu (màu lam) của Thất Thải Tiên Tôn — phách do tình cảm yêu hận đối với Phàn San Mộng hóa thành nữ tử. Nàng qua vô số lần luân hồi đều lần lượt thay đổi giữa ôn nhu và lạnh lùng, tình cảm Vương Lâm dành cho nàng vô cùng phức tạp. Sắc mặt Vương Lâm tái nhợt khi nhận ra.","anchor":"Sắc mặt Vương Lâm tái nhợt. Hắn nhận ra thân ảnh mơ hồ đó là ai."},{"importance":"bridge","mucCt":"gon","chuong":"@c1653","text":"Được liệt kê là phách thứ năm trong sáu phách đã biết, thuộc nhóm đã xảy ra biến số.","anchor":"Thanh Thủy cũng vậy, Tham Lang cũng thế, cho dù là Mộc Băng Mi, Tán Linh thượng nhân"}]},"nguon":["@c1651","@c1653"]},{"id":"phan-san-mong","name":"Phàn San Mộng","tabs":{"kinhLich":[{"importance":"normal","mucCt":"vua","chuong":"@c1651","tieuDe":"Hé lộ là đạo lữ duy nhất của Thất Thải Tiên Tôn","text":"Được xác nhận là đạo lữ duy nhất của Thất Thải Tiên Tôn dù hắn có nhiều phi tử. Tình cảm yêu hận của Tiên Tôn dành cho nàng đã hóa thành phách thứ sáu (lam), rốt cuộc biến thành Mộc Băng Mi.","anchor":"Cho dù hắn có nhiều phi tử nhưng hắn lại chỉ có một đạo lữ duy nhất"}]},"nguon":["@c1651"]},{"id":"to-dao","name":"Tô Đạo","aliases":["Tạ Thanh","Thanh Thủy","Thất Thải Tiên Tôn"],"tabs":{"kinhLich":[{"importance":"normal","mucCt":"ky","chuong":"@c1651","tieuDe":"Hé lộ là hồn thứ ba Thất Thải Tiên Tôn luân hồi","text":"Hồn thứ ba của Thất Thải Tiên Tôn luân hồi thành phàm nhân tên Tô Đạo tại Chu Tước Tinh, Triệu quốc. Cả đời không tu đạo nhưng trở thành đại nho. Trong Mộng Đạo của Vương Lâm, Tô Đạo đã nhận Vương Lâm làm đệ tử — nhân quả sâu xa xuyên luân hồi. Cuối cùng vui vẻ nhìn tơ liễu, mỉm cười chết đi.","anchor":"Hắn không biết vì sao trong Mộng Đạo mình lại được đối phương nhận làm đệ tử"},{"chuong":"@c1685","importance":"normal","mucCt":"vua","tieuDe":"Mất tư cách học Vân Đạo Thiên Thuật","text":"Trong cuộc thi vân khí chọn truyền nhân, bị Chu Lập dùng ánh mắt uy hiếp khiến phân tâm, mất hai mươi nhịp thở mới hoàn thành, mây mù yếu ớt bị hút sạch. Sư tôn truyền Thất Thải Tiên Thuật thay vì Vân Đạo Thiên Thuật. Sau khi Vương Lâm nghịch chuyển ký ức, kết quả đảo ngược hoàn toàn.","anchor":"Thất Thải Tiên Tôn năm đó tính cách nhu nhược, không nói những chuyện này ra"}],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Người đang dung hợp hồn thứ ba của hắn, mượn thân phận hắn nghịch chuyển ký ức","ghiChu":""},{"ten":"Liên Đạo Phi","tag":"su-mon","quanHe":"Sư tôn tại Đông Lâm Tông","ghiChu":"Đối đãi tốt nhưng thường bế quan nên Tô Đạo bị đãi ngộ bất công trong tông phái."},{"ten":"Chu Lập","tag":"doi-thu","quanHe":"Đại sư huynh tại Đông Lâm Tông","ghiChu":"Bề ngoài ôn hòa nhưng khinh thị Tô Đạo, dùng ánh mắt uy hiếp trong cuộc thi."}],"tuViMoc":[],"diem":[{"text":"Bản gốc hồn thứ ba Vương Lâm, tính cách nhu nhược khiến bỏ lỡ Vân Đạo Thiên Thuật, chỉ nhận Thất Thải Tiên Thuật — sau bị Vương Lâm nghịch chuyển đảo ngược kết quả.","chuong":"@c1685"},{"text":"Bản gốc hồn thứ ba Vương Lâm. Tính cách nhu nhược khiến mất cơ hội học tam đại thần thông, chỉ nhận Thất Thải Tiên Thuật.","chuong":"@c1685"}]},"nguon":["@c1651","@c1685"],"canhGioiCaoNhat":"khong-ro","trangThai":"khong-ro","vaiTro":"Tiền thân hồn thứ ba của Vương Lâm, đệ tử Đông Lâm Tông dưới trướng Liên Đạo Phi","tinhCach":[{"text":"Nhu nhược, không dám phản kháng khi bị khinh thị, giấu chuyện bất công trong lòng"}],"blurb":"Bản gốc của hồn thứ ba mà Vương Lâm đang dung hợp, đệ tử Đông Lâm Tông. Tính cách nhu nhược, năm xưa bị Chu Lập uy hiếp mất tư cách học Vân Đạo Thiên Thuật, chỉ được truyền Thất Thải Tiên Thuật.","cn":"苏道","gioiTinh":"nam","theLuc":[{"ten":"Đông Lâm Tông","trangThai":"gan-bo"}]},{"id":"ngu-ong-thanh-linh","name":"Ngư ông (Thanh Linh tinh)","gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Phàm nhân","trangThai":"song","blurb":"Ngư ông phàm nhân tại Thanh Linh tinh, La Thiên Tinh Vực. Câu được con cá là hồn thứ ba Thất Thải Tiên Tôn luân hồi, nói vợ sắp sinh — ám chỉ hồn thứ ba chờ đầu thai thành con ông.","vaiTro":"Ngư ông phàm nhân câu được hồn thứ ba Thất Thải Tiên Tôn","tinhCach":"bình dị, vui vẻ","tabs":{"diem":[{"text":"Câu được con cá chính là hồn thứ ba Thất Thải Tiên Tôn đã luân hồi mấy trăm lần trong cùng con sông, chờ đợi khoảnh khắc này.","chuong":"@c1651"}],"kinhLich":[{"importance":"normal","mucCt":"gon","chuong":"@c1651","tieuDe":"Câu được hồn thứ ba luân hồi","text":"Xuất hiện ở cuối chương, câu được con cá (hồn thứ ba Thất Thải Tiên Tôn luân hồi mấy trăm lần), nói vợ sắp sinh — ám chỉ hồn thứ ba chờ đầu thai thành con ông.","anchor":"Vợ ta sắp sinh, hôm nay câu được con cá này mang về rồi!"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1651"]},{"id":"ta-thanh","name":"Tạ Thanh","aliases":["Tô Đạo","Thanh Thủy"],"tabs":{"kinhLich":[{"chuong":"@c1652","importance":"major","mucCt":"ky","tieuDe":"Xác nhận là hồn thứ ba Thất Thải Tiên Tôn","text":"Được xác nhận chính là hồn thứ ba của Thất Thải Tiên Tôn. Cảnh chào đời trong kiếp luân hồi cuối cùng được hé lộ: cha là Tạ Đông Minh, mẹ là Tố Nhi. Hồn thứ ba từng luân hồi hàng trăm kiếp làm cá trong sông Thanh Linh Tinh trước khi sinh thành người. Câu nói năm xưa khi leo núi cầu đạo được giải mã: Tạ Thanh đã tự biết bản chất mình.","anchor":"Hồn thứ ba lại là Tạ Thanh!"},{"mucCt":"vua","text":"Được xác nhận là hồn thứ ba của Thất Thải Tiên Tôn, đệ tử của Vương Lâm. Đang ở sâu trong tu chân tinh phía đông La Thiên, hình như chủ động đợi sư phụ.","anchor":"Tạ Thanh là đệ tử của hắn. Hắn đối với Tạ Thanh có nhân quả","bridge":true,"khoang":"@c1653"},{"importance":"normal","mucCt":"ky","chuong":"@c1654","tieuDe":"Tiết lộ thân phận, trao phong ấn, tự nguyện chết","text":"Bái kiến sư tôn Vương Lâm tại u cốc hoa lan trên tu chân tinh phía đông La Thiên. Tiết lộ bản thân chính là hồn thứ ba của Thất Thải Tiên Tôn, nhưng khẳng định bản ngã là Tạ Thanh chứ không phải Tô Đạo hay Thất Thải Tiên Tôn. Sau khi trí nhớ thức tỉnh đã trốn tránh, do dự, cuối cùng ngộ ra bản ngã khi nhìn hoa lan. Dùng hồn tu lực ngưng tụ ba đạo phong ấn cho sư tôn: phong ấn thứ nhất khiến hồn thứ ba không luân hồi khi chết và mở trung tâm động phủ; hai phong ấn còn lại phối hợp lực Tiên Cương đại lục phong ấn hồn thứ nhất và hồn thứ hai. Tâm hồn hao tổn cực độ, ho ra máu. Tiết lộ trong bảy phách còn hai phách cực kỳ quan trọng với Vương Lâm. Tự nguyện nhắm mắt, nở nụ cười giải thoát, khí tuyệt thân vong. Hồn thứ ba từ thất khiếu lan ra được Vương Lâm thu lấy.","anchor":"Đệ tử Tạ Thanh bái kiến sư tôn"},{"importance":"major","mucCt":"gon","chuong":"@c1655","tieuDe":"Qua đời, hồn thứ ba xuất hiện trong thi thể","text":"Gọi tiếng sư tôn cuối cùng rồi mỉm cười qua đời. Hồn thứ ba của Thất Thải Tiên Tôn xuất hiện trong thi thể. Vương Lâm coi hồn thứ ba là Tạ Thanh chứ không phải Thất Thải Tiên Tôn, thề sẽ giúp ngưng tụ thành hồn thức tỉnh trí nhớ.","anchor":"Hắn trở mắt nhìn đệ tử Tạ Thanh gọi tiếng sư tôn cuối cùng, mỉm cười qua đời"},{"mucCt":"vua","text":"Thi thể vẫn quỳ trong sơn cốc. Được Vương Lâm bi ai an táng bằng thu lan biến thành ngôi mộ, hắn hứa sẽ tới đánh thức nàng. Từ đó mỗi mùa thu hoa lan ngập tràn tu chân tinh vô danh làm bạn với nàng.","anchor":"Ngươi thích thu lan trong dãy núi này, vậy thì an nghỉ ở đây đi","bridge":true,"khoang":"@c1656"},{"chuong":"@c1685","importance":"normal","tieuDe":"Lý do Vương Lâm nghịch chuyển ký ức","text":"Được Vương Lâm nhắc đến trong suy tư nội tâm: nếu dung hợp hoàn toàn với hồn thứ ba, Tạ Thanh sẽ tan biến vĩnh viễn, không bao giờ thức tỉnh. Đây là lý do then chốt Vương Lâm quyết định không thuận theo ký ức mà nghịch chuyển.","anchor":"Nếu như vậy thì Tạ Thanh sẽ không thể nào thức tỉnh được nữa","mucCt":"vua"},{"chuong":"@c1690","importance":"normal","mucCt":"vua","tieuDe":"Phong ấn di nguyện phát huy tác dụng","text":"Được hồi tưởng: là một lần luân hồi của hồn thứ ba Thất Thải Tiên Tôn, đã xả thân ngưng tụ ba đạo phong ấn trước khi chết. Hai đạo phong ấn chứa tâm huyết của Tạ Thanh được Vương Lâm kích hoạt, dung hợp khí tức Tiên Cương, phong ấn thành công lưỡng hồn Thất Thải Tiên Tôn.","anchor":"Phong ấn trong tay Vương Lâm hắn lờ mờ có thể thấy ánh mắt bi phẫn của Tạ Thanh."},{"importance":"bridge","mucCt":"gon","chuong":"@c1691","tieuDe":"Được Vương Lâm hứa làm sống lại","text":"Được Vương Lâm nhớ tới trước kim môn, hứa nhất định sẽ làm sống lại.","anchor":"Tạ Thanh, ta hứa sẽ làm ngươi sống lại một lần nữa, nhất định thế"}],"nhanMach":[{"ten":"Vương Lâm","tag":"su-mon","quanHe":"Sư tôn","ghiChu":"Quỳ bái kiến, tận tâm hoàn thành ba đạo phong ấn trước khi chết"},{"ten":"Thất Thải Tiên Tôn","tag":"khac","quanHe":"Bản thể gốc (hồn thứ ba)","ghiChu":"Tạ Thanh là hồn thứ ba nhưng khẳng định bản ngã riêng"},{"ten":"Tạ Đông Minh","tag":"cha-me","quanHe":"Cha trong kiếp luân hồi cuối cùng","ghiChu":"@c1652"},{"ten":"Tố Nhi","tag":"cha-me","quanHe":"Mẹ trong kiếp luân hồi cuối cùng","ghiChu":"@c1652"}],"tuViMoc":[],"diem":[{"text":"Chính là hồn thứ ba của Thất Thải Tiên Tôn nhưng kiên quyết giữ bản ngã Tạ Thanh","chuong":"@c1654"},{"text":"Tự nguyện chết để trao hồn thứ ba cho Vương Lâm và hoàn thành ba đạo phong ấn giúp sư tôn rời động phủ giới","chuong":"@c1654"},{"text":"Dùng hồn tu lực nhiều năm ngưng tụ ba đạo phong ấn — tâm hồn hao tổn cực độ, ho ra máu","chuong":"@c1654"}]},"nguon":["@c1652","@c1653","@c1654","@c1655","@c1656","@c1685","@c1690","@c1691"],"canhGioiCaoNhat":"Không rõ","trangThai":"tu-vong","vaiTro":"Đệ tử Vương Lâm, hồn thứ ba Thất Thải Tiên Tôn, tự nguyện hy sinh","tinhCach":"Trung thành tuyệt đối với sư tôn; kiên định bản ngã dù mang trí nhớ tiền kiếp; cam lòng chấp nhận cái chết; lưu luyến cuộc đời nhưng thanh thản khi buông bỏ","blurb":"Đệ tử của Vương Lâm, thực chất là hồn thứ ba của Thất Thải Tiên Tôn. Khẳng định bản ngã là Tạ Thanh, không phải Tô Đạo hay Thất Thải Tiên Tôn. Tự nguyện chết để trao hồn thứ ba cho sư tôn và hoàn thành ba đạo phong ấn.","cn":"谢青","gioiTinh":"nam"},{"id":"ta-dong-minh","name":"Tạ Đông Minh","cn":"谢东明","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Phàm nhân","trangThai":"khong-ro","blurb":"Cha của Tạ Thanh trong kiếp luân hồi cuối cùng của hồn thứ ba. Hán tử ba mươi tuổi dáng suy nhược nhưng thần sắc hào hiệp, giống văn nhân hơn ngư ông, từng đọc sách làm quan tạo phúc cho dân.","vaiTro":"Cha của Tạ Thanh trong kiếp cuối, văn nhân làm quan thanh liêm","tinhCach":"Hào hiệp, yêu thương gia đình; có chí khí bậc đại nho, thanh liêm chính trực","tabs":{"diem":[{"text":"Văn nhân ba mươi ba năm làm quan thanh liêm không thẹn lương tâm, đặt tên con Tạ Thanh mong con cao vút xuất trần như thanh trúc","chuong":"@c1652"},{"text":"Dáng suy nhược nhưng thần sắc hào hiệp, giống văn nhân hơn ngư ông, từng làm quan thanh liêm tạo phúc dân chúng.","chuong":"@c1652"},{"text":"Phàm nhân thanh liêm, từng đọc sách làm quan tạo phúc, mong con như thanh trúc cao vút xuất trần","chuong":"@c1652"}],"kinhLich":[{"chuong":"@c1652","importance":"normal","mucCt":"vua","tieuDe":"Tạ Thanh chào đời","text":"Đêm mưa bão, thê tử Tố Nhi sinh khó, Tạ Đông Minh lo lắng đấm tay vào vách trúc chảy máu, trách trời. Đứa trẻ chào đời bình an, đặt tên Tạ Thanh, mong con cao vút xuất trần như thanh trúc.","anchor":"Tạ Đông Minh ta thủa nhỏ đọc sách, hiểu đạo lý biết vạn vật làm quan tạo phúc cho dân chúng một phương"}],"tuViMoc":[],"nhanMach":[{"ten":"Tố Nhi","tag":"the-thiep","quanHe":"Thê tử, mẹ của Tạ Thanh"},{"ten":"Tạ Thanh","tag":"cha-me","quanHe":"Con trai, được đặt tên với kỳ vọng xuất trần"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1652"]},{"id":"to-nhi","name":"Tố Nhi","cn":"素儿","aliases":[],"gioiTinh":"nu","theLuc":[],"canhGioiCaoNhat":"Phàm nhân","trangThai":"khong-ro","blurb":"Thê tử của Tạ Đông Minh, mẹ của Tạ Thanh trong kiếp luân hồi cuối cùng. Nữ tử mặc tố y dung nhan xinh đẹp, sinh khó trong đêm mưa bão nhưng cuối cùng mẫu tử bình an.","vaiTro":"Mẹ của Tạ Thanh trong kiếp cuối, thê tử Tạ Đông Minh","tinhCach":"Hiền lành, nhẫn nại","tabs":{"diem":[{"text":"Sinh khó trong đêm bão sấm chớp, cuối cùng mẫu tử bình an","chuong":"@c1652"},{"text":"Nữ tử mặc tố y dung nhan xinh đẹp, mang thai chờ chồng trong căn nhà cỏ giữa rừng trúc.","chuong":"@c1652"},{"text":"Phàm nhân xinh đẹp, sinh khó trong đêm bão nhưng mẫu tử bình an","chuong":"@c1652"}],"kinhLich":[{"chuong":"@c1652","importance":"normal","mucCt":"gon","tieuDe":"Sinh hạ Tạ Thanh","text":"Sinh khó trong đêm mưa bão, cuối cùng mẫu tử bình an.","anchor":"Là con trai."}],"tuViMoc":[],"nhanMach":[{"ten":"Tạ Đông Minh","tag":"the-thiep","quanHe":"Phu quân"},{"ten":"Tạ Thanh","tag":"cha-me","quanHe":"Con trai"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1652"]},{"id":"thien-van-tu-ao-xam","name":"Thiên Vận Tử áo xám","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"vua","chuong":"@c1653","text":"Vương Lâm nghĩ tới hắn như phân thân chưa chết của Thiên Vận Tử, có thể mang theo phách thứ bảy, nhưng không chắc chắn.","anchor":"Ta suýt quên một người là Thiên Vận Tử áo xám!"}]},"nguon":["@c1653"]},{"id":"tan-linh-thuong-nhan","name":"Tán Linh thượng nhân","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1653","text":"Được liệt kê là phách thứ sáu, thuộc nhóm đã xảy ra biến số.","anchor":"Thanh Thủy cũng vậy, Tham Lang cũng thế, cho dù là Mộc Băng Mi, Tán Linh thượng nhân"},{"importance":"bridge","mucCt":"gon","chuong":"@c1689","text":"Được Vương Lâm nhắc đến khi so sánh tâm tình mở đại môn với việc Tán Linh thượng nhân đưa người ra ngoài bảy trăm vạn thiên địa bước vào Thái Cổ Tinh Thần.","anchor":"tâm tình của Tán Linh thượng nhân khi đưa người ở bảy trăm vạn thiên địa ra ngoài thế giới"}]},"nguon":["@c1653","@c1689"],"trangThai":"khong-ro"},{"id":"chuong-ton","name":"Chưởng Tôn","tabs":{"kinhLich":[{"mucCt":"vua","text":"Ở đại điện giới ngoại, mở bừng mắt hoảng sợ khi cảm nhận đại biến, nhận ra hồn thứ ba thức tỉnh và trung tâm động phủ lại mở ra. Sắc mặt tái nhợt, lập tức lao thẳng về giới nội.","anchor":"Hồn thứ ba thức tỉnh! Trung tâm động phủ lại mở ra một lần nữa!","bridge":true,"khoang":"@c1655"},{"importance":"bridge","mucCt":"gon","chuong":"@c1656","text":"Xuất hiện bên ngoài đại môn, cuống quít lui lại bên cạnh đạo nhân bảy màu, nhìn Vương Lâm kinh nghi bất định.","anchor":"Thân ảnh Chưởng Tôn xuất hiện bên ngoài cánh cửa thân thể cuống quít lui lại phía sau"},{"importance":"bridge","mucCt":"gon","chuong":"@c1657","text":"Do dự rồi cắn răng tiến vào đại môn động phủ, là người thứ ba bước vào.","anchor":"Cả người hắn hóa thành một đạo tàn ảnh ngay lập tức tới gần đại môn ở bên ngoài hơi do dự rồi cắn răng tiến vào"},{"mucCt":"vua","text":"Là người thứ ba tiến vào, vừa muốn bước qua đống đổ nát thì thần sắc biến đổi, lập tức dừng lại bắt quyết ẩn thân trở nên vô hình. Sau khi thấy Lam Mộng Đạo Tôn đi qua đống đổ nát mà không sao, ẩn một bên nhíu mày.","anchor":"thần sắc biến đổi, lập tức dừng lại, ánh mắt lóe lên, tay phải bắt quyết","bridge":true,"khoang":"@c1658"},{"chuong":"@c1659","importance":"bridge","mucCt":"gon","text":"Ẩn thân bên cạnh đống đổ nát quan sát mọi người tiến vào, khóe miệng lộ nụ cười lạnh khi tơ máu kích hoạt.","anchor":"Chưởng Tôn bí mật ẩn thân ở cạnh đó lúc này hai mắt lóe sáng, khóe miệng lộ nụ cười lạnh"},{"importance":"bridge","mucCt":"gon","chuong":"@c1667","tieuDe":"Xuất hiện mệt mỏi sau giao chiến","text":"Xuất hiện qua vòng xoáy thần sắc mệt mỏi, nhìn Lam Mộng Đạo Tôn với hàn ý — từng giao chiến trong ba trăm tàn giới.","anchor":"Thần sắc của hai người bọn họ có chút mệt mỏi, khi nhìn về phía đối phương đều nổi lên hàn ý"},{"importance":"bridge","mucCt":"vua","chuong":"@c1668","tieuDe":"Nhận ra U Minh Thú hoảng sợ","text":"Từ biển lửa ra, đứng ngây nhìn U Minh Thú sắc mặt trắng bệch. Nhớ lại chủ nhân hắn từng bị U Minh Thú nuốt năm xưa, hoảng sợ điên cuồng lui về phía sau.","anchor":"cảnh tượng năm đó chủ nhân của hắn bị nuốt khiến cho hắn rất khó có thể quên"},{"importance":"bridge","mucCt":"gon","chuong":"@c1669","tieuDe":"Nhận diện Mục Ngư, kinh hãi cung Lý Quảng","text":"Nhận diện Mục Ngư là kỳ thú Tiên Cương, khi Vương Lâm bắn tiễn thì sắc mặt tái nhợt vội lui lại vì đã bị mũi tên này giết chết hai lần trước.","anchor":"Hắn đã bị mũi tên này g**t ch*t hai lần đã khắc cốt ghi tâm"},{"mucCt":"gon","text":"Tái nhợt hóa cầu vồng bỏ chạy khi sức mạnh hủy diệt lan ra. Khi thấy Liên Đạo Phi, thân thể run lên, suýt quỳ sụp gọi chủ nhân.","anchor":"suýt chút nữa trước những lời nói của người điên đã quỳ sụp xuống","bridge":true,"khoang":"@c1670"},{"importance":"bridge","mucCt":"gon","chuong":"@c1671","tieuDe":"Quan sát mánh khóe Vương Lâm","text":"Ở phía xa quan sát toàn bộ diễn biến, nhìn ra mánh khóe của Vương Lâm nhưng không nhắc nhở Chiến lão quỷ mà thầm tính kế riêng.","anchor":"mơ hồ nhìn ra mánh khóe, trái tim đập thình thịch"},{"importance":"bridge","mucCt":"vua","chuong":"@c1676","tieuDe":"Bị Vương Lâm và Vân Dật Phong giáp công","text":"Đạp không đi tới, trên thân hiện vầng mặt trời chống đỡ huyết kiếm của Vương Lâm nhưng bị đẩy lùi một bước, đồng thời đối mặt Bát Đao Trảm Thần Hồn của Vân Dật Phong.","anchor":"một thân ảnh mơ hồ đạp không đi tới"},{"importance":"normal","mucCt":"ky","chuong":"@c1677","tieuDe":"Thi triển Chưởng diệt tam đạo, kinh hãi trước thân phận Huyền La","text":"Xuất hiện tại vùng đất cổ mộ, nhờ thông tin từ Diệu Âm nên tới nhanh vượt trước. Phán đoán Vương Lâm cạn sức sau ba lần giương cung, quyết giết Vương Lâm đoạt hồn thứ ba. Dùng hào quang bảy màu phá Bát Đao của Vân Dật Phong, dùng kim quang phá chín phi kiếm của Đường San. Thi triển Chưởng diệt tam đạo ba tầng (diệt linh đạo, diệt quỷ đạo, diệt thần đạo) đối đầu Tê Thiên Thuật, kim ấn tầng ba vượt qua giáng xuống Vương Lâm. Nhưng Huyền La chỉ tay biến kim ấn thành pháp bảo thực chất — Chưởng Tôn kinh hãi tột cùng, nhận ra đây là năng lực chỉ cửu đại thiên tôn Tiên Cương Cửu Dương mới có, gọi Huyền La là ca ca của chủ nhân.","anchor":"Đây là ca ca của chủ nhân….Tiên Cương Cửu Dương, cửu đại thiên tôn mới có thể làm được"},{"importance":"normal","mucCt":"ky","chuong":"@c1678","tieuDe":"Bị bốn người vây đánh, lần đầu phun máu, thi triển Tình Trung Lao Nguyệt","text":"Tâm thần sụp đổ vì sự hiện diện của Huyền La, nghi ca ca của chủ nhân ẩn mình gần đó, bỏ ý định giết Vương Lâm điên cuồng bỏ chạy. Bị bốn người vây đánh, ác hầu tím nhập thể theo thất khiếu, bị cự long vàng nuốt, lần đầu phun máu tại đây. Cảm nhận khí tức Lam Mộng Đạo Tôn đang lao tới, biết nếu Lam Mộng động thủ thì chắc chắn chết. Phản kích bằng nguyên thần huyết màu vàng nhắm Vương Lâm nhưng bị Định Thân Thuật chặn, bị huyết kiếm xuyên vai phun máu. Thi triển đạo thuật Tình Trung Lao Nguyệt lấy đất làm giếng phản chiếu trời, mò ra ảo ảnh giết hồn.","anchor":"lần đầu tiên Chưởng Tôn ở nơi này phun ra một ngụm máu tươi"},{"importance":"normal","mucCt":"ky","chuong":"@c1679","tieuDe":"Mất nửa hồn, bị Vương Lâm thu giữ","text":"Thi triển Tĩnh Trung Lao Nguyệt biến mặt đất thành nước giếng phản chiếu thân ảnh bốn đối thủ. Bị Lam Mộng Đạo Tôn phối hợp ba người phong ấn toàn thân ba nhịp thở, dùng kim quang hộ thể phòng ngự. Bị Vương Lâm dùng Mộng Đạo xâm nhập hồn rồi tế hồn cho Dĩ Ti, mất nửa hồn, đau đớn điên cuồng. Lao tới định giết Vương Lâm nhưng bị Dĩ Ti hiện thân đánh bại trong sương đen, bị ném ra bất tỉnh. Cuối cùng bị Vương Lâm thu vào không gian trữ vật, để dành cho người điên năm đó quyết định sống chết.","anchor":"ngay khi bị phong ấn, toàn thân hắn đột nhiên bị một đám kim quang bao trùm"},{"importance":"major","mucCt":"vua","chuong":"@c1680","tieuDe":"Bị lấy nửa hồn, luân hồi nhân quả","text":"Bị Vương Lâm lấy nửa hồn, kết cục bi thảm. Vương Lâm cảm khái: một đời kiêu hùng nhưng chỉ là nô bộc người điên, sau bái đạo nhân bảy màu làm thầy, nay rơi vào luân hồi nhân quả từ việc năm xưa vây giết Phong Tôn.","anchor":"Kẻ giết người lại bị người ta giết!"}],"nhanMach":[],"tuViMoc":[]},"nguon":["@c1655","@c1656","@c1657","@c1658","@c1659","@c1667","@c1668","@c1669","@c1670","@c1671","@c1676","@c1677","@c1678","@c1679","@c1680"],"trangThai":"khong-ro","cn":"掌尊","gioiTinh":"nam"},{"id":"lam-mong-dao-ton","name":"Lam Mộng Đạo Tôn","tabs":{"kinhLich":[{"mucCt":"vua","text":"Truyền giọng nói uy nghiêm vào tâm thần Tư Đồ Nam và Thanh Thủy, nói đã từng đáp ứng Vương Lâm giúp một tay. Không có huyết mạch Tiên Cương đại lục nên không thể tiến vào trung tâm động phủ, muốn mượn hồn phách hai người dùng một lát.","anchor":"Ta đã từng đáp ứng Vương Lâm sẽ giúp một tay","bridge":true,"khoang":"@c1655"},{"importance":"bridge","mucCt":"gon","chuong":"@c1656","text":"Lam quang lóe lên, chậm rãi bước ra, thân thể có chút bất đồng, bình tĩnh đối diện Chiến lão quỷ và đạo nhân bảy màu.","anchor":"Thần sắc Lam Mộng Đạo Tôn bình tĩnh, đứng ở nơi đó"},{"mucCt":"vua","text":"Thần sắc bình tĩnh, chậm rãi đi tới trước cửa, thầm than nhẹ rồi tiến vào. Là người duy nhất không có huyết mạch tiên cương mà vẫn vào được nhờ mượn hồn.","anchor":"Lam Mộng Đạo Tôn mượn hồn mà vào","bridge":true,"khoang":"@c1657"},{"mucCt":"vua","text":"Đi sau Chưởng Tôn tới trung tâm động phủ, nhìn đống đổ nát phía dưới rồi khóe miệng lộ nụ cười. Đơn giản cất bước dung nhập vào đại đỉnh mà đống đổ nát không biến hóa, khiến Chưởng Tôn đang ẩn thân phải nhíu mày.","anchor":"Lam Mộng Đạo Tôn đi tới, hai mắt sững lại, nhìn đống đổ nát phía dưới, khóe miệng đột nhiên lộ nụ cười","bridge":true,"khoang":"@c1658"},{"mucCt":"vua","text":"Xuất hiện thần sắc mệt mỏi sau khi giao chiến với Chưởng Tôn trong ba trăm tàn giới. Bị lực Phần Giới Cổ Tán ngăn ở bên ngoài — Vương Lâm cố ý bảo vệ, không muốn hắn dính vào trận giết chóc.","anchor":"Vương Lâm không rảnh phân tâm đi lo lắng cho Lam Mộng, nên muốn ngăn cản hắn ở bên ngoài","bridge":true,"khoang":"@c1667"},{"importance":"bridge","mucCt":"gon","chuong":"@c1678","text":"Khí tức đang từ xa nhanh chóng lao tới vùng đất cổ mộ, Chưởng Tôn cảm nhận nếu Lam Mộng động thủ thì hắn chắc chắn chết.","anchor":"khí tức của Lam Mộng Đạo Tôn cũng đang từ xa nhanh chóng lao tới"},{"mucCt":"vua","text":"Xuất hiện từ đám mây lam trên bầu trời, nhận lời Vương Lâm phong ấn Chưởng Tôn ba nhịp thở. Dùng tu vi cả đời hóa lam quang, phá giếng nước Chưởng Tôn, kéo Vân Dật Phong, Đường San, Thác Sâm dung hợp thành bốn ký hiệu phong ấn khắc lên người Chưởng Tôn.","anchor":"tu vi của hắn vốn không kém, mặc dù vẫn chưa phải là huyền kiếp, nhưng cũng có thể cùng với huyền kiếp đánh một trận","bridge":true,"khoang":"@c1679"},{"mucCt":"vua","text":"Nói kết thúc nhân quả với Vương Lâm: năm đó Vương Lâm trả truyền thừa giúp mặc lưu phân thần đại thành, nay giúp lại. Toàn thân tràn lam quang, bộc phát chiến ý kinh thiên, ở lại chặn Chiến lão quỷ.","anchor":"Lão phu đã đáp ứng là sẽ giúp ngươi, vậy thì lúc này ta vẫn sẽ giúp ngươi!","bridge":true,"khoang":"@c1680"},{"importance":"normal","mucCt":"ky","chuong":"@c1681","tieuDe":"Lấy cổ cầm chí bảo ra chiến đấu","text":"Cùng lão già họ Mã khổ chiến Chiến lão quỷ ở tầng thứ hai vùng đất cổ mộ, chủ yếu phòng ngự vì chưa độ Huyền Kiếp. Cắn lưỡi phun máu, dung hợp lam quang triệu ra cổ cầm chí bảo phong ấn nhiều năm trong máu — đòn sát thủ cuối cùng, cả đời mới dùng một lần. Đây là nguyên nhân chính thức Chưởng Tôn kiêng kỵ hắn. Lai lịch cổ cầm cực kỳ thần bí, mơ hồ không phải vật của động phủ giới. Tiếng đàn hóa sát khí phong tỏa bốn phía Chiến lão quỷ. Nhớ thê tử đang trong không gian trữ vật mà không thể khiến nàng hồi phục.","anchor":"Cả đời Lam Mộng Đạo Tôn mới chỉ dùng cổ cầm này một lần"},{"chuong":"@c1682","importance":"normal","mucCt":"vua","tieuDe":"Phong ấn cổ cầm bị phá, trọng thương vẫn tiếp tục chiến đấu","text":"Bị hồn phách Thất Thải Tiên Tôn đánh tan phong ấn cổ cầm, phun máu trọng thương nhưng tiếp tục đánh đàn tấn công. Được Vương Lâm bảo nghỉ ngơi.","anchor":"phong ấn của cổ cầm của Lam Mộng Đạo Tôn trong tiếng ầm ầm này cũng lập tức bị đánh tan thành mây khói"},{"chuong":"@c1690","importance":"bridge","mucCt":"gon","tieuDe":"","text":"Thân ảnh huyễn hóa ra khi thế giới sụp đổ, chấn động khi chứng kiến Vương Lâm tự mình phong ấn lưỡng hồn Thất Thải mà không cần Huyền La Đại Thiên Tôn ra tay.","anchor":"Bọn họ thật không ngờ Vương Lâm này lại còn một chiêu như vậy."},{"importance":"bridge","mucCt":"vua","chuong":"@c1691","tieuDe":"Chần chừ trước kim môn","text":"Hiện hình bên ngoài kim môn. Chần chừ không biết nên rời đi hay lưu lại, dù biết nơi này chỉ là động phủ.","anchor":"ánh mắt Lam Mộng đạo tôn nhìn về kim môn có chút chần chừ"},{"chuong":"@c1692","importance":"bridge","mucCt":"vua","text":"Kinh ngạc khi Huyền La hiện thân, thần thức không phát hiện được. Đứng nghe Vương Lâm nói về tình cảm với Uyển Nhi, không phẫn nộ mà đồng tình và bi ai, nhớ tới thê tử của mình.","anchor":"Nhưng lúc này hắn lại không hề phẫn nộ, chỉ có đồng tình và bi ai"}],"nhanMach":[],"tuViMoc":[],"diem":[{"text":"Thản nhiên đi qua đống đổ nát trong động phủ mà không bị phản ứng, trong khi Chưởng Tôn phát hiện nguy hiểm phải ẩn thân","chuong":"@c1658"}]},"nguon":["@c1655","@c1656","@c1657","@c1658","@c1667","@c1678","@c1679","@c1680","@c1681","@c1682","@c1690","@c1691","@c1692"],"trangThai":"song","canhGioiCaoNhat":"Không rõ","vaiTro":"Nhân vật bí ẩn tại động phủ Thất Thải Tiên Tôn","tinhCach":"Bình thản; tự tin; thâm trầm khó đoán","blurb":"Nhân vật bí ẩn xuất hiện tại trung tâm động phủ Thất Thải Tiên Tôn. Thản nhiên đi qua đống đổ nát mà không gặp trở ngại, thái độ bình thản tự tin khiến Chưởng Tôn phải nhíu mày.","gioiTinh":"nam","cn":"蓝梦道尊"},{"id":"tien-phi-thu-ba","name":"Tiên phi thứ ba","gioiTinh":"nu","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Tiên phi từng gặp Vương Lâm ở vùng đất cổ mộ, thần sắc phức tạp khi tái ngộ.","vaiTro":"Tiên phi giới ngoại, từng gặp Vương Lâm ở cổ mộ","tinhCach":"Phức tạp, khó đoán","tabs":{"diem":[{"text":"Từng gặp Vương Lâm ở vùng đất cổ mộ, tái ngộ thần sắc vô cùng phức tạp","chuong":"@c1656"}],"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1656","text":"Xuất hiện cùng các tiên phi giới ngoại trước đại môn, thần sắc vô cùng phức tạp khi nhìn thấy Vương Lâm.","anchor":"Một nữ tử trong số đó khi nhìn thấy Vương Lâm thần sắc vô cùng phức tạp"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Từng gặp ở vùng đất cổ mộ, tái ngộ thần sắc phức tạp"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1656"]},{"id":"nu-tu-trieu-ha","name":"Nữ tử từ Triệu Hà","gioiTinh":"nu","theLuc":[{"ten":"Triệu Hà","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Nữ tử thuộc Triệu Hà, từng bị Vương Lâm cự tuyệt liên thủ nên oán hận, cười lạnh khi thấy hắn bị bao vây.","vaiTro":"Tu sĩ Triệu Hà, đối thủ của Vương Lâm","tinhCach":"Sát khí, thù dai, cười lạnh khi đối thủ gặp nạn","tabs":{"diem":[{"text":"Từng bị Vương Lâm cự tuyệt liên thủ nên mang oán hận, cười lạnh khi thấy hắn bị quần hùng bao vây","chuong":"@c1656"}],"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1656","text":"Đạp sương mù xuất hiện trước đại môn, mang sát khí nhìn Vương Lâm, cười lạnh khi thấy hắn bị bao vây.","anchor":"Nàng sớm đã có mâu thuẫn với Vương Lâm. Năm đó Vương Lâm cự tuyệt liên thủ với nàng"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Từng bị Vương Lâm cự tuyệt liên thủ, oán hận"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1656"]},{"id":"lao-gia-that-dao-tong","name":"Lão già Thất Đạo Tông","aliases":["viễn cổ tiên nhân Thất Đạo Tông"],"gioiTinh":"nam","theLuc":[{"ten":"Thất Đạo Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ (viễn cổ tiên nhân, tu vi không cao)","trangThai":"tu-vong","blurb":"Đệ tử Thất Đạo Tông, tiên nhân viễn cổ tiên vực giới ngoại tu vi không cao. May mắn vượt qua đống đổ nát vào đại đỉnh, dung nhập giọt sương rồi bị Vương Lâm giết trong tàn giới.","vaiTro":"Đệ tử Thất Đạo Tông, người đầu tiên xâm nhập tàn giới Vương Lâm","tinhCach":[{"text":"Tham lam khi thấy giọt sương liền vội dung nhập, thiếu cảnh giác"}],"tabs":{"diem":[{"text":"Tiên nhân viễn cổ tiên vực tu vi thấp, may mắn vượt qua đống đổ nát nhưng bị Vương Lâm giết ngay khi vào tàn giới","chuong":"@c1659"},{"text":"May mắn vượt đống đổ nát an toàn nhờ thân pháp, nhưng lập tức bị Vương Lâm giết khi dung nhập tàn giới.","chuong":"@c1659"}],"kinhLich":[],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị Vương Lâm phục kích giết chết trong tàn giới","ghiChu":"@c1659"}],"tuiDo":{"phapBao":[{"ten":"Phất trần","moTa":"Dùng đặt dưới chân nâng thân khi bị cấm phi hành, nhưng vẫn không thoát được huyết kiếm","nguon":"@c1659"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1659"]},{"id":"nu-tu-bi-an-c1659","name":"Nữ tử bí ẩn (dòng xoáy)","aliases":[],"gioiTinh":"nu","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"khong-ro","blurb":"Thân ảnh mơ hồ xuất hiện trong dòng xoáy mới ở tàn giới Vương Lâm cuối chương 1659, danh tính chưa rõ.","vaiTro":"Nhân vật bí ẩn cuối chương, danh tính chưa xác định","tinhCach":[],"tabs":{"diem":[{"text":"Thân ảnh nữ tử mơ hồ xuất hiện trong dòng xoáy tàn giới, mở mạch sự kiện mới","chuong":"@c1659"},{"text":"Xuất hiện dưới dạng thân ảnh mơ hồ trong dòng xoáy, chưa rõ danh tính và mục đích.","chuong":"@c1659"}],"kinhLich":[{"chuong":"@c1659","importance":"bridge","mucCt":"gon","text":"Thân ảnh mơ hồ xuất hiện trong dòng xoáy ngay sau khi Vương Lâm giết ba đệ tử Thất Đạo Tông, danh tính chưa rõ.","anchor":"Bên trong dòng xoáy đó có một thân ảnh mơ hồ, không giống nam tử mà là một nữ tử"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1659"]},{"id":"tu-ha","name":"Tử Hà","aliases":["Thất phi Thất Thải Tiên Tôn"],"gioiTinh":"nu","canhGioiCaoNhat":"Không rõ","trangThai":"bi-phong-an","tabs":{"kinhLich":[{"chuong":"@c1660","importance":"normal","mucCt":"ky","tieuDe":"Mắc bẫy tâm lý Vương Lâm, bị trọng thương","text":"Xuất hiện từ dòng xoáy tại tàn giới, biết rõ quy tắc ba trăm tàn giới (không di chuyển thì quy tắc không phát tác), đi vào hơn mười tàn giới đều đứng yên dùng thần thức dẫn đường. Giao chiến thăm dò với Vương Lâm: triệu phượng hoàng tím đối kháng huyết kiếm, hai bên ngang sức. Phóng phi kiếm tím thử thêm nhưng bị sáu đạo bổn nguyên chấn nát. Lấy ngọc giản định truyền tin gọi viện binh nhưng cân nhắc rằng tứ đại chiến tướng sẽ đoạt mất hồn thứ ba nên thu lại. Suy luận ngược rằng Vương Lâm trọng thương đang phô trương che giấu, bước ra khỏi dòng xoáy truy đuổi, dòng xoáy tiêu tán mất đường rút. Quy tắc tàn giới phát tác khiến thân thể rơi vụt xuống, bị huyết kiếm đánh trúng mi tâm, máu đen phun ra từ ngực, y phục rách nát, trọng thương. Tỵ Thiên Quan là của nàng, rất có thể biết bí mật nơi này.","anchor":"Tuyệt đối không sai rồi! Vương Lâm, lúc này ngươi trốn không thoát đâu!"},{"importance":"normal","mucCt":"ky","chuong":"@c1661","tieuDe":"Bị Vương Lâm đánh bại và bắt sống","text":"Bị huyết kiếm xuyên ngực, bị sáu đạo bổn nguyên đánh trọng thương cả thân thể lẫn nguyên thần, liên tục phun máu, thân thể nứt nẻ. Không kịp xuất pháp bảo hay bắt quyết. Bị Định thân thuật cố định hoàn toàn, bị chín chỉ phong ấn đại thành, cuối cùng bị thu vào tay áo Vương Lâm. Được giữ sống vì trên người còn nhiều thứ khiến Vương Lâm hứng thú.","anchor":"Tử Hà không bị Vương Lâm giết. Trên người nàng còn có rất nhiều thứ khiến Vương Lâm cảm thấy hứng thú"},{"chuong":"@c1666","importance":"bridge","mucCt":"vua","text":"Bị Vương Lâm triệu hồi ra và điểm chỉ lên mi tâm khống chế thân thể, buộc truyền thần niệm vào ngọc giản truyền âm rồi ngọc giản vỡ vụn, đóng vai mồi nhử dụ đạo nhân bảy màu và Chiến lão quỷ tới.","anchor":"vẻ chống cự trong mắt Tử Hà càng đậm nhưng nàng lại không có biện pháp nào khống chế tâm thần và thân thể mình"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[{"ten":"Phi kiếm màu tím","trangThai":"hong","moTa":"Phi kiếm tốc độ cực nhanh, bị Vương Lâm một chỉ chấn nát hóa sương mù tím.","nguon":"@c1660"}],"khac":[{"ten":"Ngọc giản truyền tin","moTa":"Dùng để truyền tin gọi viện binh trong tàn giới, lấy ra nhưng cuối cùng thu hồi không dùng.","nguon":"@c1660"}]}},"nguon":["@c1660","@c1661","@c1666"]},{"id":"thanh-nien-dao-co","name":"Thanh niên Đạo cổ nhất tộc","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Đạo cổ nhất tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"khong-ro","trangThai":"song","blurb":"Thanh niên bí ẩn tự xưng thuộc Đạo cổ nhất tộc, đến Thất Đạo Tông ở Tiên Cương đại lục để đón một hài tử về nhà.","vaiTro":"Thành viên Đạo cổ nhất tộc, đến Tiên Cương tìm hài tử cùng tộc","tinhCach":[{"text":"Uể oải nhưng mang nụ cười chờ mong, ấm áp khi nhắc đến người đồng tộc"}],"tabs":{"diem":[{"text":"Tự xưng thuộc Đạo cổ nhất tộc, đến Thất Đạo Tông đón hài tử về nhà","chuong":"@c1633"}],"kinhLich":[{"chuong":"@c1633","importance":"normal","mucCt":"ky","tieuDe":"Xuất hiện tại Thất Đạo Tông đón hài tử Đạo cổ","text":"Xuất hiện tại Tiên Cương đại lục vùng tiên tộc, đến dãy núi nơi từng có Thất Đạo Tông. Thần sắc uể oải nhưng nở nụ cười chờ mong, tự xưng đến đón hài tử của Đạo cổ nhất tộc về nhà, nói đường về có lẽ gian nan. Mỉm cười tiến vào dãy núi.","anchor":"Hài tử của Đạo cổ nhất tộc chúng ta, ta tới đón ngươi về nhà"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1633"]},{"id":"lao-gia-toc-bac-tang-ba","name":"Lão già tóc bạc tầng ba","cn":"","aliases":["Lão già tầng thứ ba"],"gioiTinh":"nam","theLuc":[{"ten":"Quy Nhất tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không Huyền hậu kỳ đỉnh phong (nhờ áo giáp)","trangThai":"song","blurb":"Tu sĩ Quy Nhất tông đóng giữ tầng ba tháp cao trên Ngũ Hành tinh, tinh thông mộc và thổ Ngũ Hành, tu vi Không Huyền trung kỳ bước ba.","vaiTro":"Đối thủ tại tháp cao Ngũ Hành tinh, canh giữ tầng ba","tinhCach":[{"text":"Kiêu ngạo, thần sắc âm trầm khi đánh giá đối phương, quyết đoán khi dùng thủ đoạn mạnh bất chấp phản phệ"}],"tabs":{"diem":[{"text":"Tinh thông mộc và thổ Ngũ Hành, sở trường dùng roi — pháp bảo đặc trưng Quy Nhất tông","chuong":"@c1645"},{"text":"Khoác áo giáp Quy Nhất tông tăng tu vi vượt bậc nhưng chịu phản phệ đau đớn, nhánh cây chui vào da thịt","chuong":"@c1645"},{"text":"Tinh thông mộc và thổ Ngũ Hành, phía sau hiện hư ảnh đại thụ che trời và cơn lốc đất cát","chuong":"@c1645"},{"text":"Phán đoán sai Vương Lâm là người Đạo cổ nhất mạch từ Tiên Cương đại lục tới tìm Diệp Mịch","chuong":"@c1645"}],"kinhLich":[{"chuong":"@c1645","importance":"normal","mucCt":"ky","tieuDe":"Giao chiến Vương Lâm tại tháp cao","text":"Bước ra từ tầng ba tháp cao, lập phòng hộ quanh tháp tuyên bố bắt Vương Lâm. Phán đoán sai Vương Lâm là người Đạo cổ nhất mạch từ Tiên Cương đại lục tới tìm Diệp Mịch. Dùng roi xanh biếc mộc lực Ngũ Hành dài mười trượng tấn công, roi hấp thu sinh cơ cây cỏ bổ sung bổn nguyên. Bị Vương Lâm rút Côn Cực tiên đấu roi và giật đứt roi. Khoác áo giáp Quy Nhất tông hợp nhất mộc và thổ, tu vi tăng từ Không Huyền trung kỳ lên Không Huyền hậu kỳ đỉnh phong nhưng chịu phản phệ đau đớn. Hút hết cây cỏ trên Ngũ Hành tinh ngưng thành mộc nhân mấy ngàn trượng đội trời đạp đất tấn công Vương Lâm.","anchor":"Xông vào Ngũ Hành đại trận, Cửu Chuyển Tâm Luân, thằng nhãi con này thật to gan"}],"tuViMoc":[{"chuong":"@c1645","canhGioi":"Không Huyền trung kỳ bước ba","text":"Tu vi cơ bản Không Huyền trung kỳ bước ba, tinh thông mộc và thổ Ngũ Hành. Khoác áo giáp Quy Nhất tông tăng tạm lên Không Huyền hậu kỳ đỉnh phong.","importance":"major"},{"chuong":"@c1645","canhGioi":"Không Huyền hậu kỳ đỉnh phong (nhờ áo giáp)","text":"Khoác áo giáp Quy Nhất tông hợp nhất mộc+thổ, tu vi tăng vọt nhưng chịu phản phệ thống khổ.","importance":"major"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ","ghiChu":"Giao chiến tại tháp cao Ngũ Hành tinh, bị Vương Lâm áp đảo giật đứt roi"},{"ten":"Diệp Mịch","tag":"khac","quanHe":"Mục tiêu suy đoán","ghiChu":"Suy đoán nhóm Đạo cổ nhất mạch tới Ngũ Hành tinh để tìm Diệp Mịch"}],"tuiDo":{"phapBao":[{"ten":"Roi xanh biếc","moTa":"Mộc lực Ngũ Hành hóa thành, dài mười trượng, hấp thu sinh cơ cây cỏ bổ sung bổn nguyên. Bị Vương Lâm giật đứt, thu hồi tàn dư hợp nhất vào áo giáp.","trangThai":"hong","nguon":"@c1645"},{"ten":"Áo giáp Quy Nhất tông","moTa":"Hợp nhất mộc+thổ Ngũ Hành, tăng tu vi từ Không Huyền trung kỳ lên hậu kỳ đỉnh phong, nhưng phản phệ đau đớn nhánh cây chui vào da thịt.","trangThai":"dang-co","nguon":"@c1645"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1645"]},{"id":"ba-tien-nhan-that-dao-tong-ngay-6","name":"Ba tiên nhân Thất Đạo Tông (ngày thứ sáu)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thất Đạo Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không Niết sơ kỳ (người mạnh nhất trong nhóm)","trangThai":"tu-vong","blurb":"Ba đệ tử Thất Đạo Tông viễn cổ tiên vực gồm một Không Niết sơ kỳ và hai thiên nhân ngũ suy, bị Vương Lâm phục kích giết trong chưa tới ba nhịp thở.","vaiTro":"Nạn nhân của Vương Lâm trong tàn giới","tinhCach":[],"tabs":{"diem":[{"text":"Bị Vương Lâm giết cả ba trong chưa tới ba nhịp thở, người Không Niết sơ kỳ định đốt cây hương nhưng không kịp.","chuong":"@c1659"}],"kinhLich":[],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Kẻ giết cả ba","ghiChu":"Bị phục kích giết trong tàn giới"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[{"ten":"Cây hương","moTa":"Tiên nhân Không Niết sơ kỳ chụp từ hư không, định đốt lên (nghi tín hiệu cầu viện) nhưng không kịp do bị cấm phi hành.","nguon":"@c1659"}]}},"nguon":["@c1659"]},{"id":"lao-gia-that-dao-tong-vien-co","name":"Lão già Thất Đạo Tông (viễn cổ tiên nhân)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thất Đạo Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ (tu vi không cao)","trangThai":"tu-vong","blurb":"Đệ tử Thất Đạo Tông, tiên nhân viễn cổ tiên vực giới ngoại, tu vi không cao. May mắn vượt qua đống đổ nát vào đại đỉnh, dung nhập giọt sương nhưng bị Vương Lâm giết trong tàn giới.","vaiTro":"Tiên nhân viễn cổ tiên vực, đệ tử Thất Đạo Tông, nạn nhân đầu tiên của Vương Lâm trong tàn giới","tinhCach":[{"text":"Hoảng sợ khi nhận ra tơ máu ngăn cách phía sau, lập tức xông vào đại đỉnh tìm cơ duyên"}],"tabs":{"diem":[{"text":"May mắn vượt qua cấm chế đống đổ nát nhưng bị Vương Lâm phục kích giết trong tàn giới, huyết mạch và thần hồn bị tế cho cánh tay đen bí ẩn","chuong":"@c1659"},{"text":"May mắn vượt qua cấm chế tơ máu nhưng bước vào tàn giới Vương Lâm, trở thành vật thí nghiệm quy tắc cấm phi hành.","chuong":"@c1659"}],"kinhLich":[{"chuong":"@c1659","importance":"normal","mucCt":"vua","tieuDe":"Vượt cấm chế, bị giết trong tàn giới","text":"May mắn vượt đống đổ nát không kích hoạt cấm chế, bước vào đại đỉnh chọn giọt sương dung nhập tàn giới Vương Lâm. Bị quy tắc cấm phi hành khiến mất khả năng bay, dùng phất trần nâng thân nhưng bị huyết kiếm xuyên mi tâm nổ tung chết, nguyên thần bị đánh nát, huyết mạch và hồn phách bị tế cho thân thể kia.","anchor":"ngay cả nguyên thần cũng bị huyết kiếm đánh cho nát bấy, lập tức tử vong"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Kẻ phục kích giết hắn trong tàn giới","ghiChu":"@c1659"}],"tuiDo":{"phapBao":[{"ten":"Phất trần","moTa":"Dùng đặt dưới chân nâng thân khi bị cấm phi hành, nhưng không cứu được mạng","nguon":"@c1659"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1659"]},{"id":"thanh-nien-bi-an-that-dao-tong","name":"Thanh niên bí ẩn (Thất Đạo Tông)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Đạo cổ nhất tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"khong-ro","trangThai":"song","blurb":"Thanh niên thần bí xuất hiện ở vùng núi Thất Đạo Tông trên Tiên Cương đại lục, tự xưng tới đón hài tử của Đạo cổ nhất tộc về nhà.","vaiTro":"Thành viên Đạo cổ nhất tộc, tới Thất Đạo Tông đón người.","tinhCach":[{"text":"Thần sắc uể oải nhưng đầy chờ mong, giọng ôn hòa."}],"tabs":{"diem":[{"text":"Tự xưng thuộc Đạo cổ nhất tộc, tới Thất Đạo Tông đón hài tử về nhà, mở ra tuyến mới liên quan tộc Đạo cổ.","chuong":"@c1633"}],"kinhLich":[{"chuong":"@c1633","importance":"normal","mucCt":"vua","tieuDe":"Xuất hiện ở Thất Đạo Tông đón hài tử Đạo cổ nhất tộc","text":"Xuất hiện trong đêm trăng ở vùng núi Thất Đạo Tông trên Tiên Cương đại lục, thần sắc uể oải nhưng đầy chờ mong. Tự xưng tới đón hài tử của Đạo cổ nhất tộc về nhà, rồi mỉm cười tiến vào dãy núi.","anchor":"Hài tử của Đạo cổ nhất tộc chúng ta, ta tới đón ngươi về nhà"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1633"]},{"id":"lao-gia-tdat-c1659","name":"Lão già đệ tử Thất Đạo Tông (viễn cổ tiên nhân)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thất Đạo Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ (viễn cổ tiên nhân, tu vi không cao)","trangThai":"tu-vong","blurb":"Đệ tử Thất Đạo Tông từ viễn cổ tiên vực, tu vi không cao, may mắn vượt qua đống đổ nát vào đại đỉnh nhưng bị Vương Lâm phục kích giết trong tàn giới.","vaiTro":"Nạn nhân đầu tiên của Vương Lâm trong tàn giới","tinhCach":[{"text":"Thận trọng nhưng tham lam, thấy giọt sương liền dung nhập vào"}],"tabs":{"diem":[{"text":"May mắn vượt qua cấm chế tơ máu nhưng lại rơi vào tàn giới Vương Lâm, trở thành vật thí nghiệm quy tắc cấm phi hành","chuong":"@c1659"}],"kinhLich":[{"chuong":"@c1659","importance":"normal","tieuDe":"Bị Vương Lâm giết trong tàn giới","text":"Vượt qua đống đổ nát vào đại đỉnh, dung nhập giọt sương. Trong tàn giới bị quy tắc cấm phi hành khiến mất khả năng bay, dùng phất trần nâng thân nhưng bị huyết kiếm xuyên mi tâm nổ tung tử vong. Huyết mạch và nguyên thần bị cánh tay đen thu lấy tế cho thân thể.","mucCt":"vua","anchor":"huyết quang đã lóe qua mi tâm của hắn"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Kẻ giết hắn","ghiChu":"Bị phục kích trong tàn giới"}],"tuiDo":{"phapBao":[{"ten":"Phất trần","moTa":"Dùng đặt dưới chân nâng thân khi mất khả năng phi hành, nhưng không cứu được mạng","nguon":"@c1659"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1659"]},{"id":"ba-tien-nhan-tdat-c1659","name":"Ba tiên nhân Thất Đạo Tông (nhóm ngày thứ sáu)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thất Đạo Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không Niết sơ kỳ (người mạnh nhất trong nhóm)","trangThai":"tu-vong","blurb":"Ba đệ tử Thất Đạo Tông viễn cổ tiên vực — một Không Niết sơ kỳ, hai thiên nhân ngũ suy chưa bước thứ ba — bị Vương Lâm phục kích giết sạch trong chưa đầy ba nhịp thở.","vaiTro":"Nạn nhân của Vương Lâm trong tàn giới","tinhCach":[{"text":"Không kịp phản ứng trước phục kích"}],"tabs":{"diem":[{"text":"Bị giết sạch trong chưa đầy ba nhịp thở, tiên nhân Không Niết sơ kỳ định đốt cây hương cầu viện nhưng không kịp","chuong":"@c1659"}],"kinhLich":[{"chuong":"@c1659","importance":"normal","tieuDe":"Bị Vương Lâm phục kích giết trong tàn giới","text":"Xuất hiện qua dòng xoáy vào tàn giới, bị Vương Lâm ra tay cực nhanh: huyết kiếm chém đầu một người, chỉ điểm mi tâm giết người thứ hai, kích hoạt cấm phi hành khiến tiên nhân Không Niết sơ kỳ rơi xuống rồi huyết kiếm xuyên ngực kết hợp chưởng ấn đánh tan nát. Tiên nhân Không Niết định đốt cây hương cầu viện nhưng không kịp.","mucCt":"gon","anchor":"Giết ba người không cần tới ba nhịp thở!"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Kẻ giết cả ba","ghiChu":"Bị phục kích trong tàn giới"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[{"ten":"Cây hương","moTa":"Tiên nhân Không Niết sơ kỳ rút ra định đốt (nghi vật cầu viện) nhưng bị rơi xuống do cấm phi hành, không kịp đốt đã bị giết","nguon":"@c1659"}]}},"nguon":["@c1659"]},{"id":"ba-de-tu-that-dao-tong-dot-hai","name":"Ba đệ tử Thất Đạo Tông (đợt hai)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thất Đạo Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không Niết sơ kỳ (mạnh nhất trong ba)","trangThai":"tu-vong","blurb":"Ba tiên nhân viễn cổ tiên vực mặc đạo bào Thất Đạo Tông, bị Vương Lâm phục kích giết sạch trong chưa tới ba nhịp thở.","vaiTro":"Nạn nhân của Vương Lâm trong tàn giới.","tinhCach":[{"text":"Không kịp phản ứng trước phục kích"}],"tabs":{"diem":[{"text":"Một Không Niết sơ kỳ và hai thiên nhân ngũ suy, bị Vương Lâm giết trong chưa tới ba nhịp thở ngay khi vừa xuất hiện qua dòng xoáy.","chuong":"@c1659"}],"kinhLich":[{"chuong":"@c1659","importance":"normal","mucCt":"gon","tieuDe":"Bị phục kích giết sạch trong tàn giới","text":"Vừa xuất hiện qua dòng xoáy liền bị Vương Lâm phục kích: huyết kiếm chém đầu người thứ nhất, điểm chỉ mi tâm giết người thứ hai, người Không Niết sơ kỳ bị cấm phi hành rơi xuống rồi bị huyết kiếm xuyên ngực và chưởng đánh tan nát.","anchor":"Giết ba người không cần tới ba nhịp thở!"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị Vương Lâm phục kích giết chết","ghiChu":""}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1659"]},{"id":"bach-ho-chien-tuong","name":"Bạch Hổ chiến tướng","cn":"白虎战将","aliases":["Bạch Hổ Thánh Hoàng"],"gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1663","importance":"normal","mucCt":"ky","tieuDe":"Bại trận trong giới cờ trước Vương Lâm","text":"Dung nhập thần sắc vào chiến tướng bạch giáp, hiện hư ảnh mãnh hổ ngập trời. Lần va chạm đầu với Vương Lâm, vũ khí và ngựa đều hủy, bổn tôn phun máu hoảng sợ trước sát khí Vương Lâm. Từ chối nhận thua, tự đấm ngực phun máu dung hợp cho bạch giáp, phóng ngàn giọt huyết khí giết gần mười vạn binh lính không phân địch ta để tái tạo giáp và mã. Lần hai bạch mã hóa Bạch Hổ thật, cầm thương ba trượng xung phong nhưng bị Vương Lâm một đao chẻ đôi chiến tướng bạch giáp từ mi tâm. Bổn tôn phun máu, thần sắc ảm đạm. Bị Vương Lâm tuyên bố thu làm nô bộc.","anchor":"Bạch Hổ ta tuyệt đối sẽ không nhận thua"},{"mucCt":"vua","text":"Bị uy áp của Vương Lâm đè nặng như ngọn núi, buộc phải cúi đầu khuất phục do thân thể thần thức đã bị cắn nuốt và lời thề huyết mạch ràng buộc. Quy tắc Bạch Hổ bị đường đao đánh tan, phun máu tươi. Sau khi tàn giới hủy diệt, lời thề có hiệu lực, nhận mệnh lệnh đầu tiên từ Vương Lâm: bắt tu sĩ Ngũ Hành tinh.","anchor":"Lời thề của hắn đã có hiệu lực","bridge":true,"khoang":"@c1664"},{"mucCt":"vua","text":"Bị Vương Lâm phóng thích cùng tu sĩ trung niên Ngũ Hành Tinh. Sửng sốt được tha, ánh mắt cảm kích, vái sâu Vương Lâm rồi cùng Huyền Vũ và Chu Tước bay vào kim môn.","anchor":"Bạch Hổ chiến tướng sửng sốt, ánh mắt lộ vẻ cảm kích, hướng về phía Vương Lâm vái một cái thật sâu","bridge":true,"khoang":"@c1691"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1663","@c1664","@c1691"]},{"id":"tu-si-ngu-hanh-tinh","name":"Tu sĩ Ngũ Hành tinh","cn":"","aliases":["chiến tướng kim giáp"],"gioiTinh":"nam","vaiTro":"Tu sĩ hóa chiến tướng kim giáp trong giới cờ, quân cờ yếu nhất","tinhCach":"yếu đuối; hoảng sợ trước nguy hiểm","blurb":"Tu sĩ đến từ Ngũ Hành tinh, bị biến thành chiến tướng kim giáp trong ván cờ giới. Là quân cờ yếu nhất, bị Vương Lâm thôn phệ bằng bản năng thôn hồn.","trangThai":"song","tabs":{"diem":[{"text":"Quân cờ yếu nhất trong giới cờ, bị Vương Lâm thôn phệ bằng bản năng thôn hồn để tăng cường lực lượng.","chuong":"@c1663"}],"kinhLich":[{"mucCt":"gon","text":"Là quân cờ yếu nhất, hoảng sợ lui lại khi Vương Lâm nhắm tới, bị một chưởng phá nát kim giáp rồi bị thôn phệ bởi bản năng thôn hồn của thần thức Vương Lâm.","anchor":"chiến tướng này hét thảm một tiếng, kim giáp toàn thân lập tức tan nát","bridge":true,"khoang":"@c1663"},{"chuong":"@c1664","importance":"bridge","mucCt":"gon","tieuDe":"Bị lệnh bắt giữ","text":"Dưới uy áp của Vương Lâm kính sợ tái nhợt, bị Vương Lâm ra lệnh cho Bạch Hổ chiến tướng bắt giữ vì có chỗ quan trọng cần dùng.","anchor":"Bắt hắn, hắn đối với ta có chỗ quan trọng cần dùng"},{"importance":"bridge","mucCt":"gon","chuong":"@c1667","tieuDe":"Đứng ngoài quan sát trận chiến","text":"Cùng đám người từ vòng xoáy đi ra, tới gần tu chân tinh nhưng khi đạo nhân bảy màu và Chiến lão quỷ xuất hiện thì đứng yên trong tinh không lạnh lùng quan sát.","anchor":"đám người lão già họ Mã ở Ngũ Hành Tinh vẫn đứng trong tinh không không hề nhúc nhích, lạnh lùng nhìn lại"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị Vương Lâm thôn phệ trong giới cờ","ghiChu":"@c1663"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1663","@c1664","@c1667"]},{"id":"huyen-la-dai-thien-ton","name":"Huyền La Đại Thiên Tôn","gioiTinh":"nam","aliases":["Huyền La"],"theLuc":[{"ten":"Đạo Cổ nhất mạch","trangThai":"gan-bo"},{"ten":"Cửu Dương","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Đại Thiên Tôn (một trong Cửu Dương)","trangThai":"song","blurb":"Cường giả bí ẩn âm thầm theo dõi Vương Lâm, coi cuộc truy kích là khảo nghiệm cuối cùng đối với Vương Lâm.","vaiTro":"Cường giả bí ẩn theo dõi và khảo nghiệm Vương Lâm","tinhCach":"Thâm trầm; kiên nhẫn quan sát không vội ra tay; trọng tài năng","tabs":{"diem":[{"text":"Âm thầm theo dõi toàn bộ cuộc truy kích Vương Lâm, coi đây là khảo nghiệm cuối cùng, chỉ ra tay khi Vương Lâm phát hiện sự tồn tại của hắn.","chuong":"@c1665"},{"text":"Khen ngợi Vương Lâm là “rồng trong cõi người” sau khi chứng kiến kế trong kế thoát thân.","chuong":"@c1665"},{"text":"Đã bám theo Vương Lâm từ Ngũ Hành Tinh qua Tiên Giới tới trung tâm động phủ giới mà không ai phát hiện, cho thấy tu vi cực cao","chuong":"@c1691"},{"text":"Bị Vương Lâm gọi đích danh mà kinh ngạc không hiểu vì sao Vương Lâm biết tên mình","chuong":"@c1691"}],"kinhLich":[{"mucCt":"vua","text":"Theo dõi toàn bộ cuộc truy kích Vương Lâm từ phía sau, quyết định không ra tay giúp mà coi đây là lần khảo nghiệm cuối cùng. Chứng kiến Vương Lâm dùng kế trong kế thoát thân, kinh ngạc khen ngợi là rồng trong cõi người.","anchor":"Để người này rèn luyện cần phải như thế. Nếu hắn có thể phát hiện ra sự tồn tại của ta thì ta mới ra tay","bridge":true,"khoang":"@c1665"},{"mucCt":"vua","text":"Là người duy nhất biết thần thông Mục Ngư mở mắt biến hóa. Thu lấy con Mục Ngư thứ năm. Nhận ra người điên là Liên Đạo Phi — đệ đệ của Liên Đạo Chân, ánh mắt lộ ra ánh sáng kỳ dị.","anchor":"Liên Đạo Phi Đệ đệ của Liên Đạo Chân hắn không ngờ cũng tới nơi này","bridge":true,"khoang":"@c1670"},{"mucCt":"vua","text":"Đứng nơi con Mục Ngư thứ tư biến mất, cười đắc ý nhìn Vương Lâm kinh ngạc. Đã thu tổng cộng sáu con Mục Ngư (năm con biến mất trước đó cộng con thứ tư trước mắt Vương Lâm).","anchor":"khóe miệng lộ nụ cười đắc ý","bridge":true,"khoang":"@c1671"},{"mucCt":"ky","text":"Ẩn trong thiên địa đóng băng quan sát Vương Lâm hấp thu nguyên thần huyết, chủ động gia cố tầng băng mạnh hơn ngàn vạn lần để tranh thủ thời gian. Nhận xét nữ Cổ Thần thuộc Đạo cổ nhất mạch, có thể bồi dưỡng làm thị thiếp cho đệ tử duy nhất. Đánh giá Diệp Mịch thiên tư không tồi nhưng không thể đoạt xá Vương Lâm do hồn huyết, chọn đứng về phía Vương Lâm.","anchor":"Ngươi muốn thời gian bao lâu ta sẽ cho ngươi bấy lâu","bridge":true,"khoang":"@c1672"},{"importance":"bridge","mucCt":"gon","chuong":"@c1673","text":"Ngạc nhiên khi ánh mắt Vương Lâm thoáng chạm vào hắn, sau đó chắp tay sau lưng đứng trên bầu trời hồ băng quan sát Vương Lâm phá băng dung hợp cánh tay trái Diệp Mịch, cười cười với ánh mắt cổ quái.","anchor":"Huyền La Đại Thiên Tôn chắp tay sau lưng, cũng nhìn về hồ nước này"},{"importance":"bridge","mucCt":"vua","chuong":"@c1674","tieuDe":"Nhận ra nơi Diệp Mịch tử vong","text":"Đứng trên đài cao trong vùng đất cổ mộ, nhìn sương mù và than nhẹ rằng đây chính là nơi Diệp Mịch tử vong.","anchor":"Nơi này chính là nơi mà đứa nhỏ Diệp Mịch tử vong rồi"},{"mucCt":"ky","text":"Bình tĩnh quan sát Vương Lâm suốt trận chiến, cảm thấy vừa lòng với tâm trí và quyết đoán của Vương Lâm. Khi Vương Lâm lùi ba bước tới sau lưng hắn, ánh mắt hai người chạm nhau trong vô hình. Huyền La cười nói Thú vị, tùy ý giơ tay chỉ — dừng kim ấn giữa không trung rồi biến nó từ thần thông hư ảo thành pháp bảo thực chất. Chưởng Tôn kinh hãi xác nhận đây là năng lực thay trời đổi đất, lấy tạo hóa sinh vật chỉ cửu đại thiên tôn Tiên Cương Cửu Dương mới làm được, gọi Huyền La là ca ca của chủ nhân.","anchor":"Huyền La đột nhiên cười, hắn giơ tay phải lên rất tùy ý chỉ vào kim ấn đang từ trên không trung hạ xuống","bridge":true,"khoang":"@c1677"},{"importance":"bridge","mucCt":"gon","chuong":"@c1678","text":"Đứng trước Vương Lâm liếc nhìn đầy thâm ý rồi cười, sự hiện diện khiến Chưởng Tôn hoảng sợ tới cực điểm, không trực tiếp giao chiến.","anchor":"liếc nhìn Vương Lâm một cái đầy thâm ý, đột nhiên cười"},{"mucCt":"vua","text":"Ở trên mặt đất đằng xa, ngay khi Dĩ Ti xuất hiện liền nhận ra đây là khôi linh đã chuyển biến hai lần. Than rằng Thất Thải Tiên Tôn lòng dạ ác độc.","anchor":"quả nhiên chính là khôi linh, hơn nữa đã chuyển biến hai lần","bridge":true,"khoang":"@c1679"},{"chuong":"@c1682","importance":"normal","mucCt":"vua","tieuDe":"Nhận ra ngân mục do hồn huyết cổ Tổ","text":"Kích động khi thấy Vương Lâm có đôi mắt bạc, nhận ra đây là do hồn huyết cổ Tổ mang lại đệ nhất tượng trong cửu khúc — Ngân mục. Đây là lần thứ hai hắn thấy ngân mục.","anchor":"Hồn huyết của cổ Tổ. Khiến hắn có được đệ nhất tượng trong cửu khúc - Ngân mục"},{"chuong":"@c1683","importance":"bridge","mucCt":"gon","text":"Đứng xa quan sát trận chiến, khi nhìn thấy hư ảnh đầu lâu Cổ Tổ do Đạo Cổ Vô Tiên triệu ra thì chấn động sùng kính gọi Cổ tổ.","anchor":"Huyền La đứng ở đằng xa nhìn thấy cảnh tượng này thân thể chấn động"},{"mucCt":"vua","text":"Đã bám theo Vương Lâm từ Ngũ Hành Tinh tới Tiên Giới rồi tới trung tâm động phủ mà ẩn thân. Bị Vương Lâm gọi đích danh, buộc phải xuất hiện dưới dạng thân ảnh mơ hồ từ hư vô, kinh ngạc hỏi Vương Lâm sao biết tên mình.","anchor":"Ngươi làm sao biết được tên của bổn tôn","bridge":true,"khoang":"@c1691"},{"chuong":"@c1692","importance":"normal","mucCt":"ky","tieuDe":"Hiện thân, mời Vương Lâm làm đệ tử duy nhất","text":"Chính thức hiện thân trước Vương Lâm, Lam Mộng đạo tôn và Thác Sâm, thần thức không thể cảm nhận sự tồn tại của hắn. Tự suy đoán đúng cách Vương Lâm phát hiện thân phận mình, thừa nhận sơ sót việc Mục Ngư cảm nhận khí tức lẫn nhau. Xác nhận thân phận: một trong Cửu Dương, Đại Thiên Tôn của Đạo Cổ nhất mạch tại Tiên Cương đại lục. Xác định muốn Vương Lâm làm đệ tử duy nhất vì hắn vượt mọi kỳ vọng, đặc biệt chưa từng xin giúp đỡ. Giải thích quy tắc Tiên Cương: sinh linh không có huyết mạch bị hồn phi phách tán, bác bỏ tiếp dẫn giả (trừ Cửu Dương đồng thời ra tay). Phát hiện hồn Uyển Nhi không hoàn chỉnh, một phần biến mất không dấu vết. Đề xuất Thiên Dương luân hồi chuyển thế thuật cho bằng hữu Vương Lâm, riêng Uyển Nhi cho năm phần mười cơ hội mang trực tiếp, phải trả giá rất lớn nhưng không do dự.","anchor":"Theo ta trở về lãnh địa của Đạo Cổ nhất mạch tại Tiên Cương đại lục, trở thành đệ tử duy nhất của Huyền La ta"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Đối tượng khảo nghiệm / theo dõi","ghiChu":"Âm thầm theo dõi cuộc truy kích, đặt điều kiện chỉ ra tay khi Vương Lâm phát hiện sự tồn tại của hắn. @c1665"},{"ten":"Vương Lâm","tag":"su-mon","quanHe":"Đệ tử duy nhất (đã mời, chưa chính thức nhận)","ghiChu":"Cực kỳ hài lòng, trả giá lớn giúp đỡ."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1665","@c1670","@c1671","@c1672","@c1673","@c1674","@c1677","@c1678","@c1679","@c1682","@c1683","@c1690","@c1691","@c1692"],"cn":"玄罗大天尊"},{"id":"tam-phi","name":"Tam phi","aliases":["Đường San","Đệ tam phi","Tam phi"],"tabs":{"kinhLich":[{"importance":"bridge","mucCt":"vua","chuong":"@c1667","tieuDe":"Do dự trước bẫy Vương Lâm","text":"Thần sắc lạnh như băng, mục đích duy nhất là trở về Tiên Cương Đại Lục. Đối với Vương Lâm không biết là địch hay bạn, do dự rồi vẫn đến nhưng không bước vào tu chân tinh.","anchor":"Mục đích của nàng chỉ có một, đó chính là trở về nhà!"},{"chuong":"@c1670","importance":"bridge","mucCt":"gon","tieuDe":"","text":"Ở đằng xa, sắc mặt tái nhợt, thần sắc ngây ra khi thấy Liên Đạo Phi xuất hiện.","anchor":"bổn vương sẽ mách với ca ca, các ngươi thật là quá đáng"},{"mucCt":"vua","text":"Bay trong sương mù đệ tứ hoa, nhận ra đây là vùng đất cổ mộ. Hồi ức về lần gặp Vương Lâm năm đó ở nơi này, xác nhận hắn là người đầu tiên trong đời ra tay giúp nàng, trong lòng muốn báo đáp. Tưởng niệm sư tôn và muội muội, muốn về nhà.","anchor":"Hắn đã từng trợ giúp ta. Việc này phải báo đáp","bridge":true,"khoang":"@c1674"},{"mucCt":"ky","text":"Nhìn thấy u quang truyền tống trận trong sương mù, do dự hồi lâu rồi cắn răng bước vào tầng hai theo Vương Lâm. Bị tiếng gầm Dĩ Ti Chi Khôi tấn công, dùng kim môn phòng hộ chống đỡ nhưng liên tục bị phá vỡ, phun máu nhiều lần. Truyền âm tìm Vương Lâm, nói muốn trả ơn năm xưa. Khi Vương Lâm hiện thân chặn dư âm cho nàng rồi lạnh lùng từ chối giúp đỡ, đưa ra chuỗi hạt châu trên cổ tay do sư tôn ban tặng — có thể hóa thành bảy kim môn đồng thời hiện ra — đề nghị giúp hắn tiến vào ngọn núi nơi Dĩ Ti Chi Khôi ẩn náu.","anchor":"Vật này là do sư tôn của ta ban tặng nhưng có thể hóa thành bảy kim môn đồng thời hiện ra","bridge":true,"khoang":"@c1675"},{"importance":"normal","mucCt":"ky","chuong":"@c1676","tieuDe":"Tiết lộ tên thật, thi triển phòng hộ lên người khác","text":"Cho Vương Lâm biết tên thật là Đường San, nói muốn trả ơn năm xưa ở vùng đất cổ mộ. Khi Vân Dật Phong xuất hiện, mở Thất Diện Kim Môn phòng thân. Sau trận đấu, thi triển bảy kim môn phòng hộ lên cả Vân Dật Phong và Vương Lâm, khiến Vương Lâm cả đời lần đầu chứng kiến thần thông phòng hộ dùng cho người khác.","anchor":"đây là lần đầu tiên chứng kiến thần thông phòng hộ có thể thi triển lên người khác"},{"mucCt":"vua","text":"Thi triển bảy kim môn lên Vương Lâm và Vân Dật Phong vừa chữa trị vừa phòng hộ, đồng thời triệu chín thanh phi kiếm lập kiếm trận tấn công Chưởng Tôn. Chín phi kiếm bị kim quang phá nát, hạt châu màu vàng trên cổ tay và bảy kim môn chống đỡ nhưng bị phản lực, khóe miệng tràn máu lùi lại.","anchor":"Hạt châu màu vàng ở trên cổ tay Đường San nhanh chóng lóe lên","bridge":true,"khoang":"@c1677"},{"mucCt":"vua","text":"Vung hạt châu màu vàng trên cổ tay, kim môn xuất hiện, thất môn hợp nhất hóa cự long màu vàng lao tấn công Chưởng Tôn. Sau đó bị thương, khóe miệng tràn máu lùi ngàn trượng.","anchor":"con cự long màu vàng, từ trong kim môn kia lao ra","bridge":true,"khoang":"@c1678"},{"importance":"bridge","mucCt":"gon","chuong":"@c1679","text":"Bị lam quang kéo dung hợp góp sức phong ấn Chưởng Tôn, khi Dĩ Ti hiện hình sắc mặt tái nhợt liên tục lùi lại.","anchor":"sắc mặt Đường San liền lập tức tái nhợt, thân thể liên tục lùi lại phía sau mấy bước"},{"importance":"bridge","mucCt":"vua","chuong":"@c1680","tieuDe":"Triển bảy kim môn chặn Chiến lão quỷ","text":"Trầm mặc gật đầu khi Vương Lâm tuyên bố hai bên cân bằng. Vung tay triển khai bảy kim môn quanh bốn phía mọi người, ở lại chặn Chiến lão quỷ.","anchor":"Lập tức bốn phía mọi người đều hiện lên bảy kim môn."},{"importance":"bridge","mucCt":"gon","chuong":"@c1681","text":"Bị cuồng phong đánh văng trọng thương, máu tươi tràn miệng.","anchor":"cuồng phong gào thét cuốn thân thể đệ tam phi Đường San đi"},{"chuong":"@c1682","importance":"bridge","mucCt":"gon","tieuDe":"","text":"Nhảy lên lao tới định ngăn Huyền Vũ và Chu Tước xâm nhập tầng cuối nhưng chậm hơn tốc độ hai chiến tướng.","anchor":"Đường San lúc này không chút chần chừ. Nàng cắn răng nhảy lên"},{"importance":"normal","mucCt":"vua","chuong":"@c1691","tieuDe":"Từ biệt Vương Lâm qua kim môn","text":"Nhìn kim môn rơi nước mắt nhớ quê hương, tông môn, sư tôn. Bước tới kim môn cảm ơn Vương Lâm, trước khi biến mất quay đầu hỏi có thể gặp lại không, Vương Lâm không đáp, mắt nàng ảm đạm rồi biến mất trong kim quang.","anchor":"Chúng ta còn có thể gặp lại không"}],"nhanMach":[{"ten":"Vương Lâm","tag":"an-nhan","quanHe":"Ân nhân từng giúp đỡ tại vùng đất cổ mộ","ghiChu":"Muốn trả ơn, thi triển phòng hộ lên người Vương Lâm"},{"ten":"Vân Dật Phong","tag":"dong-minh","quanHe":"Cùng phe Vương Lâm sau thệ huyết","ghiChu":"Thi triển Thất Diện Kim Môn phòng hộ lên người Vân Dật Phong"}],"tuViMoc":[],"diem":[{"text":"Tên thật Đường San, trước gọi Tam phi, thuộc Thiên Môn Đạo — tông phái nhỏ nổi danh thần thông phòng hộ cho người khác","chuong":"@c1676"},{"text":"Có thể thi triển Thất Diện Kim Môn phòng hộ lên người khác, khả năng cực kỳ hiếm thấy mà Vương Lâm cả đời lần đầu chứng kiến","chuong":"@c1676"}]},"nguon":["@c1667","@c1670","@c1674","@c1675","@c1676","@c1677","@c1678","@c1679","@c1680","@c1681","@c1682","@c1691"],"trangThai":"song","canhGioiCaoNhat":"Không rõ","vaiTro":"Đồng hành phòng hộ bên Vương Lâm, tu sĩ Thiên Môn Đạo","tinhCach":"Trọng ân nghĩa, chân thành muốn trả ơn; tu vi không kém, phản ứng nhanh nhạy","blurb":"Tên thật Đường San, trước đây gọi là Tam phi. Thuộc Thiên Môn Đạo ở đại lục Tiên Cương, tông phái nhỏ nổi danh nhờ thần thông phòng hộ có thể thi triển lên người khác. Từng được Vương Lâm giúp đỡ tại vùng đất cổ mộ, nay muốn trả ơn.","cn":"唐珊","gioiTinh":"nu","theLuc":[{"ten":"Thiên Môn Đạo","trangThai":"gan-bo"}]},{"id":"luc-phi","name":"Lục phi","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1667","tieuDe":"Theo chiến hương tới tu chân tinh","text":"Từng suýt chết dưới tay Vương Lâm, mắt lộ oán độc, cắn răng theo mùi hương tới tu chân tinh.","anchor":"Lục phi kia trong mắt lộ ra vẻ oán độc, năm đó nàng may mắn thoát khỏi tay Vương Lâm"},{"importance":"normal","mucCt":"gon","chuong":"@c1668","tieuDe":"Bị U Minh Thú nuốt","text":"Chật vật ra khỏi biển lửa thân thể trọng thương, bị lực hút U Minh Thú cuốn vào, gào thét không chống nổi, bị nuốt.","anchor":"lục phi kia trong tiếng gào thét chói tai không thể chống lại lực hút này, thân thể mềm mại trực tiếp bị cuốn vào bên trong cái miệng của u Minh Thú"}],"nhanMach":[],"tuViMoc":[]},"nguon":["@c1667","@c1668"],"trangThai":"song"},{"id":"lao-gia-ao-vai-tho-xanh","name":"Lão già áo vải thô xanh","gioiTinh":"nam","theLuc":[{"ten":"Thất Đạo Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Thủ lĩnh đám đệ tử Thất Đạo Tông từ Viễn cổ Tiên Vực, bước ra từ tinh không giới nội khi ngửi thấy chiến hương.","vaiTro":"Thủ lĩnh đệ tử Thất Đạo Tông tại giới ngoại","tinhCach":"Cảnh giác; hành động nhanh","tabs":{"diem":[{"text":"Dẫn đầu đệ tử Thất Đạo Tông ở giới ngoại, lập tức hành động khi ngửi thấy chiến hương","chuong":"@c1667"}],"kinhLich":[{"mucCt":"gon","text":"Bước ra từ tinh không giới nội, ngửi thấy chiến hương, dẫn đầu đệ tử Thất Đạo Tông tới tu chân tinh của Vương Lâm.","anchor":"Ai đã đốt chiến hương vậy, chẳng lẽ đã có phát hiện gì","bridge":true,"khoang":"@c1667"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1667"]},{"id":"nam-tu-trung-nien-ao-tim","name":"Nam tử trung niên áo tím đạo bào","gioiTinh":"nam","theLuc":[{"ten":"Thất Đạo Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Tu sĩ Thất Đạo Tông đang tìm kiếm trên tu chân tinh ở giới khác, lập tức rời đi khi cảm nhận mùi chiến hương.","vaiTro":"Đệ tử Thất Đạo Tông tại giới ngoại","tinhCach":"Phản ứng nhanh nhạy","tabs":{"diem":[{"text":"Không cần nghĩ ngợi lập tức biến mất khi cảm nhận mùi hương","chuong":"@c1667"}],"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1667","tieuDe":"Theo chiến hương rời đi","text":"Đang tìm kiếm trên tu chân tinh ở giới khác, cảm nhận mùi chiến hương lập tức biến mất rời khỏi.","anchor":"hai mắt hắn lóe lên không cần nghĩ ngợi lập tức biến mất rời khỏi"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1667"]},{"id":"lao-gia-ho-ma","name":"Lão già họ Mã","cn":"","aliases":["Lão già họ Mã (Ngũ Hành tinh)"],"gioiTinh":"nam","theLuc":[{"ten":"Ngũ Hành Tinh","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Người cầm đầu đám tu sĩ Ngũ Hành Tinh trong trận chiến trên tu chân tinh, đứng xa quan sát không tham chiến. Lần đầu chứng kiến cung Lý Quảng cực kỳ chấn động.","vaiTro":"Thủ lĩnh đám tu sĩ Ngũ Hành Tinh","tinhCach":"Thận trọng, biết đánh giá tình thế","tabs":{"diem":[{"text":"Cầm đầu đám tu sĩ Ngũ Hành Tinh, khôn ngoan đứng xa quan sát không tham chiến khi bảy màu và Vương Lâm giao đấu.","chuong":"@c1669"}],"kinhLich":[{"mucCt":"gon","text":"Cầm đầu đám tu sĩ Ngũ Hành Tinh đứng xa quan sát trận chiến, lần đầu thấy cung Lý Quảng cực kỳ chấn động, nhận ra Vương Lâm tới Ngũ Hành Tinh lần trước ngoài Thiên Đạo còn mang cả cung này.","anchor":"Cây cung của Lý Quảng không ngờ lại ở trong tay hắn","bridge":true,"khoang":"@c1669"},{"chuong":"@c1670","importance":"bridge","mucCt":"gon","tieuDe":"","text":"Kinh ngạc trước thần thông Mục Ngư mở mắt, run rẩy kinh hoàng khi thấy Liên Đạo Phi, không ngờ hắn ở nơi này.","anchor":"Hắn.không ngờ hắn lại ở chỗ này"},{"mucCt":"vua","text":"Bất đắc dĩ ra tay theo yêu cầu Huyền La Đại Thiên Tôn — nếu không ra tay thì cả đời không rời khỏi động phủ giới. Cùng Lam Mộng Đạo Tôn khổ chiến Chiến lão quỷ ở tầng thứ hai. Thi triển Ngũ hành kim tiên — Ngưng tụ kim thiên và Ngũ hành thổ tiên — Ngưng tụ hắc địa, triệu hai bàn tay khổng lồ kim sắc và hắc sắc đánh Chiến lão quỷ.","anchor":"Hắn không thể không ra tay","bridge":true,"khoang":"@c1681"},{"chuong":"@c1682","importance":"normal","mucCt":"vua","tieuDe":"Thần thông bị phá, nhớ truyền thuyết cửu khúc tam tượng khi thấy ngân mục","text":"Cánh tay kim sắc bị hồn phách Thất Thải Tiên Tôn phá, chịu lực phản chấn lui trăm trượng, khóe miệng tràn máu nhưng cắn răng quay lại chiến đấu. Khi thấy Vương Lâm xuất hiện với đôi mắt bạc, nhớ tới truyền thuyết cửu khúc tam tượng của tiên tổ giáng trần: lưỡng khúc là ngân mục kim thân.","anchor":"Trong cửu khúc của lưỡng khúc là ngân mục kim thân"},{"chuong":"@c1690","importance":"normal","mucCt":"vua","tieuDe":"Kinh hoàng trước tám bổn nguyên chân thân","text":"Thân ảnh huyễn hóa ra khi thế giới sụp đổ. Kinh hoàng khi nhìn thấy tám bổn nguyên chân thân Vương Lâm, giải thích trừ người mở thần cảnh hoặc trở thành Đại Thiên Tôn mới có bổn nguyên chân thân, mà Vương Lâm có tới tám cái.","anchor":"Người tầm thường có được một bổn nguyên đã là hiếm thấy, hắn. Hắn không ngờ lại có tới tám cái!"},{"mucCt":"vua","text":"Cảm khái nhìn Vân Dật Phong bằng ánh mắt hiền từ. Là người đầu tiên bước ra tiễn biệt Vương Lâm, mời hắn ngày sau tới Quy Nhất Tông ở Tiên Tộc rồi bay vào kim môn rời đi.","anchor":"Vương đạo hữu, lão phu xin đi trước một bước. Ngày sau nếu đi tới Tiên Tộc thì có thể tới Quy Nhất Tông một phen","bridge":true,"khoang":"@c1691"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối tượng quan sát, kiêng dè","ghiChu":"Nhận ra Vương Lâm mang cung Lý Quảng, cực kỳ chấn động @c1669"},{"ten":"Vân Dật Phong","tag":"dong-minh","quanHe":"Cùng phe Ngũ Hành Tinh","ghiChu":""}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1669","@c1670","@c1681","@c1682","@c1690","@c1691"]},{"id":"van-na","name":"Vân Na","aliases":["nữ Cổ Thần"],"gioiTinh":"nu","theLuc":[{"ten":"Đông Lâm tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Nữ Cổ Thần, thần trưởng lão Đông Lâm tông dưới trướng tiên tôn. Mi tâm có bảy tinh điểm Cổ Thần, ẩn chứa máu huyết tâm thần cuối cùng của Diệp Mịch. Là sinh mệnh do sinh cơ của Thất Thải Tiên Tôn tạo ra, tồn tại trong đệ nhị hoa của Ngũ hoa bát môn.","vaiTro":"Thần trưởng lão Đông Lâm tông, nữ Cổ Thần ẩn chứa tâm thần huyết Diệp Mịch","tinhCach":"Trung thành với chủ nhân; bình tĩnh, chủ động đề nghị dung hợp tâm thần huyết","tabs":{"diem":[{"text":"Mi tâm có bảy tinh điểm Cổ Thần, ẩn chứa máu huyết tâm thần cuối cùng của Diệp Mịch","chuong":"@c1671"},{"text":"Nhận ra Vương Lâm mang phân hồn Thất Thải Tiên Tôn, nhận hắn là chủ nhân mới của Đông Lâm tông","chuong":"@c1671"}],"kinhLich":[{"importance":"normal","mucCt":"ky","chuong":"@c1671","tieuDe":"Gặp Vương Lâm, nhận chủ nhân mới","text":"Ngồi khoanh chân trong tảng đá bình chùy giữa thế giới đóng băng đệ nhị hoa, mi tâm bảy tinh điểm Cổ Thần chuyển động. Tự giới thiệu là Vân Na, thần trưởng lão Đông Lâm tông dưới trướng tiên tôn. Tiết lộ nơi này do Thất Thải Tiên Tôn tạo dựa trên ký ức về Đông Lâm tông trên Tiên Cương đại lục, Thất Thải xưa là đệ tử bị khu trừ. Nhận ra Vương Lâm mang phân hồn chủ nhân, nhận hắn là chủ nhân mới, đề nghị dung hợp tâm thần huyết cuối cùng của Diệp Mịch trong cơ thể nàng để chữa thương cho Vương Lâm.","anchor":"Vân Na, Đông Lâm tông thần trưởng lão dưới trướng tiên tôn"},{"chuong":"@c1672","importance":"normal","mucCt":"ky","tieuDe":"Trao nguyên thần huyết, tiết lộ lai lịch Đông Lâm tông","text":"Đóng băng thiên địa phong bế kẻ xâm nhập, điểm vào mi tâm ngưng tụ giọt nguyên thần huyết cuối cùng của Diệp Mịch trao cho Vương Lâm, đổi lấy lời hứa giúp nàng rời khỏi động phủ giới; sau khi trao nàng suy yếu hẳn. Tiết lộ chủ nhân Diệp Mịch ngưng tụ máu huyết tạo ra nàng để bảo vệ Đông Lâm tông với vị trí thần trưởng lão; nhị vị trưởng lão Yêu, Ma đã tử vong trong giấc ngủ đóng băng. Bị uy áp nguyên thần Diệp Mịch ép quỳ vì trong cơ thể nàng cũng có máu huyết tầm thường của Diệp Mịch.","anchor":"Chủ nhân ngưng tụ máu huyết của Diệp Mịch hóa thành người thay chủ nhân bảo về Đông Lâm tông"},{"importance":"bridge","mucCt":"gon","chuong":"@c1673","text":"Phủ phục trước Vương Lâm khi hắn tỏa khí tức tổ tiên, cho biết nơi kêu gọi là hậu sơn Đông Lâm tông — Đông Lâm Trì do Thất Thải Tiên Tôn dựa trí nhớ sáng tạo ra, được Vương Lâm hứa sẽ đưa rời khỏi nơi này.","anchor":"Nơi đó trước kia là hậu sơn của Đông Lâm tông"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Chủ nhân mới (mang phân hồn Thất Thải Tiên Tôn)","gap":"@c1671"},{"ten":"Thất Thải Tiên Tôn","tag":"su-mon","quanHe":"Chủ nhân cũ, tiên tôn Đông Lâm tông (đã chết)","gap":"@c1671"},{"ten":"Diệp Mịch","tag":"khac","quanHe":"Ẩn chứa máu huyết tâm thần cuối cùng của Diệp Mịch trong cơ thể","gap":"@c1671"}],"tuiDo":{}},"nguon":["@c1671","@c1672","@c1673"]},{"id":"thac-sam","name":"Thác Sâm","aliases":["Hoặc Đồ Ti","Cổ thần Đồ Ti","Đồ Ti"],"tabs":{"kinhLich":[{"importance":"normal","mucCt":"gon","chuong":"@c1674","tieuDe":"Mở mắt khi Vương Lâm tới cổ mộ","text":"Ở đại điện trong vùng đất cổ mộ, bất ngờ mở mắt khi Vương Lâm tiến vào.","anchor":"Thác Sâm - Hoặc Đồ Ti mở mắt"},{"importance":"normal","mucCt":"ky","chuong":"@c1678","tieuDe":"Đồ Ti thức tỉnh trong thân Thác Sâm","text":"Xuất hiện từ vùng thiên địa vặn vẹo, nửa người màu đỏ mang vẻ bá đạo, đánh một quyền vào Chưởng Tôn gây chấn động. Bành trướng thân thể lên mấy vạn trượng cùng Vương Lâm phong tỏa Chưởng Tôn. Sau đó khí chất bá đạo tiêu tan, biến đổi thành Đồ Ti thức tỉnh — trầm ổn tỉnh táo, triệu thanh trường mâu khổng lồ đâm Chưởng Tôn. Bị Chưởng Tôn đánh lui trăm trượng nhưng không bị thương.","anchor":"người xuất hiện ở trước mắt chính là Đồ Ti"},{"importance":"bridge","mucCt":"gon","chuong":"@c1679","text":"Bị lam quang Lam Mộng kéo dung hợp, góp sức tạo một trong bốn ký hiệu phong ấn Chưởng Tôn, chấn động tâm thần khi thấy Dĩ Ti hiện thân.","anchor":"Dựa theo ký ức của Thất Thải Tiên Tôn, vật này một khi hiện thân sẽ có được tu vi đỉnh của Không Kiếp Sơ Kỳ"},{"importance":"bridge","mucCt":"vua","chuong":"@c1680","tieuDe":"Ở lại chặn Chiến lão quỷ","text":"Thân hóa kích thước người thường, trầm mặc nhìn Vương Lâm rồi phát ra tiếng nổ, ngẩng đầu nắm tay, ở lại chặn Chiến lão quỷ.","anchor":"Hắn không nói gì nhưng thân thể lại phát ra những tiếng nổ bùng bùng, ngẩng đầu nắm tay."},{"importance":"bridge","mucCt":"gon","chuong":"@c1681","text":"Toàn thân tràn ngập hắc khí, bị phong ấn hoàn toàn không thể thoát ra.","anchor":"Thác Sâm lúc này toàn thân tràn ngập hắc khí, bị phong ấn hoàn toàn"},{"chuong":"@c1682","importance":"normal","mucCt":"vua","tieuDe":"Phá phong ấn chữ Chiến, kinh sợ khi thấy Vương Lâm","text":"Gầm nhẹ đánh tan phong ấn chữ Chiến đã suy yếu, lao về phía Huyền Vũ và Chu Tước nhưng vẫn chậm hơn. Khi thấy Vương Lâm xuất hiện với chín tinh điểm mi tâm thì vô cùng khiếp sợ.","anchor":"Thác Sâm bị Chiến lão quỷ phong ấn lúc này gầm nhẹ, một quyền đánh tan phong ấn"},{"importance":"bridge","mucCt":"vua","chuong":"@c1691","tieuDe":"Trầm mặc trước kim môn","text":"Hiện hình bên ngoài kim môn cùng những người sống sót. Trầm mặc nhìn kim môn, tâm thần uể oải, không rõ đang nghĩ gì.","anchor":"Thác Sâm hoặc là Đồ Ti cũng trầm mặc, nhìn kim môn nọ không biết đang nghĩ điều gì"},{"chuong":"@c1692","importance":"bridge","mucCt":"gon","text":"Kinh ngạc khi Huyền La hiện thân, đồng tử co rút, vẻ mặt ngưng trọng.","anchor":"thần sắc Lam Mộng đạo tôn và Thác Sâm biến đổi, đồng tử trong hai mắt co rút"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1674","@c1678","@c1679","@c1680","@c1681","@c1682","@c1691","@c1692"],"trangThai":"song","gioiTinh":"nam","cn":"托森","tinhCach":[]},{"id":"hon-thu-ba-vuong-lam","name":"Ác quỷ Dĩ Ti","gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1680","tieuDe":"Theo Vương Lâm vào tầng cuối","text":"Đi theo phía sau Vương Lâm vào tầng cuối vùng đất cổ mộ, không bị tiếng tim ảnh hưởng, vẻ hung sát và nôn nóng ngày càng đậm.","anchor":"Đầu lưỡi nó vươn dài, vẻ hung sát trong mắt càng ngày càng đậm, mơ hồ tỏa ra cảm giác nôn nóng."},{"importance":"bridge","mucCt":"gon","chuong":"@c1681","text":"Ngồi chồm hỗm bên cạnh Vương Lâm tại tầng cuối cùng, vẻ hung sát và bạo ngược trong mắt càng đậm, liên tục gầm rống vô thức.","anchor":"Dĩ ti chi khôi như ác quỷ ngồi chồm hỗm ở đó, vẻ hung sát và bạo ngược trong mắt càng đậm"},{"chuong":"@c1682","importance":"normal","mucCt":"vua","tieuDe":"Lao ra từ tầng cuối hút máu Chu Tước chiến tướng","text":"Từ tầng cuối lao ra với tiếng rít gào hung bạo, khát máu điên cuồng, đụng thẳng vào Chu Tước chiến tướng, ôm cổ cắn hút máu khiến đối phương héo rũ rồi đạp nện xuống đất, bay lên không lộ thân hình.","anchor":"mang theo nụ cười nanh ác, cắn lên cổ Chu Tước chiến tướng"},{"chuong":"@c1683","importance":"bridge","mucCt":"gon","text":"Hóa sương đen tấn công Chiến lão quỷ, bị hắn phun máu nuốt lấy một lần rồi thoát ra tiếp tục quấn lấy đối phương chiến đấu.","anchor":"con quỷ Dĩ Ti đã tới gần Chiến lão quỷ, trong đám hắc khí lượn lờ"}],"nhanMach":[],"tuViMoc":[]},"nguon":["@c1680","@c1681","@c1682","@c1683"],"aliases":["Dĩ Ti","Dĩ Ti Chi Khôi","khôi linh","quỷ Dĩ Ti","Cổ thần Đồ Ti"],"tinhCach":[]},{"id":"chu-lap","name":"Chu Lập","cn":"朱立","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Đông Lâm Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"khong-ro","trangThai":"song","blurb":"Đại sư huynh của Tô Đạo tại Đông Lâm Tông trong thế giới ký ức Thất Thải Tiên Tôn. Thiên tư tuyệt hảo, bề ngoài ôn hòa nhưng khinh thị sư đệ, dùng uy hiếp giành lợi thế trong cuộc thi chọn truyền nhân.","vaiTro":"Đại sư huynh Đông Lâm Tông, đối thủ của Tô Đạo trong ký ức","tinhCach":"Bề ngoài ôn hòa nhưng bản chất khinh thị kẻ yếu; dùng ánh mắt uy hiếp sư đệ; thiên tư cao nhưng tâm tính hẹp hòi","tabs":{"diem":[{"text":"Thiên tư tuyệt hảo, bề ngoài ôn hòa nhưng khinh thị Tô Đạo, mặc kệ người khác khi nhục sư đệ","chuong":"@c1685"},{"text":"Bị Vương Lâm nghịch chuyển ký ức, từ người thắng trở thành kẻ thua, phun máu khi mây mù bị rồng nuốt sạch","chuong":"@c1685"},{"text":"Hận Tô Đạo vì tranh giành quyền học Vân Đạo Thiên Thuật, nhập môn trước nhưng bị Tô Đạo cướp cơ hội","chuong":"@c1688"},{"text":"Thiên tư tuyệt hảo, mặc kệ người khác khinh nhục sư đệ Tô Đạo, dùng ánh mắt uy hiếp trong cuộc thi — sau bị Vương Lâm nghịch chuyển đánh bại hoàn toàn.","chuong":"@c1685"},{"text":"Thiên tư tuyệt hảo, khoác vẻ ôn hòa nhưng khinh thị sư đệ, dùng ánh mắt uy hiếp trong cuộc thi chọn truyền nhân.","chuong":"@c1685"},{"text":"Thiên tư tuyệt hảo nhưng tính cách ngầm đàn áp sư đệ, bị Vương Lâm nghịch chuyển ký ức đánh bại hoàn toàn","chuong":"@c1685"}],"kinhLich":[{"chuong":"@c1685","importance":"normal","tieuDe":"Bị Vương Lâm đàn áp, mất tư cách Vân Đạo Thiên Thuật","text":"Trong cuộc thi tuyển trước mặt sư tôn, dùng ánh mắt uy hiếp Tô Đạo (Vương Lâm) nhưng bị đáp trả bằng hàn quang sát khí khiến tâm thần chấn động. Phải 20 nhịp thở mới miễn cưỡng hoàn thành vận chuyển vân khí, sương mù ít ỏi bị rồng mây của Vương Lâm nuốt sạch, phun máu. Bị chuyển sang học Thất Thải Tiên Thuật thay vì Vân Đạo Thiên Thuật.","anchor":"Một cái nuốt này khiến sương mù toàn thân Chu Lập bị nhanh chóng hấp thu vào trong mồm rồng","mucCt":"vua"},{"chuong":"@c1686","importance":"bridge","mucCt":"vua","text":"Trong ký ức hồn thứ ba: năm xưa đạt được Vân Đạo Thiên Thuật, xếp thứ chín cuộc thi Đông Lâm Tông, được vào Đông Lâm Trì tu hành, cuối cùng bị Thất Thải Tiên Tôn bắt giết vào ngày hắn thành đạo.","anchor":"Còn về phần Chu Lập thì vào ngày Thất Thải Tiên Tôn thành đạo đã bị hắn bắt"},{"mucCt":"vua","text":"Được chọn dự thi nhưng năm tháng qua nội tâm bị hành hạ, mắt đầy tơ máu. Tại quảng trường, ánh mắt cường giả chỉ lướt qua hắn, đại đa số ngưng tụ vào Vương Lâm — đố kị oán hận ngập trời.","anchor":"hai mắt lộ ra sự đố kị và oán hận ngập trời","bridge":true,"khoang":"@c1687"},{"mucCt":"vua","text":"Ẩn nấp trong ngọn núi với tám lệnh bài, bị Vương Lâm phá sập núi rồi đặt tay lên đỉnh đầu giết chết. Cái chết kích thích mạnh ký ức hồn thứ ba Thất Thải.","anchor":"Tô Đạo đáng chết, nếu không có hắn, Vân Đạo ThiênThuật phải là do ta học được mới đúng","bridge":true,"khoang":"@c1688"}],"tuViMoc":[],"nhanMach":[{"ten":"Thất Thải Tiên Tôn","tag":"su-mon","quanHe":"Sư đệ tại Đông Lâm Tông","ghiChu":"Khinh thị Tô Đạo, dùng ánh mắt uy hiếp trong cuộc thi"},{"ten":"Liên Đạo Phi","tag":"su-mon","quanHe":"Sư tôn tại Đông Lâm Tông","ghiChu":"Được sư tôn truyền Thất Thải Tiên Thuật (sau nghịch chuyển)"},{"ten":"Tần Mai","tag":"the-thiep","quanHe":"Đạo lữ (trong ký ức hồn thứ ba, sau cuộc thi sẽ thành đạo lữ)","ghiChu":"@c1687"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị Vương Lâm (đóng vai Tô Đạo) giết trong ký ức tỷ thí","ghiChu":"@c1688"},{"ten":"Thất Thải Tiên Tôn","tag":"doi-thu","quanHe":"Hận Tô Đạo (Thất Thải) vì tranh giành quyền học Vân Đạo Thiên Thuật","ghiChu":"@c1688"},{"ten":"Tô Đạo","tag":"su-mon","quanHe":"Sư đệ tại Đông Lâm Tông","ghiChu":"Khinh thị sư đệ, dùng ánh mắt uy hiếp trong cuộc thi."},{"ten":"Tô Đạo","tag":"doi-thu","quanHe":"Sư đệ tại Đông Lâm Tông","ghiChu":"Khinh thị và dùng ánh mắt uy hiếp trong cuộc thi","gap":"@c1685"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[{"ten":"Thất Thải Tiên Thuật","trangThai":"dang-co","moTa":"Nhận được sau khi ký ức bị nghịch chuyển (trong ký ức gốc là Vân Đạo Thiên Thuật)","nguon":"@c1685"}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1685","@c1686","@c1687","@c1688"]},{"id":"thanh-nien-cam-o","name":"Thanh niên cầm ô","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Đông Lâm Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"khong-ro","trangThai":"song","blurb":"Đệ tử theo sau Vương Lâm (Tô Đạo) trong thế giới ký ức Thất Thải Tiên Tôn, sắc mặt xấu hổ, che ô cho sư huynh trong mưa.","vaiTro":"Đệ tử theo hầu Tô Đạo trong ký ức Đông Lâm Tông","tinhCach":"Rụt rè, xấu hổ, không dám nhìn ai","tabs":{"diem":[{"text":"Che ô cho Tô Đạo trong mưa, sắc mặt xấu hổ không dám nhìn ai, sư tôn thấy người này thì nhíu mày rồi nở cười","chuong":"@c1685"}],"kinhLich":[],"tuViMoc":[],"nhanMach":[{"ten":"Thất Thải Tiên Tôn","tag":"dong-hanh","quanHe":"Sư huynh, người được che ô","ghiChu":"Theo sau Tô Đạo trong mưa"},{"ten":"Tô Đạo","tag":"su-mon","quanHe":"Sư huynh tại Đông Lâm Tông","ghiChu":"Che ô theo hầu."},{"ten":"Vương Lâm","tag":"khac","quanHe":"Chủ nhân (thân phận Tô Đạo)","ghiChu":"Che ô cho Vương Lâm trong mưa","gap":"@c1685"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1685"]},{"id":"tan-mai","name":"Tần Mai","cn":"秦梅","aliases":[],"gioiTinh":"nu","theLuc":[{"ten":"Đông Lâm Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Nữ tử xinh đẹp tuyệt trần, đồng môn với Tô Đạo và Chu Lập trong Đông Lâm Tông. Từng có tình cảm qua lại với Tô Đạo nhưng theo ký ức hồn thứ ba, sau cuộc thi đấu sẽ trở thành đạo lữ của Chu Lập.","vaiTro":"Đồng môn Đông Lâm Tông, nhân vật tình cảm trong ký ức hồn thứ ba","tinhCach":"Xinh đẹp dịu dàng; chủ động bắt chuyện; dễ bị ấn tượng bởi khí chất mạnh mẽ","tabs":{"diem":[{"text":"Nữ tử tuyệt trần cùng hệ với Tô Đạo và Chu Lập, từng có tình ý với Tô Đạo nhưng cuối cùng trở thành đạo lữ Chu Lập theo ký ức hồn thứ ba.","chuong":"@c1687"}],"kinhLich":[{"chuong":"@c1687","importance":"normal","mucCt":"vua","tieuDe":"Xuất hiện tại khai mạc thi đấu Đông Lâm Tông","text":"Được sư tôn chọn dự thi cùng Tô Đạo (Vương Lâm) và Chu Lập. Chúc mừng Tô Đạo đạt tư cách tu Vân Đạo Thiên Thuật, ngạc nhiên vì hắn không còn ngại ngùng mà mỉm cười hào hiệp đầy mị lực.","anchor":"Tô Đạo vốn là người cực kỳ anh tuấn, lúc này lại mang theo nụ cười mỉm của Vương Lâm, tự nhiên có một luồng mị lực đặc biệt"}],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Đồng môn (hắn đang giả Tô Đạo), từng có tình ý với Tô Đạo thật","ghiChu":"@c1687"},{"ten":"Chu Lập","tag":"the-thiep","quanHe":"Đạo lữ (theo quỹ đạo ký ức hồn thứ ba)","ghiChu":"@c1687"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1687"]},{"id":"con-bang","name":"Côn Bằng","gioiTinh":"nam","aliases":[],"theLuc":[{"ten":"Đông Lâm Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"khong-ro","blurb":"Thiên tài Đông Lâm Tông trong ký ức hồn thứ ba Thất Thải, sở trường tốc độ, từng đứng thứ ba trong cửa thứ nhất tỷ thí.","vaiTro":"Thiên tài Đông Lâm Tông, đối thủ trong ký ức tỷ thí","tinhCach":"Tự tin vào tốc độ; hoảng sợ trước kẻ mạnh áp đảo","tabs":{"diem":[{"text":"Sở trường tốc độ, từng đứng thứ ba trong cửa thứ nhất tỷ thí Đông Lâm Tông","chuong":"@c1688"}],"kinhLich":[{"mucCt":"vua","text":"Bị Vương Lâm (đóng vai Tô Đạo) tìm đến, dù sở trường tốc độ vẫn không đủ nhanh. Hoảng sợ vứt bỏ hơn mười ngọc bội bỏ chạy.","anchor":"tốc độ của hắn triển khai thì như một đạo tàn ảnh","bridge":true,"khoang":"@c1688"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị Vương Lâm (đóng vai Tô Đạo) đánh bại trong ký ức tỷ thí","ghiChu":"@c1688"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1688"]}]};
